-- Poems batch 237
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('35508ed3-3d10-4eb5-a41c-c85de6d922cc','和崔丞勸農','蕭泰來','宋','宋诗','song-poetry','','[]','昨宵雨過水平平，自不歸耕却勸耕。',64,'全唐诗/poet.song.216000.json','["昨宵雨過水平平，自不歸耕却勸耕。", "犢卧草根黄藴藉，鷺飛山脚白分明。", "瀹茶僻寺同僧話，送酒芳園見主情。", "父老歡呼官長醉，歸鞭止信馬蹄行。"]'),
('037f8645-53be-4ea7-9702-cf8f6b38252a','挽羅榷院子遠二章  其一','劉鑑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','萬石家居最，清修却似貧。',48,'全唐诗/poet.song.216000.json','["萬石家居最，清修却似貧。", "賦中前進士，詩裏謫仙人。", "連疏西湖上，扁舟穎水濱。", "一從書乙亥，歲歲兩眉顰。"]'),
('0698e7f2-7ed7-4de8-b26d-6ac678daaef2','挽羅榷院子遠二章  其二','劉鑑','宋','宋诗','song-poetry','','[]','不謂懸弧旦，翻成屬纊期。',48,'全唐诗/poet.song.216000.json','["不謂懸弧旦，翻成屬纊期。", "死同生一視，弔與賀相隨。", "靈運先成佛，劉叉懶說詩。", "西風吹獨樹，誰譜鳳鳴枝。"]'),
('71446ecc-0464-4ea4-b8ec-16bd1bad4983','見提舉蔡澗松','劉鑑','宋','宋诗','song-poetry','','[]','今人標致古心胸，吉士依歸有澗松。',64,'全唐诗/poet.song.216000.json','["今人標致古心胸，吉士依歸有澗松。", "白髮半頭身欲鶴，蒼髯千丈氣如龍。", "三年博士留韓愈，十載中郎老蔡邕。", "根脚青原培植久，蓬萊行上最高峯。"]'),
('f703954f-ce6d-4ba5-aebf-e43ae66aca7e','見率齋王廉使  其一','劉鑑','宋','宋诗','song-poetry','','[]','渡孟升陑未歲餘，訪箕問虺即求書。',32,'全唐诗/poet.song.216000.json','["渡孟升陑未歲餘，訪箕問虺即求書。", "從來文武相經緯，正在朝廷妙卷舒。"]'),
('c265e0c5-b375-40fb-af01-f2f61c33306f','見率齋王廉使  其二','劉鑑','宋','宋诗','song-poetry','','[]','樽俎折衝賢甲胄，衣裳定伯勝兵車。',32,'全唐诗/poet.song.216000.json','["樽俎折衝賢甲胄，衣裳定伯勝兵車。", "先生學譜河汾嫡，禮樂須還貞觀初。"]'),
('7984fb93-c94d-4d76-9022-0232283506ac','見率齋王廉使  其三','劉鑑','宋','宋诗','song-poetry','','[]','人物東南又一初，甲田氣運恰相符。',32,'全唐诗/poet.song.216000.json','["人物東南又一初，甲田氣運恰相符。", "王通今日經重續，關朗當年筮不誣。"]'),
('b2bf6c27-b749-42be-89eb-f2487f125029','見率齋王廉使  其四','劉鑑','宋','宋诗','song-poetry','','[]','千載河汾兩夫子，一家洙泗幾生徒。',32,'全唐诗/poet.song.216000.json','["千載河汾兩夫子，一家洙泗幾生徒。", "升堂房社俱先達，還許程元後至無。"]'),
('9896426c-a7a2-4edd-b0f2-2c3a6cece2f5','見率齋王廉使  其五','劉鑑','宋','宋诗','song-poetry','','[]','使星來照鷺邊沙，王郎皇皇遠有華。',32,'全唐诗/poet.song.216000.json','["使星來照鷺邊沙，王郎皇皇遠有華。", "盡起綺園山箇裏，更招溫石水之涯。"]'),
('67ed4add-68b0-421c-b9f1-04a9107545ba','見率齋王廉使  其六','劉鑑','宋','宋诗','song-poetry','','[]','漢唐禮樂成三代，南北車書又一家。',32,'全唐诗/poet.song.216000.json','["漢唐禮樂成三代，南北車書又一家。", "鳴鹿歌詩將意厚，臣忠端出自賓嘉。"]'),
('f374860a-fcec-4478-b1f5-258fe7915ec4','見率齋王廉使  其七','劉鑑','宋','宋诗','song-poetry','','[]','平生怪怪復奇奇，一字何曾樂得饑。',32,'全唐诗/poet.song.216000.json','["平生怪怪復奇奇，一字何曾樂得饑。", "太白枉承金殿召，浩然空負玉堂知。"]'),
('b4e4d9a1-f7b8-4ca8-823f-0a6fb5048d5e','見率齋王廉使  其八','劉鑑','宋','宋诗','song-poetry','','[]','田園僅了都人役，事業全拋進士詩。',32,'全唐诗/poet.song.216000.json','["田園僅了都人役，事業全拋進士詩。", "白髮見公曾感慨，深衣重有道行時。"]'),
('b06c2ac9-81eb-4910-93ee-9319dddc6c39','和率齋王廉使三首  其一','劉鑑','宋','宋诗','song-poetry','','[]','試手東風第一杯，士如侯栗與侯梅。',64,'全唐诗/poet.song.216000.json','["試手東風第一杯，士如侯栗與侯梅。", "潤之春雨根方茂，悴以秋霜花肯開。", "昔有兩生增魯重，今聞四皓爲劉來。", "聖朝禮樂須三代，接武行看上曲臺。"]'),
('22834695-a6eb-4a62-9117-8874134337dd','和率齋王廉使三首  其二','劉鑑','宋','宋诗','song-poetry','','[]','試手東風第一杯，南冠久掛市門梅。',64,'全唐诗/poet.song.216000.json','["試手東風第一杯，南冠久掛市門梅。", "賢遣在野時曾閉，道大如天運復開。", "江左人傳茂弘相，河汾士喜仲淹來。", "深衣增重逾貂暖，立到天花雨滿臺。"]'),
('126edde2-d059-49bd-b17d-1a8b0cd21bf3','和率齋王廉使三首  其三','劉鑑','宋','宋诗','song-poetry','','[]','試手東風第一杯，一番人物萃歐梅。',64,'全唐诗/poet.song.216000.json','["試手東風第一杯，一番人物萃歐梅。", "曳裙昔憚王門峻，振鐸今逢孔席開。", "送酒馬軍江上去，持書驛使隴頭來。", "斯文未墜重增氣，燕飯猶勝愧有臺。"]'),
('c98f7159-2bf0-4536-b4ee-7e2ee6d57859','謁蕭大山','劉鑑','宋','宋诗','song-poetry','','[]','阿統遥知是迺宗，作詩工似選詩工。',64,'全唐诗/poet.song.216000.json','["阿統遥知是迺宗，作詩工似選詩工。", "寫成判語皆吟筆，翻得離騷再國風。", "共喜橫渠傳有弟，久誇坡老學如翁。", "世間師友多零落，今在庭闈諾唯中。"]'),
('921b4797-cfd8-41cc-85fa-f1eab9155e2e','謁蕭小山  其一','劉鑑','宋','宋诗','song-poetry','','[]','一冬晴暖春相似，欲叩吟關未有詩。',32,'全唐诗/poet.song.216000.json','["一冬晴暖春相似，欲叩吟關未有詩。", "折得梅花裝擔了，起程還是雪飛時。"]'),
('6d862c26-7839-40c2-94f7-de3e8013e009','謁蕭小山  其二','劉鑑','宋','宋诗','song-poetry','','[]','一水凝寒棹不開，幾人於此欲船回。',32,'全唐诗/poet.song.216000.json','["一水凝寒棹不開，幾人於此欲船回。", "思君却有扁舟興，半夜直衝風雪來。"]'),
('106a39da-7ad6-45fe-bcac-776a47502ef1','上尚郎中  其一','劉鑑','宋','宋诗','song-poetry','','[]','先生名姓重金臺，一路春風手挽回。',64,'全唐诗/poet.song.216000.json','["先生名姓重金臺，一路春風手挽回。", "黄閣自應調鼎去，青原猶爲算舟來。", "雪晴和風千家滿，雲放天光萬里開。", "畢竟濟川須用楫，韉車行看虎符催。"]'),
('d93680f2-ed13-433b-8438-02f298ae60bf','上尚郎中  其二','劉鑑','宋','宋诗','song-poetry','','[]','六合陰沉一樣雲，行人白晝亦黄昏。',64,'全唐诗/poet.song.216000.json','["六合陰沉一樣雲，行人白晝亦黄昏。", "貪財吏似方山犬，逃命民如入峽猿。", "典到琴書猶小事，賣拋田産更銷魂。", "先生明共霜臺月，照徹茅簷幾淚痕。"]'),
('d25f2d1d-94f2-40eb-a6ed-c7e2a61fe314','上尚郎中  其三','劉鑑','宋','宋诗','song-poetry','','[]','衰年何用響錚錚，一錯元來鑄不成。',64,'全唐诗/poet.song.216000.json','["衰年何用響錚錚，一錯元來鑄不成。", "爲役誰憐燭之武，浮言枉累鐵元城。", "鑠金有口難從衆，轑釜無羹枉怨兄。", "一點紅爐屬君手，放教躍冶要分明。"]'),
('82872cba-71d3-4097-bfaf-5166fdda7f15','題醉月亭','劉鑑','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','采石江頭李太白，狂不奈煩宮錦窄。',184,'全唐诗/poet.song.216000.json','["采石江頭李太白，狂不奈煩宮錦窄。", "赤壁磯下蘇東坡，一葉泛泛凌風波。", "當時有月并有酒，和酒和月吞入口。", "酒腸得月冷于冰，化作瑰辭喧宇宙。", "兩首賦，百篇詩，千秋萬古稱絕奇。", "兩翁不作歸來鶴，玉宇瓊樓寒漠漠。", "若得長江變潑醅，少住人間亦差樂。", "望圓晦缺秋復春，古來明月今來人。", "我時舉酒問明月，月亦團團應不得。", "鐵如意，玉唾壺。", "我歌君和聲嗚嗚，爛醉起舞嗔人扶。", "問影莫是李與蘇，月中仙子知得無。"]'),
('b8e0f656-96ad-416f-ac30-bf0a91a14c0b','登黄鶴樓','劉鑑','宋','宋诗','song-poetry','','[]','西風吹我登黄鶴，白雲半在闌干角。',64,'全唐诗/poet.song.216000.json','["西風吹我登黄鶴，白雲半在闌干角。", "題詩不見舊時人，惟見青山俯城郭。", "萋萋芳草鸚鵡洲，江水衮衮來無休。", "歲月俯仰成春秋，古人今人無限愁。"]'),
('d42d8746-e1d5-478b-8c4e-6f27f2433f01','寄朱約山','劉鑑','宋','宋诗','song-poetry','','[]','歲晚江空煙水寒，楓林葉落楚天寬。',64,'全唐诗/poet.song.216000.json','["歲晚江空煙水寒，楓林葉落楚天寬。", "苦無雁足書難寄，作盡鳶聲吟未安。", "晉帖臨成思入石，離騷讀罷擬栽蘭。", "老來絕被梅花惱，後會君應笑我孱。"]'),
('98094d15-b873-44fc-b5d0-e08f845cfe8f','月巖','劉鑑','宋','宋诗','song-poetry','','[]','世事從來滿則虧，十分何似八分時。',32,'全唐诗/poet.song.216000.json','["世事從來滿則虧，十分何似八分時。", "青山作計常千古，只露巖前月半規。"]'),
('b865b3e5-c645-464d-b663-d4d99d1db629','題靜軒','劉鑑','宋','宋诗','song-poetry','','[]','徑深寂寂鎖苔茵，此地不生車馬塵。',64,'全唐诗/poet.song.216000.json','["徑深寂寂鎖苔茵，此地不生車馬塵。", "夢斷瑶臺惟有竹，棋聲花院似無人。", "蛛因門閉牢穿網，鵲悟枝乾自采薪。", "祇道乾坤大如許，不知天地又新春。"]'),
('c715758d-4daa-4a8f-aae0-84a187537322','賀周總管耐軒遷居回任  其一','劉鑑','宋','宋诗','song-poetry','','[]','就第開藩自古難，旌門累世况團圞。',64,'全唐诗/poet.song.216000.json','["就第開藩自古難，旌門累世况團圞。", "肯邀父老爲鄰舍，更約交游說歲寒。", "千里春風棠蔽芾，一窗秋月竹平安。", "鄉人鄉飲推鄉貴，祗作平時樣子看。"]'),
('415287d1-2a73-41ec-a2c6-5359799a48e4','賀周總管耐軒遷居回任  其二','劉鑑','宋','宋诗','song-poetry','','[]','袖詩兩度出山扉，到得城來與願違。',64,'全唐诗/poet.song.216000.json','["袖詩兩度出山扉，到得城來與願違。", "南浦綠波凝望久，東山零雨喜公歸。", "疎梅鬭雪增新潔，喬木參天長舊圍。", "重對門牆簾定卷，春風賀厦燕棲依。"]'),
('0a145943-157f-4ecd-8faa-dd61fa66a8c5','梅四首  其一','劉鑑','宋','宋诗','song-poetry','','[]','休說逋仙兩句工，冰甌滌筆別形容。',64,'全唐诗/poet.song.216000.json','["休說逋仙兩句工，冰甌滌筆別形容。", "清標騷客風前立，素面仙姝月下逢。", "山店霜寒香撲馬，溪橋水淺影如龍。", "一□盡是寒凝結，金鼎無鹽味更濃。"]'),
('31a71e08-386f-4a2a-a495-f2845e80b73d','梅四首  其二','劉鑑','宋','宋诗','song-poetry','','[]','破荒玉雪粲煙村，倚竹無言獨斷魂。',64,'全唐诗/poet.song.216000.json','["破荒玉雪粲煙村，倚竹無言獨斷魂。", "三弄直須琴對越，一寒安用酒溫存。", "家風巢許堪同社，心事夷齊可共論。", "應出繽紛幾紅紫，一枝開處自乾坤。"]'),
('ff83c115-e407-4165-bcd1-ff15d95533f9','梅四首  其三','劉鑑','宋','宋诗','song-poetry','','[]','除香除影賦梅花，方許詩中擅作家。',64,'全唐诗/poet.song.216000.json','["除香除影賦梅花，方許詩中擅作家。", "怕俗似嫌羔作酒，高人頗稱雪煎茶。", "參橫屋角霜初下，人倚闌干月欲斜。", "夜冷玉肌愁入骨，金壺移入伴窗紗。"]'),
('316bea35-eeb1-464b-9a10-78fd625654ff','梅四首  其四','劉鑑','宋','宋诗','song-poetry','','[]','天花夜半落溪傍，傍有獰然爲取將。',64,'全唐诗/poet.song.216000.json','["天花夜半落溪傍，傍有獰然爲取將。", "擎爪仰空呈潔白，掀髯倒地覓昏黄。", "修鱗月下霜同色，敗甲風前雪有香。", "欲起補之圖影看，生愁飛入水中藏。"]'),
('f5df6d8c-8433-4d9e-9758-6b080bbd9341','書燈  其一','劉鑑','宋','宋诗','song-poetry','','[]','一點蘭膏數寸心，小窗伴我夜沈沈。',64,'全唐诗/poet.song.216000.json','["一點蘭膏數寸心，小窗伴我夜沈沈。", "煖分青燄藜煙細，喜動紅光花意深。", "洞見苦心歸典策，照殘幽夢入寒衾。", "他時富貴不相棄，移上長檠伴醉吟。"]'),
('e2f456a2-55b3-435b-a25e-da3368c66073','書燈  其二','劉鑑','宋','宋诗','song-poetry','','[]','玉樓夜費燭熒熒，祗得眼前歌舞明。',32,'全唐诗/poet.song.216000.json','["玉樓夜費燭熒熒，祗得眼前歌舞明。", "照破三千年外事，書生元不用長檠。"]'),
('2dc6392d-ddcc-47ab-9be8-3f453727bb06','客崇安寄蕭小山','李德真','宋','宋诗','song-poetry','','[]','宦清只有著書忙，六舘歸時客滿堂。',64,'全唐诗/poet.song.216000.json','["宦清只有著書忙，六舘歸時客滿堂。", "芍藥待吟班已峻，梅花曾賦筆猶香。", "夜瞻北斗星河近，晴倚冬梅嶺樹長。", "別日未深情不淺，雪風吹老孟襄陽。"]'),
('12d6caca-b4fe-4cb5-bcd0-9fb9e942f160','寄南嶽故人','李德真','宋','宋诗','song-poetry','','["\u8861\u5c71"]','只自章江別，吳楓又幾霜。',48,'全唐诗/poet.song.216000.json','["只自章江別，吳楓又幾霜。", "天遥人在嶽，月冷夢浮湘。", "紅樹猿孤嘯，黄雲雁一行。", "樓高添遠恨，不敢望斜陽。"]'),
('dec27fa8-fc49-4028-b6ac-fd9aab7707cb','武林春遊即事','李德真','宋','宋诗','song-poetry','','[]','風光如此莫傷春，雲樹煙花一色新。',32,'全唐诗/poet.song.216000.json','["風光如此莫傷春，雲樹煙花一色新。", "杜宇不啼真解事，帝鄉誰是肯歸人。"]'),
('65cb9bbc-71c0-4356-a903-e8c83ad5aa84','雨吟','俞桂','宋','宋诗','song-poetry','','[]','輕輕煙霧失樓臺，雨暗吳山鎖不開。',32,'全唐诗/poet.song.216000.json','["輕輕煙霧失樓臺，雨暗吳山鎖不開。", "試與漁翁閑訪問，落花幾許泛溪來。"]'),
('dd9f78d2-bae9-4c9a-b6d2-f7004219e6ec','過湖','俞桂','宋','宋诗','song-poetry','','[]','舟移別岸水紋開，日暖風香正落梅。',32,'全唐诗/poet.song.216000.json','["舟移別岸水紋開，日暖風香正落梅。", "山色濛濛橫畫軸，白鷗飛處带詩來。"]'),
('88389251-483b-4dea-8470-a8389f7f9a05','和葉廣文韻','俞桂','宋','宋诗','song-poetry','','[]','入得春來物物饒，翻思湖上短長橋。',32,'全唐诗/poet.song.216000.json','["入得春來物物饒，翻思湖上短長橋。", "去年寒食閑遊處，曾把扁舟繫柳條。"]'),
('d89b3675-5b7d-489c-bf8e-a5ce4fb25d60','書齋','俞桂','宋','宋诗','song-poetry','','[]','野草沿庭砌，清閑日掩扉。',48,'全唐诗/poet.song.216000.json','["野草沿庭砌，清閑日掩扉。", "晚凉疎雨過，落葉覺蟬稀。", "天籟自鳴竹，砧聲誰擣衣。", "僧寮不過此，何必扣玄機。"]'),
('faf25f56-07c8-46f4-94ff-8a0b38f48e73','閲名勝詩集','俞桂','宋','宋诗','song-poetry','','[]','買得山房數冊詩，倚篷細讀已移時。',32,'全唐诗/poet.song.216000.json','["買得山房數冊詩，倚篷細讀已移時。", "只貪眼底看冰玉，月上荷花更不知。"]'),
('037ac814-ba09-4579-a1d5-ebdd4a10de5e','書懷','俞桂','宋','宋诗','song-poetry','','[]','僻性止耽書，村中謾寓居。',48,'全唐诗/poet.song.216000.json','["僻性止耽書，村中謾寓居。", "心惟求事省，身合與名疎。", "木葉秋風起，蛩吟夜雨初。", "吾生今晚矣，不必問何如。"]'),
('a9ef33ef-446f-48d7-bbd1-bc8648177b94','閨怨  其一','俞桂','宋','宋诗','song-poetry','','[]','鳳幃曉起鬢𩰀鬆，枕肉初生酒暈紅。',32,'全唐诗/poet.song.216000.json','["鳳幃曉起鬢𩰀鬆，枕肉初生酒暈紅。", "一把柳絲挪在手，沉吟無語對春風。"]'),
('667e838b-64b4-4b61-8e69-200c7cbd7548','閨怨  其二','俞桂','宋','宋诗','song-poetry','','[]','誰憐人去鎖朱樓，終日憑欄只带愁。',32,'全唐诗/poet.song.216000.json','["誰憐人去鎖朱樓，終日憑欄只带愁。", "燕子也知人薄倖，飛來略不傍簾鈎。"]'),
('13663fae-9301-4d2c-adf9-dcf82d6300f7','溪流','俞桂','宋','宋诗','song-poetry','','[]','雲脚纔行又復開，一聲隠隠只空雷。',32,'全唐诗/poet.song.216000.json','["雲脚纔行又復開，一聲隠隠只空雷。", "家僮忽報溪流漲，知是前村落雨來。"]'),
('39e4e20f-a173-4b72-bd50-39e5eeb7c501','初秋','俞桂','宋','宋诗','song-poetry','','[]','火老金柔暑告殘，乘凉正好望西山。',32,'全唐诗/poet.song.216000.json','["火老金柔暑告殘，乘凉正好望西山。", "秋聲來處無尋覓，只作窗前竹葉間。"]'),
('9c743d08-48f7-48d9-ae7a-706962b14469','雜興','俞桂','宋','宋诗','song-poetry','','[]','漫山花發草萋萋，楊柳飛綿水拍堤。',32,'全唐诗/poet.song.216000.json','["漫山花發草萋萋，楊柳飛綿水拍堤。", "況是客懷禁不得，那堪杜宇耳邊啼。"]'),
('9eda13dc-ec7f-4e20-a179-2e90afae7a29','偶吟','俞桂','宋','宋诗','song-poetry','','[]','降伏吾心法，無如去外魔。',48,'全唐诗/poet.song.216000.json','["降伏吾心法，無如去外魔。", "苦吟詩愈拙，著意字猶訛。", "荏苒青衫舊，消磨白髮多。", "不才爲世棄，徒自詠卷阿。"]'),
('88b726a7-db2e-4846-80db-878257e440c8','雨中遣愁','俞桂','宋','宋诗','song-poetry','','[]','花已開時人正愁，花簪頭上使人羞。',32,'全唐诗/poet.song.216000.json','["花已開時人正愁，花簪頭上使人羞。", "一春可厭無晴日，下却珠簾懶凭樓。"]'),
('c5cb2b20-40b7-4671-bd14-4ae38536edb0','清明','俞桂','宋','宋诗','song-poetry','','[]','朝來閣雨喜新晴，枝上綿蠻調好聲。',32,'全唐诗/poet.song.216000.json','["朝來閣雨喜新晴，枝上綿蠻調好聲。", "佳節莫將虛過了，人生贏得幾清明。"]'),
('017ee184-5415-4ef8-ae40-531a72791e2c','即事','俞桂','宋','宋诗','song-poetry','','[]','陰雲釀雨勒花遲，梅已飄殘到杏枝。',32,'全唐诗/poet.song.216000.json','["陰雲釀雨勒花遲，梅已飄殘到杏枝。", "好是池塘清夢處，勾吟春草入新詩。"]'),
('ea9f7807-20a8-494d-b521-6e782dd11103','松江','俞桂','宋','宋诗','song-poetry','','[]','荷葉翻風暑氣微，看山露冷濕征衣。',32,'全唐诗/poet.song.216000.json','["荷葉翻風暑氣微，看山露冷濕征衣。", "垂虹夜靜三高月，只照漁溪一舸歸。"]'),
('afdb72b4-1fbc-4a15-a304-0b9bbfaca474','惜春','俞桂','宋','宋诗','song-poetry','','[]','春事三分過二分，桃花水上覓紅雲。',32,'全唐诗/poet.song.216000.json','["春事三分過二分，桃花水上覓紅雲。", "遊人浪說春歸去，柳外黄鸝尚自吟。"]'),
('5843aa9c-6860-48f8-b0c3-50f77618a65f','次吳秋潭韻','俞桂','宋','宋诗','song-poetry','','[]','相逢款話傍簷西，坎止流行事不齊。',32,'全唐诗/poet.song.216000.json','["相逢款話傍簷西，坎止流行事不齊。", "君到白蘋秋正好，飽吟風月棹前溪。"]'),
('5319cbaf-7d5a-463a-b23d-85dddb6d6b73','東山','俞桂','宋','宋诗','song-poetry','','[]','東山隨分作生涯，即是清高隠者家。',32,'全唐诗/poet.song.216000.json','["東山隨分作生涯，即是清高隠者家。", "粗有小園供日涉，不愁無地種梅花。"]'),
('58d918dd-37b9-4c6b-bf38-8f0975837c3f','夏中即事','俞桂','宋','宋诗','song-poetry','','[]','重梅過了猶慳雨，幸有南薰在翠槐。',32,'全唐诗/poet.song.216000.json','["重梅過了猶慳雨，幸有南薰在翠槐。", "燕子亦於貧者薄，今年全不見飛來。"]'),
('5e3f55f3-3475-4bf6-a47f-0418730e52b2','延祥觀','俞桂','宋','宋诗','song-poetry','','[]','御園猶自有逋梅，約束遊人莫肯開。',32,'全唐诗/poet.song.216000.json','["御園猶自有逋梅，約束遊人莫肯開。", "聽得老兵談舊事，幾年不見翠華來。"]'),
('47f1f8e0-a154-43f0-a833-3d6bcdb53752','虎丘','俞桂','宋','宋诗','song-poetry','','[]','兩寺今爲一，因秦虎占丘。',48,'全唐诗/poet.song.216000.json','["兩寺今爲一，因秦虎占丘。", "鶴飛王劍化，鳥宿古墳愁。", "石與泉流接，池通海水浮。", "十奇多勝槩，不及盡追遊。"]'),
('afc1569d-1c11-4ea8-9a4e-746458fbf916','家園','俞桂','宋','宋诗','song-poetry','','[]','眺望西山在目中，更須寬展竹籬通。',32,'全唐诗/poet.song.216000.json','["眺望西山在目中，更須寬展竹籬通。", "殘梅尚守清廉節，不嫁東君昨夜風。"]'),
('39ed3ed1-43cf-48a9-a5ee-2b5109bb321a','首夏','俞桂','宋','宋诗','song-poetry','','[]','槐幄陰陰蔽綠扉，池抽荷葉落薔薇。',32,'全唐诗/poet.song.216000.json','["槐幄陰陰蔽綠扉，池抽荷葉落薔薇。", "梁間紫燕新雛弱，來傍簷前旋學飛。"]'),
('881bbd97-4d09-4135-9566-840b04776dc7','偶成','俞桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','短髮蕭蕭滿鏡秋，家居但覺歲時流。',32,'全唐诗/poet.song.216000.json','["短髮蕭蕭滿鏡秋，家居但覺歲時流。", "兩年不見西湖面，笑我寒盟是白鷗。"]'),
('fdbd5fb7-5572-482a-af00-2ffeadff7f7a','月夜','俞桂','宋','宋诗','song-poetry','','[]','江南又見鴈初飛，楓葉蕭疎旋覺稀。',32,'全唐诗/poet.song.216000.json','["江南又見鴈初飛，楓葉蕭疎旋覺稀。", "邊塞戍夫天氣冷，誰家月夜搗征衣。"]'),
('1bf75c92-9d77-449f-9716-ee716c9c5831','裴墳','俞桂','宋','宋诗','song-poetry','','[]','買船穿僻徑，墳古最幽深。',48,'全唐诗/poet.song.216000.json','["買船穿僻徑，墳古最幽深。", "山近風常冷，松蟠晝亦陰。", "來時無速騎，歸路有鳴禽。", "寄語城居者，何人肯訪尋。"]'),
('1d19292e-c6db-48c9-a0eb-cca4bd57d473','山中','俞桂','宋','宋诗','song-poetry','','[]','剖竹相通澗下泉，更邀山色在樽前。',32,'全唐诗/poet.song.216000.json','["剖竹相通澗下泉，更邀山色在樽前。", "一鈎明月軒窗上，欹枕藤床獨自眠。"]'),
('77b5a463-2ec0-4bb4-a7aa-86a168549318','惠山','俞桂','宋','宋诗','song-poetry','','[]','徑入松關古，秋雲带樹煙。',48,'全唐诗/poet.song.216000.json','["徑入松關古，秋雲带樹煙。", "只疑山有雨，恰是澗流泉。", "騷客詩留壁，遊人岸繫船。", "憑誰招陸羽，瀹茗古欄邊。"]'),
('cd842692-6400-4dd9-94b3-59a56c668c9a','秋懷','俞桂','宋','宋诗','song-poetry','','[]','喚醒歸舟是早秋，水光雲影兩悠悠。',32,'全唐诗/poet.song.216000.json','["喚醒歸舟是早秋，水光雲影兩悠悠。", "西風不管梧桐怨，一葉吹來一葉愁。"]'),
('467b65f2-1f28-43cd-be5f-69e69f5a0029','農事','俞桂','宋','宋诗','song-poetry','','[]','東作農家處處忙，金珠非是療饑方。',32,'全唐诗/poet.song.216000.json','["東作農家處處忙，金珠非是療饑方。", "京華只識笙歌樂，豈識男耕與女桑。"]'),
('24cec9e8-99a8-4307-9a8e-3304c6104bca','甘露寺','俞桂','宋','宋诗','song-poetry','','[]','占斷淮南勢，西風入鬢毛。',48,'全唐诗/poet.song.216000.json','["占斷淮南勢，西風入鬢毛。", "一江流不盡，多景最爲高。", "斜日迷煙樹，孤帆送客舠。", "興懷人物少，今古等秋毫。"]'),
('2fdba4d4-8751-4c1c-9bd7-29b9e91bf051','夏晨偶作','俞桂','宋','宋诗','song-poetry','','[]','蠶事行將了，農家刈麥初。',48,'全唐诗/poet.song.216000.json','["蠶事行將了，農家刈麥初。", "雨慳林少笋，水澀港無魚。", "因病嘗懲酒，偷閑懶答書。", "今年身愈老，事事覺全疎。"]'),
('666a2151-572a-410d-a0e8-e05b8e32a05a','贈雲間陸琴士','俞桂','宋','宋诗','song-poetry','','[]','地僻居閑絕可人，殷勤過我抱桐君。',32,'全唐诗/poet.song.216000.json','["地僻居閑絕可人，殷勤過我抱桐君。", "聲中知有遼天鶴，彈散華亭一片雲。"]'),
('f040dc10-7b73-443b-a9da-98aeeac61500','煙霞石壁','俞桂','宋','宋诗','song-poetry','','[]','山深入翠微，寺僻掩幽扉。',48,'全唐诗/poet.song.216000.json','["山深入翠微，寺僻掩幽扉。", "景別金仙地，人忘塵世機。", "石滋崖雨滴，龍出洞雲飛。", "結屋同僧處，何須賦式微。"]'),
('28dcdeea-8c40-49bd-b281-81567639455d','久雨','俞桂','宋','宋诗','song-poetry','','[]','踰月留京國，春光總不知。',48,'全唐诗/poet.song.216000.json','["踰月留京國，春光總不知。", "可傷連夜雨，好似暮秋時。", "有客來無酒，逢人只說詩。", "官中聞閉糴，應是細民饑。"]'),
('57f1bb4c-2802-494d-b26b-36ef29e8e871','次坦菴兄韻','俞桂','宋','宋诗','song-poetry','','[]','便中蒙賜墨，得句勝如書。',48,'全唐诗/poet.song.216000.json','["便中蒙賜墨，得句勝如書。", "暫爾兩年別，俄然春暮餘。", "夢馳情不間，心邇迹何疎。", "自省吾今老，湖山縛屋居。"]'),
('01921c0e-617c-48f4-9e13-d27da5a5f9c8','豫章滕閣','俞桂','宋','宋诗','song-poetry','','[]','滕閣昔曾遊，今無檻外樓。',48,'全唐诗/poet.song.216000.json','["滕閣昔曾遊，今無檻外樓。", "遠山連樹合，盡日對江流。", "古石空存記，騷人易感愁。", "夜深歌酒處，燈火燦漁舟。"]'),
('a54d009b-1a70-4742-a8ee-6b9ae0cd45ca','寄書','俞桂','宋','宋诗','song-poetry','','[]','歲月逡巡笑故吾，人生南北隔江湖。',32,'全唐诗/poet.song.216000.json','["歲月逡巡笑故吾，人生南北隔江湖。", "樓頭約取衡陽鴈，寄得一行書信無。"]'),
('6f861a84-b634-4c41-8239-367a55f70468','冷泉亭','俞桂','宋','宋诗','song-poetry','','[]','步入侵雲嶺，亭高路恰平。',48,'全唐诗/poet.song.216000.json','["步入侵雲嶺，亭高路恰平。", "池邊幽樹占，水底細沙明。", "無友詩難詠，逢僧話轉清。", "此中真勝地，林寂鳥無聲。"]'),
('348a5b76-8fc4-49a7-95c1-00f13ba09769','夏晝','俞桂','宋','宋诗','song-poetry','','[]','輕摇羽扇著輕紗，閑汲清泉自煮茶。',32,'全唐诗/poet.song.216000.json','["輕摇羽扇著輕紗，閑汲清泉自煮茶。", "緣是夏來無甚雨，小池猶未有荷花。"]'),
('1a43e9c4-3240-4c47-a400-8d4f55af6779','楓橋寺','俞桂','宋','宋诗','song-poetry','','[]','湖水相連月照天，鴈聲嘹嚦攪人眠。',32,'全唐诗/poet.song.216000.json','["湖水相連月照天，鴈聲嘹嚦攪人眠。", "昔年曾到楓橋宿，石岸傍邊繫小船。"]'),
('12feedbc-b567-4530-92bd-e64bccbfc76d','秋千','俞桂','宋','宋诗','song-poetry','','[]','吾今兩鬢已成絲，每每逢春獨自悲。',32,'全唐诗/poet.song.216000.json','["吾今兩鬢已成絲，每每逢春獨自悲。", "最恨秋千無力上，風流不比少年時。"]'),
('790910cb-0224-4588-bd08-d39877d442dd','早春','俞桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','客裏匆匆二月春，梅花開後柳爭新。',32,'全唐诗/poet.song.216000.json','["客裏匆匆二月春，梅花開後柳爭新。", "西湖不待清明到，早有尋芳拾翠人。"]'),
('ccda8464-3d41-48ce-a1d6-c627c93fec32','寄懷','俞桂','宋','宋诗','song-poetry','','[]','一番舊事總成空，莫使相思夢裏逢。',32,'全唐诗/poet.song.216000.json','["一番舊事總成空，莫使相思夢裏逢。", "惆悵陽臺雲共雨，陽臺今隔幾千重。"]'),
('dd38dbd0-07ad-4ae3-ae13-9291e677b492','夏中即事','俞桂','宋','宋诗','song-poetry','','[]','青青梅子已添肥，犢角新抽晚筍遲。',32,'全唐诗/poet.song.216000.json','["青青梅子已添肥，犢角新抽晚筍遲。", "茶罷日長消睡處，案頭一卷樂天詩。"]'),
('66370a1a-4401-4a24-bee7-c098641d29e9','看先叔祖青松居士倉使詩','俞桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','儒冠每笑拙身謀，春日因何桂玉留。',64,'全唐诗/poet.song.216000.json','["儒冠每笑拙身謀，春日因何桂玉留。", "南浦未思芳草恨，西湖正爲落梅愁。", "四靈去矣今如在，諸老蕭然事已休。", "衣鉢青松誰繼續，家雞還復可搜求。"]'),
('c17d3f3e-6a67-40f7-9809-8d19367694ca','軍中請衣','俞桂','宋','宋诗','song-poetry','','[]','諸營今日請春衣，積沓如山競捧歸。',32,'全唐诗/poet.song.216000.json','["諸營今日請春衣，積沓如山競捧歸。", "曾念雪中兵墮指，戍邊鐵甲正防圍。"]'),
('3ea44cf8-08d9-468c-8c1c-1e04c86e8865','海棠','俞桂','宋','宋诗','song-poetry','','[]','海棠嫋嫋弄臙脂，雨入枝頭睡正宜。',32,'全唐诗/poet.song.216000.json','["海棠嫋嫋弄臙脂，雨入枝頭睡正宜。", "最是高人有遺恨，杜陵因甚却無詩。"]'),
('f1e53aff-b1d2-4576-bb67-1745ac1043ca','居官','俞桂','宋','宋诗','song-poetry','','[]','幸喜居官事不多，庭空吏散雀堪羅。',32,'全唐诗/poet.song.216000.json','["幸喜居官事不多，庭空吏散雀堪羅。", "近來轉覺詩朋少，誰肯高軒爲我過。"]'),
('debd7d82-4dde-4a5d-9d62-eea72d804270','心事','俞桂','宋','宋诗','song-poetry','','[]','落落功名鬢早斑，蹉跎心事十年間。',32,'全唐诗/poet.song.216000.json','["落落功名鬢早斑，蹉跎心事十年間。", "看來只合歸湖上，漁釣叢中盡日閑。"]'),
('4310be52-b8a3-4e01-b1f9-8c84199b7770','垂虹','俞桂','宋','宋诗','song-poetry','','[]','松江一景是虹橋，欲約騷人釣巨鼇。',64,'全唐诗/poet.song.216000.json','["松江一景是虹橋，欲約騷人釣巨鼇。", "吳越封疆知幾夢，古今人物壯三高。", "雪天斫鱠莎煙冷，秋月漁歌劍氣豪。", "收拾琉璃千萬頃，盡爲醽醁汲波濤。"]'),
('a290baa6-5dd5-4a67-998c-b3ec8c251367','臘八前四日','俞桂','宋','宋诗','song-poetry','','[]','天氣晴和又作陰，老來畏冷自難禁。',32,'全唐诗/poet.song.216000.json','["天氣晴和又作陰，老來畏冷自難禁。", "餘霙待伴留痕在，殊動騷人訪戴心。"]'),
('6cfb2dd0-e8ef-40ed-9161-b075b739974c','湖上閑步','俞桂','宋','宋诗','song-poetry','','[]','一番雨過一番春，芒竹閑行踏軟塵。',32,'全唐诗/poet.song.216000.json','["一番雨過一番春，芒竹閑行踏軟塵。", "城裏不知春色早，湖邊楊柳已撩人。"]'),
('bd6c0206-d088-49af-a055-297a4ef9405e','新竹','俞桂','宋','宋诗','song-poetry','','[]','傍牆穿過鄰家竹，愛護新篁數十竿。',32,'全唐诗/poet.song.216000.json','["傍牆穿過鄰家竹，愛護新篁數十竿。", "剪伐莫令童僕輩，老夫日日要來看。"]'),
('ac914503-85a0-4dfc-98a4-9d621d349af2','松江','俞桂','宋','宋诗','song-poetry','','[]','香飄菡萏短篷中，水色山光一樣同。',32,'全唐诗/poet.song.216000.json','["香飄菡萏短篷中，水色山光一樣同。", "行止又非人所料，今年兩度上垂虹。"]'),
('fb442ac5-15ea-43e8-b130-8f5e9cf73c24','虎丘','俞桂','宋','宋诗','song-poetry','','[]','突兀浮圖插翠微，吳王事迹總成非。',32,'全唐诗/poet.song.216000.json','["突兀浮圖插翠微，吳王事迹總成非。", "寺僧未晚山門閉，不放閑雲一片飛。"]'),
('c078d467-d122-4eb4-8539-8905434356e0','秋詠','俞桂','宋','宋诗','song-poetry','','[]','吟軸捲還開，行歌興盡回。',48,'全唐诗/poet.song.216000.json','["吟軸捲還開，行歌興盡回。", "買花澆換葉，開徑掃蒼苔。", "巾學凉紗樣，衣從薄苧裁。", "潘郎羞鬢白，多是爲秋來。"]'),
('b751fab9-1b83-4162-9ae1-37a509bb9974','秋夜','俞桂','宋','宋诗','song-poetry','','[]','秋夜多愁思，虛堂風露凉。',48,'全唐诗/poet.song.216000.json','["秋夜多愁思，虛堂風露凉。", "觀書燈可近，欲睡漏初長。", "蛩響頻催織，螢飛爍有光。", "雨梢窗外過，散入稻花香。"]'),
('a63ef12b-3723-4eb5-bfbd-25b7e8bbafe0','寄陳芸居','俞桂','宋','宋诗','song-poetry','','[]','生長京華地，衣冠東晉人。',48,'全唐诗/poet.song.216000.json','["生長京華地，衣冠東晉人。", "書中塵不到，筆下句通神。", "江海知名日，池塘幾夢春。", "精神長似舊，芸藁愈清新。"]'),
('616a5d37-fd97-4db6-b9fe-bf8b3e1a5cd6','冷泉亭','俞桂','宋','宋诗','song-poetry','','[]','欲訪飛來景，湖頭賃小船。',48,'全唐诗/poet.song.216000.json','["欲訪飛來景，湖頭賃小船。", "白雲侵嶺下，翠樹傍泉邊。", "入寺人須到，深林影自圓。", "山居相去近，夜坐學參禪。"]'),
('ddfd5e0f-0c65-4868-9a59-f45427b5bc74','春晚湖上','俞桂','宋','宋诗','song-poetry','','[]','花事已成休，都人懶出遊。',48,'全唐诗/poet.song.216000.json','["花事已成休，都人懶出遊。", "水添煙浪闊，山带夕陽愁。", "柳樹鳴黄鳥，沙堤卧白鷗。", "不辭歸路遠，何必買扁舟。"]'),
('2a2c42d3-8a45-4699-9a28-bd893a46e4a5','春詠','俞桂','宋','宋诗','song-poetry','','[]','盡日看詩只掩扉，出門細雨怕霑衣。',32,'全唐诗/poet.song.216000.json','["盡日看詩只掩扉，出門細雨怕霑衣。", "杏花已露臙脂色，燕子如何却未歸。"]'),
('2da4d8f7-d0e5-4bad-8208-d40bece38bb8','苔錢','俞桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','庭砌方圓出化鈞，何須抵死論錢神。',32,'全唐诗/poet.song.216000.json','["庭砌方圓出化鈞，何須抵死論錢神。", "貧家阿堵新添富，買斷西湖風月春。"]'),
('5359fc78-a3a7-428a-a0f6-3b013d71af84','買魚','俞桂','宋','宋诗','song-poetry','','[]','蘆花荷葉晚秋天，鴈影橫斜遠水連。',32,'全唐诗/poet.song.216000.json','["蘆花荷葉晚秋天，鴈影橫斜遠水連。", "頻喚買魚人不譍，偷忙撐入怕官船。"]'),
('b0c722a7-2147-4684-b324-8176291fa081','即事','俞桂','宋','宋诗','song-poetry','','[]','東君無處不繁華，一雨纔晴意便佳。',32,'全唐诗/poet.song.216000.json','["東君無處不繁華，一雨纔晴意便佳。", "客舍山梅開遍了，從今懶買檐頭花。"]'),
('45625dc0-e982-4f92-8134-6a7629421461','送春','俞桂','宋','宋诗','song-poetry','','[]','作惡情懷是別離，老夫懶作送春詩。',32,'全唐诗/poet.song.216000.json','["作惡情懷是別離，老夫懶作送春詩。", "東君歸去無蹤跡，試問垂楊便可知。"]'),
('f27fff0b-663e-472b-9ff4-b11279286977','春歸  其一','俞桂','宋','宋诗','song-poetry','','[]','青青結子在梅梢，方見春來夏已交。',32,'全唐诗/poet.song.216000.json','["青青結子在梅梢，方見春來夏已交。", "認得主人雙燕子，香泥銜去理新巢。"]'),
('888b899c-3048-4545-8153-dac5295547ba','春歸  其二','俞桂','宋','宋诗','song-poetry','','[]','晴天氣淑濃如酒，引得狂蜂路亦迷。',32,'全唐诗/poet.song.216000.json','["晴天氣淑濃如酒，引得狂蜂路亦迷。", "獨立欄干凝望處，賣花人在畫橋西。"]'),
('3c4115c5-1c4e-41ea-bd74-62a050061561','閑中','俞桂','宋','宋诗','song-poetry','','[]','花飛春減燕雛飛，葉葉成陰障翠圍。',32,'全唐诗/poet.song.216000.json','["花飛春減燕雛飛，葉葉成陰障翠圍。", "囊裏酒錢消鑠盡，滿船贏得載詩歸。"]'),
('4165d80a-2463-4b4a-bc27-b1882ff9704c','江頭','俞桂','宋','宋诗','song-poetry','','[]','漁浦山邊白鷺飛，西興渡口夕陽微。',32,'全唐诗/poet.song.216000.json','["漁浦山邊白鷺飛，西興渡口夕陽微。", "等閑更上層樓望，貪看江潮不肯歸。"]'),
('49244621-00c1-4485-9578-6836a1701e24','口占','俞桂','宋','宋诗','song-poetry','','[]','園林綠暗又紅稀，蜀鳥啼山笋蕨肥。',32,'全唐诗/poet.song.216000.json','["園林綠暗又紅稀，蜀鳥啼山笋蕨肥。", "春夏一番交篆早，綿衣脫了著單衣。"]'),
('70c52edb-2be5-41b3-ada5-d998b547cebb','吟詩','俞桂','宋','宋诗','song-poetry','','[]','漁溪僻好只吟詩，此意還須識者知。',32,'全唐诗/poet.song.216000.json','["漁溪僻好只吟詩，此意還須識者知。", "自古島郊貧徹骨，詩逢窮處始爲奇。"]'),
('6342a28c-d38a-4f44-a99b-825fd05ae677','社日','俞桂','宋','宋诗','song-poetry','','[]','今朝社日寒猶力，燕子還尋五柳家。',32,'全唐诗/poet.song.216000.json','["今朝社日寒猶力，燕子還尋五柳家。", "宰肉不沾吾分薄，强斟聾酒度年華。"]'),
('a1e3dd3f-eda8-4402-827d-4b650d9c3cb7','喜雨上別大參','俞桂','宋','宋诗','song-poetry','','[]','爰立爲霖仰望深，今朝一雨慰蒼生。',64,'全唐诗/poet.song.216000.json','["爰立爲霖仰望深，今朝一雨慰蒼生。", "經綸久柬君心在，燮理還同天道亨。", "愛國慮勤寬玉带，籌邊謀遠捍金城。", "我公勳業難模寫，但見皇家慶太平。"]'),
('33e24a8d-7531-454b-bc3b-a087a7a72ca8','寓京二首  其一','俞桂','宋','宋诗','song-poetry','','[]','一官濩落笑如初，只合空山去讀書。',32,'全唐诗/poet.song.216000.json','["一官濩落笑如初，只合空山去讀書。", "不稼不漁無活計，謾將名氏玷公車。"]'),
('bce4046a-1ea9-4e9b-b3d7-6d8e078add0b','寓京二首  其二','俞桂','宋','宋诗','song-poetry','','[]','車馬滔滔厭軟紅，湖邊秋意属西風。',32,'全唐诗/poet.song.216000.json','["車馬滔滔厭軟紅，湖邊秋意属西風。", "木犀初放荷花老，買箇船兒學釣翁。"]'),
('56ce8d99-4b7f-4bd4-b7c3-9cd2b20b9683','春日即事  其一','俞桂','宋','宋诗','song-poetry','','[]','春入侯家春事深，日長庭院又沉沉。',32,'全唐诗/poet.song.216000.json','["春入侯家春事深，日長庭院又沉沉。", "客中不耐如絲雨，攪起思家寸寸心。"]'),
('73edfeca-24c1-47c9-b047-1974246df047','春日即事  其二','俞桂','宋','宋诗','song-poetry','','[]','春光滿目是吳頭，水碧琉璃拍岸流。',32,'全唐诗/poet.song.216000.json','["春光滿目是吳頭，水碧琉璃拍岸流。", "憶著去年桃葉渡，相思無限使人愁。"]'),
('293547a7-c57b-47a9-9be9-86656c037998','丙午七夕後一日晚抵松江塔下  其一','俞桂','宋','宋诗','song-poetry','','[]','到得垂虹迫暮煙，前村雨暗莫行船。',32,'全唐诗/poet.song.216000.json','["到得垂虹迫暮煙，前村雨暗莫行船。", "幸然得與僧人熟，借得終宵客位眠。"]'),
('0a958718-f503-43b6-8d5d-faa46b3654bb','丙午七夕後一日晚抵松江塔下  其二','俞桂','宋','宋诗','song-poetry','','[]','客中情况少人知，正值鍾聲約束時。',32,'全唐诗/poet.song.216000.json','["客中情况少人知，正值鍾聲約束時。", "清坐更無人共話，挑燈來看菊潭詩。"]'),
('23dc8e10-f9f7-4005-b724-bbb118ebe5fb','江上','俞桂','宋','宋诗','song-poetry','','[]','江頭雲閣雨，柳色與春深。',24,'全唐诗/poet.song.216000.json','["江頭雲閣雨，柳色與春深。", "船發春風阻，誰知客子心。"]'),
('47230662-f55a-41c5-8182-ba5cae717532','居閑','俞桂','宋','宋诗','song-poetry','','[]','富貴人所願，貧賤不堪憂。',72,'全唐诗/poet.song.216000.json','["富貴人所願，貧賤不堪憂。", "自有蘭蕙清，非比蕭艾羞。", "功名如露草，飄瓦若虛舟。", "千載儻相遇，臯夔及伊周。", "苟使窮未達，一壑營一丘。", "出處謹吾節，斯心已細籌。"]'),
('b9bbfdff-3a32-43eb-a80f-e3fe4977322c','古意','俞桂','宋','宋诗','song-poetry','','[]','無言情脉脉，美人久相隔。',60,'全唐诗/poet.song.216000.json','["無言情脉脉，美人久相隔。", "道阻脩且長，春草幾番碧。", "鳳釵冷鬢雲，鸞鏡輕雲羃。", "昔爲比翼鳥，今作孤飛翮。", "愁絕寄郎衣，腰瘦裁宜窄。"]'),
('a6f5c076-2c55-4635-b44c-35384d75b604','春日即事','俞桂','宋','宋诗','song-poetry','','[]','羲馭舒徐日正遲，園林已覺杏花稀。',32,'全唐诗/poet.song.216000.json','["羲馭舒徐日正遲，園林已覺杏花稀。", "半晴半雨春無準，燕怯輕寒不耐飛。"]'),
('352efd7b-ad97-4bb4-bf1c-a5662155b26d','即事','俞桂','宋','宋诗','song-poetry','','[]','薄薄輕輕寒露雨，微微颯颯早秋風。',32,'全唐诗/poet.song.216000.json','["薄薄輕輕寒露雨，微微颯颯早秋風。", "小舟辦了松江去，占取三高作釣翁。"]'),
('8e4aa46a-f64f-429f-9226-fdd0909c4e1f','賞月','俞桂','宋','宋诗','song-poetry','','[]','天浄無一雲，地浄無一塵。',132,'全唐诗/poet.song.216000.json','["天浄無一雲，地浄無一塵。", "十六月圓滿，皎皎白玉輪。", "古今同此月，照破世間人。", "夜久方浴出，露坐風滿襟。", "清影入窗戶，聊足尉我心。", "所欠一樽酒，所乏一張琴。", "如此好月色，惜乎在海濱。", "癡兒官事了，空自疲精神。", "不得賞新月，酬酢相與頻。", "今宵詩興動，狂吟漁溪民。", "獨對猶復爾，况逢親共賓。"]'),
('061f68b2-09a9-43a8-a96f-2779e1c30f4b','採蓮曲','俞桂','宋','宋诗','song-poetry','','[]','畫艇將歸笑語頻，鴛鴦對對起還沉。',32,'全唐诗/poet.song.216000.json','["畫艇將歸笑語頻，鴛鴦對對起還沉。", "妾心先自懷郎苦，怕嚼蓮心苦轉深。"]'),
('fd221dbf-b01e-411e-a97f-51b3a4dabc67','靈隠','俞桂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','回首得兩年，曾入靈隠去。',48,'全唐诗/poet.song.216000.json','["回首得兩年，曾入靈隠去。", "一路看不足，衣霑松上露。", "白雲來相迎，澗泉飛瀑素。", "此景天下無，遠勝廬山路。"]'),
('5a47c47e-c46c-4d6c-a740-08f612e89a36','種竹','俞桂','宋','宋诗','song-poetry','','[]','門前槐已長，庭內草自生。',84,'全唐诗/poet.song.216000.json','["門前槐已長，庭內草自生。", "所欠園中竹，多種渠幾莖。", "此君真可愛，非獨王猷情。", "有時吟詠暇，入園得閑行。", "所幸筍萌出，次第陰可成。", "□使神宇爽，漸覺眼界清。", "最是秋雨夜，風來□□□。"]'),
('e1a988ef-8c11-4e8d-94c2-33c34c622c8e','春暮寄友人','俞桂','宋','宋诗','song-poetry','','[]','日煖梨花雪，風吹楊柳綿。',48,'全唐诗/poet.song.216000.json','["日煖梨花雪，風吹楊柳綿。", "春踰三月半，夢憶十年前。", "詩借鶑聲和，書無鴈字傳。", "東君還似舊，吾鬢嘆皤然。"]'),
('3553560d-3022-4f18-ae92-c5367f1f8b2d','即事','俞桂','宋','宋诗','song-poetry','','[]','吹落楊花春事了，小池新綠雨添痕。',32,'全唐诗/poet.song.216000.json','["吹落楊花春事了，小池新綠雨添痕。", "育蠶時節寒猶在，村落人家半掩門。"]'),
('e8fc5560-c1dd-46bb-a820-91224d4591c8','初夏','俞桂','宋','宋诗','song-poetry','','[]','薔薇花已謝，芍藥擬下坡。',96,'全唐诗/poet.song.216000.json','["薔薇花已謝，芍藥擬下坡。", "午陰有嘉樹，景序猶清和。", "日得詩篇詠，門無俗客過。", "笋胎今歲少，荷葉小池多。", "春去餘旬日，夏雲已嵯峩。", "吾年嗟老矣，身事笑蹉跎。", "但欲卧白石，幽巖捫青蘿。", "已與心料理，不必問如何。"]'),
('c91e83b7-84f3-4717-adde-b46e8008eb4d','次下竺僧韻','俞桂','宋','宋诗','song-poetry','','[]','朝市軟紅塵，山林氣味深。',48,'全唐诗/poet.song.216000.json','["朝市軟紅塵，山林氣味深。", "放懷隨野鶴，過耳任春禽。", "石澗鳴泉玉，松釵墜日陰。", "隠居無箇事，存養讀書心。"]'),
('b8949e03-0183-475e-abf7-95cd5f837a33','江上','俞桂','宋','宋诗','song-poetry','','[]','小雨纔收日漸斜，酒旗插處兩三家。',32,'全唐诗/poet.song.216000.json','["小雨纔收日漸斜，酒旗插處兩三家。", "江頭粧點秋來景，半是蘆花半蓼花。"]'),
('7238047c-30a4-4ec0-8c97-249db25f628c','秋日','俞桂','宋','宋诗','song-poetry','','[]','芙蓉未拆桂香浮，落日西風鴈過樓。',32,'全唐诗/poet.song.216000.json','["芙蓉未拆桂香浮，落日西風鴈過樓。", "一雨空階深夜滴，十分秋是十分愁。"]'),
('9ca2af1c-e9fe-431c-9090-50655f6dba59','偶成','俞桂','宋','宋诗','song-poetry','','[]','吹來一葉報秋知，玉露金風正及時。',32,'全唐诗/poet.song.216000.json','["吹來一葉報秋知，玉露金風正及時。", "戴了凉巾披野服，桂花香裏看唐詩。"]'),
('2c2d5279-4633-4ef9-9b28-64e77320c71e','秋行吟','俞桂','宋','宋诗','song-poetry','','[]','西風緊兮葉脫枝，寒露瀼兮菊遶籬。',128,'全唐诗/poet.song.216000.json','["西風緊兮葉脫枝，寒露瀼兮菊遶籬。", "蘆花白兮蓼滿湄，鴈聲急兮蛩轉悲。", "樂吾淛兮殊興思，况東淮兮落遠陲。", "朝氣肅兮夜漏遲，暮雲黯兮山色衰。", "紛紛瞇目黄埃吹，艱關千里徒驅馳。", "窮猿投林任所之，膏粱諸公那得知。", "從今休被微官縛，未若琴歌詩酒樂。", "豈無手足懷我情，當念行人多寂寞。"]'),
('8c7072e5-1d3a-43d1-82d4-7bf0236c8470','習氣','俞桂','宋','宋诗','song-poetry','','[]','習氣於詩却未除，儘教人笑治生疎。',32,'全唐诗/poet.song.216000.json','["習氣於詩却未除，儘教人笑治生疎。", "功夫若到窮吟地，雖是居貧富不如。"]'),
('0cb82de9-0aa1-4161-b632-8784694df20c','即事','俞桂','宋','宋诗','song-poetry','','[]','暑赫練襟汗欲流，倩誰喚得一天秋。',32,'全唐诗/poet.song.216000.json','["暑赫練襟汗欲流，倩誰喚得一天秋。", "無人共訂吟邊句，獨有蟬聲叫樹頭。"]'),
('e28d1c8a-1b8c-4a77-bc04-607846c54a72','平湖','俞桂','宋','宋诗','song-poetry','','[]','平湖一景堪圖畫，舟子煙波去復歸。',32,'全唐诗/poet.song.216000.json','["平湖一景堪圖畫，舟子煙波去復歸。", "舊日玄真無覓處，西山長見鷺鷥飛。"]'),
('318d80d0-221a-456f-89ff-a7018a39078f','半塘','俞桂','宋','宋诗','song-poetry','','[]','因訪雲巖過半塘，清明時候野花香。',32,'全唐诗/poet.song.216000.json','["因訪雲巖過半塘，清明時候野花香。", "小舟趁雨衝風去，不及尋僧到上方。"]'),
('83af665b-9793-4b86-8b59-a712d1c1ae24','送人至松江','俞桂','宋','宋诗','song-poetry','','["\u6292\u60c5"]','西風蕭瑟入船窗，送客離愁酒滿缸。',32,'全唐诗/poet.song.216000.json','["西風蕭瑟入船窗，送客離愁酒滿缸。", "要記此時分袂處，暮煙細雨過松江。"]'),
('37afb3fa-adeb-4ddd-a40d-8f514f97f83a','雨後','俞桂','宋','宋诗','song-poetry','','[]','雨後新晴日轉西，桑間猶有拙鳩啼。',32,'全唐诗/poet.song.216000.json','["雨後新晴日轉西，桑間猶有拙鳩啼。", "十分愁意無人管，紅蓼黄蘆水滿溪。"]'),
('bb8ab164-81c8-4bb6-bad6-6dac279c3659','紀愁','俞桂','宋','宋诗','song-poetry','','[]','可笑無詩紀四愁，强將歡伯解吾憂。',32,'全唐诗/poet.song.216000.json','["可笑無詩紀四愁，强將歡伯解吾憂。", "夜長明月紗窗冷，分得寒蛩一半秋。"]'),
('d7382034-7126-4f28-a646-acfb698df58e','和樂天初夏韻','俞桂','宋','宋诗','song-poetry','','[]','雨脚來山岫，溪痕漲岸沙。',72,'全唐诗/poet.song.216000.json','["雨脚來山岫，溪痕漲岸沙。", "插旗多酒戶，掛網盡漁家。", "地出綳兒笋，園收菜子花。", "春歸鶑囀嬾，風急燕飛斜。", "盃瀉青荷葉，甌煎白玉茶。", "孤村流水晚，數點有歸鴉。"]'),
('43d38423-fdd3-4af0-b37f-e3f33ee2f090','述己','俞桂','宋','宋诗','song-poetry','','[]','落落功名鬢久斑，重遊京國又何顔。',32,'全唐诗/poet.song.216000.json','["落落功名鬢久斑，重遊京國又何顔。", "早知寸祿榮家晚，悔不當初便入山。"]'),
('0272f3d2-eaae-4186-a73b-b4259183ac4e','釣臺','俞桂','宋','宋诗','song-poetry','','[]','不愛三公漢祿榮，一絲風月許多清。',32,'全唐诗/poet.song.216000.json','["不愛三公漢祿榮，一絲風月許多清。", "只將節義高千古，豈釣人間利共名。"]'),
('cf89f4c3-4f62-454a-a770-b0542fc892fe','七夕有懷','俞桂','宋','宋诗','song-poetry','','[]','擘釵情緒思悠悠，月下穿針嬾傍樓。',32,'全唐诗/poet.song.216000.json','["擘釵情緒思悠悠，月下穿針嬾傍樓。", "非獨雙星苦離別，人間天上一般愁。"]'),
('ee1962eb-4f28-4bc8-8d75-c0c95b4166bd','秋夜','俞桂','宋','宋诗','song-poetry','','[]','月華如水浄無塵，千里相思總一心。',32,'全唐诗/poet.song.216000.json','["月華如水浄無塵，千里相思總一心。", "絡緯籬邊吟不徹，做成秋意十分深。"]'),
('00626e24-0c1d-411c-b030-76ffe582469a','賡宋雪巖韻','俞桂','宋','宋诗','song-poetry','','[]','詩與梅花一樣清，江湖久矣熟知名。',64,'全唐诗/poet.song.216000.json','["詩與梅花一樣清，江湖久矣熟知名。", "未容便理趨朝計，行見相留入幕榮。", "照座精神澄玉宇，當官才刃壓金城。", "星郎况是曾知己，刮目英游藻鑑明。"]'),
('caea9e7e-0552-4431-a4c5-21deb6bef9ca','南蹌跧上人之平江','俞桂','宋','宋诗','song-poetry','','[]','青浦相逢恰二年，今宵再會亦前緣。',32,'全唐诗/poet.song.216000.json','["青浦相逢恰二年，今宵再會亦前緣。", "詩囊和月橫挑去，穩泛楓橋夜半船。"]'),
('61b9792d-8b1a-4cc2-b022-a1555df56084','夏日遣懷','俞桂','宋','宋诗','song-poetry','','[]','老大今無用，吟詩了白頭。',48,'全唐诗/poet.song.216000.json','["老大今無用，吟詩了白頭。", "百年如電影，萬事付沙鷗。", "性淡偏宜靜，居貧動是愁。", "人情難似舊，門外水長流。"]'),
('1b6e77d6-8bb6-4502-b4d7-25567d72df8a','寓歸','俞桂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','水激長江浪，風傳遠寺鍾。',48,'全唐诗/poet.song.216000.json','["水激長江浪，風傳遠寺鍾。", "宦情秋意薄，歸興客愁濃。", "捲箔迎新鴈，喧籬厭舊蛩。", "何時旋故里，載酒插芙蓉。"]'),
('8df765da-40df-4a0e-8de0-4949f657fdd9','性拙','俞桂','宋','宋诗','song-poetry','','[]','性拙難爲巧，年來陰屢經。',48,'全唐诗/poet.song.216000.json','["性拙難爲巧，年來陰屢經。", "身閑詩謾賦，心靜夢能靈。", "富貴如朝露，英雄幾曉星。", "尋思世間事，日影過中庭。"]'),
('9d7bb1ba-8963-45b4-a5ac-81bc9ce6a132','秋日即事','俞桂','宋','宋诗','song-poetry','','[]','宿有騷人興，休教世俗知。',48,'全唐诗/poet.song.216000.json','["宿有騷人興，休教世俗知。", "郊墟聊晚眺，風月入秋宜。", "愁極惟憑酒，囊空却剩詩。", "更長人不睡，燈火可親時。"]'),
('0a96f5ca-cade-4c80-9f10-3a53311f0808','論詩','俞桂','宋','宋诗','song-poetry','','[]','大道本無體，何在文字間。',48,'全唐诗/poet.song.216000.json','["大道本無體，何在文字間。", "易從先天畫，詩自聖人刪。", "流風傳益遠，後作莫可攀。", "推敲誰氏子，一字不可閑。"]'),
('19567811-845c-448e-b619-8d0af77f5576','採蓮曲  其一','俞桂','宋','宋诗','song-poetry','','[]','朝露濕妾衣，暮霞耀妾矚。',72,'全唐诗/poet.song.216000.json','["朝露濕妾衣，暮霞耀妾矚。", "一葉小如瓜，去住無拘束。", "兀棹歌採菱，襲襲薰風足。", "蘆葉映港清，捉對鴛鴦浴。", "蓮中有苦心，欲折手還曲。", "折蓮恐傷藕，藕斷絲難續。"]'),
('7932e4da-8ee9-472f-b63e-c3943c656689','採蓮曲  其二','俞桂','宋','宋诗','song-poetry','','[]','平湖淼淼蓮風清，花開映日紅妝明。',64,'全唐诗/poet.song.216000.json','["平湖淼淼蓮風清，花開映日紅妝明。", "一雙鸂鶒忽飛去，爲驚花底蘭橈鳴。", "蘭橈蕩漾誰家女，雲妥髻鬟黛眉嫵。", "采采荷花滿袖香，荷深忘却歸時路。"]'),
('31168943-7e57-4970-99b2-e9c5cee04b1e','採蓮曲  其三','俞桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖西畔荷花多，扣舷女兒嬌唱歌。',96,'全唐诗/poet.song.216000.json','["西湖西畔荷花多，扣舷女兒嬌唱歌。", "道旁駿馬金叵羅，欲住不住橫秋波。", "放船却入花深處，臨流照妝噤不語。", "南山起雲北山雨，折得荷花不歸去。", "弄波驚起鴛鴦雙，水珠濺濕芙蓉裳。", "恨無飛羽致汝旁，遡澠從之雲路長。"]'),
('5e8771e4-2f08-4d39-8cfb-9246e5d8b483','採蓮曲  其四','俞桂','宋','宋诗','song-poetry','','[]','西風引袂涼雲起，鴛槳扶船浮淥水。',96,'全唐诗/poet.song.216000.json','["西風引袂涼雲起，鴛槳扶船浮淥水。", "露沁花脂茜粉香，滿柄鋒芒刺葱指。", "紅綃半妥金釧明，堤上六郎闚唱聲。", "湘中暮雨歡期失，各自東西空目成。", "船蕩波心烟漠漠，歸路花從唱邊落。", "綠艷紅妖江水深，水底靈均應不覺。"]'),
('2966cfc2-fb04-411e-8e66-2e9cc9b4f676','採蓮曲  其五','俞桂','宋','宋诗','song-poetry','','[]','女伴歌採蓮，清聲度流水。',24,'全唐诗/poet.song.216000.json','["女伴歌採蓮，清聲度流水。", "無意驚鴛鴦，鴛鴦自飛起。"]'),
('546c9090-16f8-4500-b82b-8b89f84eeca2','採蓮曲  其六','俞桂','宋','宋诗','song-poetry','','[]','荷葉籠頭學道情，花妝那似妾妝清。',32,'全唐诗/poet.song.216000.json','["荷葉籠頭學道情，花妝那似妾妝清。", "雙雙頭白猶交頸，翻笑鴛鴦不老成。"]'),
('10514dc0-e02b-4fe1-aa3e-edf22272ed5e','採蓮曲  其七','俞桂','宋','宋诗','song-poetry','','[]','拗落圓房響釧金，昔人細數子藏深。',32,'全唐诗/poet.song.216000.json','["拗落圓房響釧金，昔人細數子藏深。", "不嫌到手多尖刺，祇怕傷人有苦心。"]'),
('9b426ccc-427e-43b5-9b23-37cee2ccdfc9','提幹漁溪','俞桂','宋','宋诗','song-poetry','','[]','不涉驚濤心自穩，柳陰陰處著孤舟。',32,'全唐诗/poet.song.216000.json','["不涉驚濤心自穩，柳陰陰處著孤舟。", "的知世路多機穽，一線閒名付直鈎。"]'),
('be117457-ece3-405f-85c6-db10bce7b41c','香林洞','俞桂','宋','宋诗','song-poetry','','[]','月月巖頭古翠埋，綿雲深隔洞門開。',64,'全唐诗/poet.song.216000.json','["月月巖頭古翠埋，綿雲深隔洞門開。", "蒼藤隨石無根活，靈杞何年有種栽。", "氣凝野烟疑麝過，暖熏山雨誤蜂來。", "空庭誰領幽芳坐，雪鶴同行損綠苔。"]'),
('0352af23-1083-4feb-a0e9-809489fdc181','石筍峰','俞桂','宋','宋诗','song-poetry','','[]','異種休參玉板禪，嶄然一角立層巔。',64,'全唐诗/poet.song.216000.json','["異種休參玉板禪，嶄然一角立層巔。", "遠尖自抱雲根壯，疊蘚誰疑雨籜纏。", "夢裏三生空過眼，胸中千畝漫流涎。", "此龍難入寧僧譜，出土摩霄是幾年。"]'),
('6b2a1d64-eb73-4db6-984a-c2dcdb1e6033','和顔長官百詠 農桑 其一','朱繼芳','宋','宋诗','song-poetry','','[]','裹飯驅兒候暖耕，堘泥滑滑不堪行。',32,'全唐诗/poet.song.216000.json','["裹飯驅兒候暖耕，堘泥滑滑不堪行。", "如何說得農家苦，雨笠風蓑過一生。"]'),
