('3991bf03-64b1-41a5-ada2-335a7284e52b','和顔長官百詠 山居 其六','朱繼芳','宋','宋诗','song-poetry','','[]','好山當戶四無隣，似是秦時採藥人。',32,'全唐诗/poet.song.216000.json','["好山當戶四無隣，似是秦時採藥人。", "千百年間天地裏，不多不少一閑身。"]'),
('528f22a7-30a5-4fd6-b75a-6fbea22699a4','和顔長官百詠 山居 其七','朱繼芳','宋','宋诗','song-poetry','','[]','宿世仙家十二樓，誤嬰時網未深愁。',32,'全唐诗/poet.song.216000.json','["宿世仙家十二樓，誤嬰時網未深愁。", "浮丘輩行如相覓，騎却紫雲歸去休。"]'),
('6b53cfc6-3bc7-4736-b010-5d8df3b94ef4','和顔長官百詠 山居 其八','朱繼芳','宋','宋诗','song-poetry','','[]','種藥千畦手自鋤，年來漸喜識人疎。',32,'全唐诗/poet.song.216000.json','["種藥千畦手自鋤，年來漸喜識人疎。", "等閑旋點黄金賣，莫訝家無檐石儲。"]'),
('48a2e638-5f33-4717-8a36-d85b79b6f8be','和顔長官百詠 山居 其九','朱繼芳','宋','宋诗','song-poetry','','[]','矮窗欹枕看朝榮，老覺迎逢禮數生。',32,'全唐诗/poet.song.216000.json','["矮窗欹枕看朝榮，老覺迎逢禮數生。", "來往頗知麋鹿性，寒暄不會俗人情。"]'),
('95e9090e-6f02-48c0-8978-2d762173e2da','和顔長官百詠 山居 其一○','朱繼芳','宋','宋诗','song-poetry','','[]','擁樹溪雲迷近遠，低簷山果亂紅青。',32,'全唐诗/poet.song.216000.json','["擁樹溪雲迷近遠，低簷山果亂紅青。", "莫言身外都無事，早晚焚香看道經。"]'),
('6839ae0b-70e9-499a-88df-ddd87c25d3c4','和顔長官百詠 漁父 其一','朱繼芳','宋','宋诗','song-poetry','','[]','不踏長安十二門，鸕鷀飛處數家村。',32,'全唐诗/poet.song.216000.json','["不踏長安十二門，鸕鷀飛處數家村。", "停橈試向灘頭問，莫是嚴光末世孫。"]'),
('a6c0c0b9-fa9d-4d38-a142-bce19136d937','和顔長官百詠 漁父 其二','朱繼芳','宋','宋诗','song-poetry','','[]','一曲清漪濯晚霞，釣竿斜插白鷗沙。',32,'全唐诗/poet.song.216000.json','["一曲清漪濯晚霞，釣竿斜插白鷗沙。", "傍人借問居何處，四海五湖都是家。"]'),
('a2e9fcca-420d-42db-9f59-8887746cff72','和顔長官百詠 漁父 其三','朱繼芳','宋','宋诗','song-poetry','','[]','秋風淅淅獵菰蒲，如此江山其可孤。',32,'全唐诗/poet.song.216000.json','["秋風淅淅獵菰蒲，如此江山其可孤。", "天與玻瓈三萬頃，更添一半夕陽鋪。"]'),
('ab88653e-9b69-4bf1-964a-22588a160601','和顔長官百詠 漁父 其四','朱繼芳','宋','宋诗','song-poetry','','[]','長作絲綸短短牽，一池漢水盡南天。',32,'全唐诗/poet.song.216000.json','["長作絲綸短短牽，一池漢水盡南天。", "誰知有客量江面，不是漁郎兩板船。"]'),
('1620b15d-8e44-44b4-9518-5721987f4c11','和顔長官百詠 漁父 其五','朱繼芳','宋','宋诗','song-poetry','','[]','推起篷窗抱月眠，三三兩兩柳邊船。',32,'全唐诗/poet.song.216000.json','["推起篷窗抱月眠，三三兩兩柳邊船。", "不須聽說文王事，孤負漁竿八十年。"]'),
('5a4c75b9-d588-4219-a3ca-72fb59b22942','和顔長官百詠 漁父 其六','朱繼芳','宋','宋诗','song-poetry','','[]','傳呼扶柁晚風前，一陣驚鴻沒遠煙。',32,'全唐诗/poet.song.216000.json','["傳呼扶柁晚風前，一陣驚鴻沒遠煙。", "不是吾儂棲泊處，却回別港避官船。"]'),
('d6999d89-ebf9-4cc7-a9ca-f0146a2ede39','和顔長官百詠 漁父 其七','朱繼芳','宋','宋诗','song-poetry','','[]','五湖煙裏我知魚，屬玉舂鋤一處居。',32,'全唐诗/poet.song.216000.json','["五湖煙裏我知魚，屬玉舂鋤一處居。", "欲到垂虹風作惡，幾株官柳向人疎。"]'),
('95331ba9-6272-4d75-89bb-ec03180bb622','和顔長官百詠 漁父 其八','朱繼芳','宋','宋诗','song-poetry','','[]','秋聲只在樹中間，極浦斜陽更有山。',32,'全唐诗/poet.song.216000.json','["秋聲只在樹中間，極浦斜陽更有山。", "卷却絲綸呼酒盞，鷗邊聊得此身閑。"]'),
('0e7cd8bc-3237-40e7-a60b-6e28d8166586','和顔長官百詠 漁父 其九','朱繼芳','宋','宋诗','song-poetry','','[]','舟繫蓬萊淺水傍，鰲頭縮盡海生桑。',32,'全唐诗/poet.song.216000.json','["舟繫蓬萊淺水傍，鰲頭縮盡海生桑。", "百川日夜滔滔去，借問人間有底忙。"]'),
('0234474b-75d7-4144-8b05-6dc3b4ba3925','和顔長官百詠 漁父 其一○','朱繼芳','宋','宋诗','song-poetry','','[]','璧月滄波上下天，秋風摇落四無邊。',32,'全唐诗/poet.song.216000.json','["璧月滄波上下天，秋風摇落四無邊。", "玉龍盡喚眠鷗起，兩岸蘆花不見船。"]'),
('12a8f44b-8874-4a9e-a04b-3084428de517','庚戌壽意一先生','朱繼芳','宋','宋诗','song-poetry','','[]','江涵秋色碧潭潭，飲馬胡兒不敢南。',64,'全唐诗/poet.song.216000.json','["江涵秋色碧潭潭，飲馬胡兒不敢南。", "宥密老臣功第一，緝熙天子歲登三。", "身扶紫極星辰正，手拆黄封雨露甘。", "見說年來淮尾漲，漢庭可要百曹參。"]'),
('91fb8187-8d9d-4934-b395-3792dc393b0d','反招隠','朱繼芳','宋','宋诗','song-poetry','','[]','木末徑微微，誰敲白板扉。',48,'全唐诗/poet.song.216000.json','["木末徑微微，誰敲白板扉。", "緩行松葉滑，小摘藥苗稀。", "山色自今古，塵寰多是非。", "昂昂千歲鶴，便肯傍人飛。"]'),
('1dfb3063-5c58-467e-b2a0-ec077f509493','太極圖','朱繼芳','宋','宋诗','song-poetry','','[]','動靜無端畫一圈，分明擘破又渾全。',32,'全唐诗/poet.song.216000.json','["動靜無端畫一圈，分明擘破又渾全。", "日光漏得先天意，鑽入書窗箇箇圓。"]'),
('7d12fb7f-3710-49d2-8bf7-d6b658ee5e9f','觀化','朱繼芳','宋','宋诗','song-poetry','','[]','看見青蟲作蝶時，不知蝶是此身非。',32,'全唐诗/poet.song.216000.json','["看見青蟲作蝶時，不知蝶是此身非。", "牀頭爲有南華卷，午枕酣來忽夢飛。"]'),
('a83ce71e-7e64-4dfe-88dc-74ffe1452750','蛬','朱繼芳','宋','宋诗','song-poetry','','[]','一蛬何唧唧，吟落兒童心。',24,'全唐诗/poet.song.216000.json','["一蛬何唧唧，吟落兒童心。", "只在竹籬外，篝燈無處尋。"]'),
('caff2a87-3a6c-407b-8f52-00b3f73ba977','春晚有感','朱繼芳','宋','宋诗','song-poetry','','[]','坐對吳山酒，閑同越客吟。',48,'全唐诗/poet.song.216000.json','["坐對吳山酒，閑同越客吟。", "月明人渡淺，花暗鳥啼深。", "往事空流水，還丹未化金。", "不堪春又晚，惆悵百年心。"]'),
('e6b82933-33e4-4c40-ab24-4d52fd3d9d2c','送僧蘋洲遊醉李','朱繼芳','宋','宋诗','song-poetry','','[]','師今遊醉李，自刺釣舡篙。',48,'全唐诗/poet.song.216000.json','["師今遊醉李，自刺釣舡篙。", "地說三吳勝，人夸二陸豪。", "草黄工女績，波白課丁熬。", "近海寒應早，霜毛怯剃刀。"]'),
('1324c550-cfdf-4f26-9d85-8dfb60d08b93','有歎','朱繼芳','宋','宋诗','song-poetry','','[]','與老本無期，相尋天一涯。',48,'全唐诗/poet.song.216000.json','["與老本無期，相尋天一涯。", "履承雙足繭，帽裹半頭絲。", "路近行猶歇，鄉遥夢豈知。", "酒酣增意氣，忽憶少年時。"]'),
('93a53cdf-6463-4475-a71a-f0be0e484bea','子規','朱繼芳','宋','宋诗','song-poetry','','[]','自身歸未得，却勸別人歸。',48,'全唐诗/poet.song.216000.json','["自身歸未得，却勸別人歸。", "思婦心中事，征夫淚滿衣。", "蜀天知近遠，江樹間稠稀。", "幸自安雙翼，誰教不奮飛。"]'),
('cb2f4bd5-4348-4321-baa6-3f1bfef79e0b','老將','朱繼芳','宋','宋诗','song-poetry','','[]','不把琱刀賣，曾隨夜斫營。',48,'全唐诗/poet.song.216000.json','["不把琱刀賣，曾隨夜斫營。", "老年猶善飯，壯日想能兵。", "上馬身仍健，看鴻眼更明。", "戰多人不信，枉指箭瘢呈。"]'),
('8bea7ba6-9a2d-44ca-8be2-2688449b8c33','登眺','朱繼芳','宋','宋诗','song-poetry','','[]','破帽任風吹，天知髮已絲。',48,'全唐诗/poet.song.216000.json','["破帽任風吹，天知髮已絲。", "大江流禹蹟，老樹見秦時。", "北際山如礪，南溟水似池。", "夜凉無夢到，久矣歎吾衰。"]'),
('a847e5b3-6285-4bd9-a304-39a0f4df155a','梨山廟','朱繼芳','宋','宋诗','song-poetry','','[]','無處著詩名，梨山萬古青。',48,'全唐诗/poet.song.216000.json','["無處著詩名，梨山萬古青。", "人間留此像，天上作何星。", "祝史祠神醉，騷人謁夢醒。", "當時青紫楦，曾有許精靈。"]'),
('19f7fb93-53ce-4628-bb2f-fb6bb7b5e05b','惜花','朱繼芳','宋','宋诗','song-poetry','','[]','留春春不住，春去落花隨。',48,'全唐诗/poet.song.216000.json','["留春春不住，春去落花隨。", "枉自收殘片，何堪綴舊枝。", "輪蹄前日約，蜂蝶一年期。", "代謝由來事，誰能作許悲。"]'),
('3ae51748-a5a3-462e-b604-90ed964128be','桃源官罷芸居以唐詩拙作贈別','朱繼芳','宋','宋诗','song-poetry','','[]','自作還相送，唐詩結伴來。',48,'全唐诗/poet.song.216000.json','["自作還相送，唐詩結伴來。", "歸裝携此重，笑口爲君開。", "蓮上巢難穩，桃邊艇却回。", "空餘吟卷在，沙鳥莫驚猜。"]'),
('e7c0d4fa-3241-451b-bbb3-fa7ed5860a58','元日','朱繼芳','宋','宋诗','song-poetry','','[]','堂上序周親，相看又一春。',48,'全唐诗/poet.song.216000.json','["堂上序周親，相看又一春。", "吾年方覺老，童子儼成人。", "婪尾屠酥酒，從頭鬰壘神。", "何須千歲上，即此是新陳。"]'),
('4278074e-97e8-4069-ab77-04844507ef5e','昭慶寺','朱繼芳','宋','宋诗','song-poetry','','[]','幽尋得勝趣，城市幾人能。',48,'全唐诗/poet.song.216000.json','["幽尋得勝趣，城市幾人能。", "古柳深中磬，長廊盡處燈。", "畫龍聽說法，塑佛看齋僧。", "別寺經行遍，茲遊昔未曾。"]'),
('1a7990b2-7f9e-449c-b263-94cbd6fd1f56','苕溪','朱繼芳','宋','宋诗','song-poetry','','[]','維舟古祠下，野飯就魚羹。',48,'全唐诗/poet.song.216000.json','["維舟古祠下，野飯就魚羹。", "坐聽篙人說，行逢牽路平。", "居民難問姓，溪鴨自呼名。", "天目無由到，沿洄更幾程。"]'),
('0a9fb111-12f9-4e28-958b-8bf12c922a97','雪中僧虛舟來','朱繼芳','宋','宋诗','song-poetry','','[]','雪中聞犬吠，清卧起來遲。',48,'全唐诗/poet.song.216000.json','["雪中聞犬吠，清卧起來遲。", "開戶千山白，逢僧一箇緇。", "言從風絮裏，憶得雨花時。", "寒舍無祗待，煎茶且說詩。"]'),
('7836cdd0-20ae-4d7a-a5f8-6af4cdb7df4b','湖蕩','朱繼芳','宋','宋诗','song-poetry','','[]','雙橈入天影，野葑綠全交。',48,'全唐诗/poet.song.216000.json','["雙橈入天影，野葑綠全交。", "魚唼垂絲柳，鷗眠折葉茭。", "行人沿岸曲，落日挂林梢。", "歸去嚴城隔，僧門尚可敲。"]'),
('2ee24936-bf68-44b6-bca9-c8ff11cc4c71','六和塔','朱繼芳','宋','宋诗','song-poetry','','[]','三百有餘年，潮頭不敢顛。',48,'全唐诗/poet.song.216000.json','["三百有餘年，潮頭不敢顛。", "孤尖標白浪，層級上青天。", "鈴隔山僧唄，燈通海客舡。", "老來登眺眼，不道步難前。"]'),
('56271346-a61e-47c6-8013-147c7d1f5445','題丘芳仲月林','朱繼芳','宋','宋诗','song-poetry','','[]','阿姊種婆娑，秋風奈若何。',48,'全唐诗/poet.song.216000.json','["阿姊種婆娑，秋風奈若何。", "人間千樹少，天上一枝多。", "安得仙槎客，携將玉斧柯。", "和根都斫却，還我舊山河。"]'),
('ef7c900e-db8b-4b11-b429-a046abe89f02','贈日者','朱繼芳','宋','宋诗','song-poetry','','[]','烏兔走雙丸，誰將手控摶。',48,'全唐诗/poet.song.216000.json','["烏兔走雙丸，誰將手控摶。", "短長三萬日，好醜百千般。", "數遠談何易，天高問却難。", "送君尋富貴，我命不中看。"]'),
('8c7163d0-604c-4068-a4e1-c10600f8a1f5','旅館','朱繼芳','宋','宋诗','song-poetry','','[]','僕行方請息，旅館復相招。',48,'全唐诗/poet.song.216000.json','["僕行方請息，旅館復相招。", "小市三家聚，前村五里遥。", "茅柴侵熟飲，松葉带生燒。", "猶有斜陽在，行吟忽斷橋。"]'),
('f71b00cc-287a-4602-8a91-b72648f5b981','嚴衢道中','朱繼芳','宋','宋诗','song-poetry','','[]','草白三丫路，苔青五里牌。',48,'全唐诗/poet.song.216000.json','["草白三丫路，苔青五里牌。", "長年車馬客，幾兩利名鞋。", "斗糴隨時貴，方言到處乖。", "近山樵有主，童稚拾松釵。"]'),
('133f9ce4-9776-4686-b9ca-df14ef47a1c0','舟到梅雨暴漲','朱繼芳','宋','宋诗','song-poetry','','[]','夜月離于畢，篙師可奈何。',48,'全唐诗/poet.song.216000.json','["夜月離于畢，篙師可奈何。", "帆穿風減半，江闊雨添多。", "側岸無牽路，中流有旋渦。", "平生柂樓底，得在柳梢過。"]'),
('e19f093e-0f5e-4a70-8477-966f862ddd6c','對酒','朱繼芳','宋','宋诗','song-poetry','','[]','莫信樵人說，秦時有樹存。',48,'全唐诗/poet.song.216000.json','["莫信樵人說，秦時有樹存。", "青天浮渤澥，白日走昆侖。", "爲有愁千斛，時須酒一尊。", "提壺亦相勸，花下綠陰繁。"]'),
('ab613293-e771-40c6-a66a-9c9ac94b20f1','客路','朱繼芳','宋','宋诗','song-poetry','','[]','閨閤空相憶，那知客路艱。',48,'全唐诗/poet.song.216000.json','["閨閤空相憶，那知客路艱。", "背人前去鳥，迎面遠來山。", "夜泊孤燈悄，晨裝片月彎。", "猿聲不知處，杳杳白雲間。"]'),
('06207448-d6f4-4ec3-92c6-3db7ff7fcb60','送人之武昌','朱繼芳','宋','宋诗','song-poetry','','[]','秋風吹落葉，君作武昌遊。',48,'全唐诗/poet.song.216000.json','["秋風吹落葉，君作武昌遊。", "只道從軍樂，那知別路愁。", "寒暄楚岫色，日夜漢江流。", "大閫多珠履，無爲彈蒯緱。"]'),
('ffac0710-7f14-49b3-8ec1-049dd69df738','舊遊','朱繼芳','宋','宋诗','song-poetry','','[]','兩峰多少寺，分日去遨遊。',48,'全唐诗/poet.song.216000.json','["兩峰多少寺，分日去遨遊。", "山翠橫天目，湖光浴佛頭。", "花朝騎馬醉，月夜傍船謳。", "一被微官縛，重來不自由。"]'),
('22886c1e-af7e-42eb-bb5a-3a1d387e8558','挽芸居','朱繼芳','宋','宋诗','song-poetry','','[]','不得來書久，那知是古人。',48,'全唐诗/poet.song.216000.json','["不得來書久，那知是古人。", "近吟丞相喜，往事諫官嗔。", "身死留名在，堂空著影新。", "平生聞笛感，爲此一沾巾。"]'),
('d1e2c11e-871f-41ad-b0e0-510a54b975ed','溪寺','朱繼芳','宋','宋诗','song-poetry','','[]','背人沙鳥一行斜，喚客桐魚幾疊撾。',64,'全唐诗/poet.song.216000.json','["背人沙鳥一行斜，喚客桐魚幾疊撾。", "誤向山中參白足，不知頭上著烏紗。", "煮茶烟暖浮新竹，洗鉢泉香带落花。", "過夏功勞眠與食，誰能展卷看楞伽。"]'),
('8d8c03bc-70e1-4248-bb3e-a4ac14a80715','暮春','朱繼芳','宋','宋诗','song-poetry','','[]','姚黄魏紫惱人看，羅襪成塵俛仰間。',64,'全唐诗/poet.song.216000.json','["姚黄魏紫惱人看，羅襪成塵俛仰間。", "蜀魄聲乾花有血，湘靈淚盡竹無斑。", "年光冉冉趨雙鬢，暮雨霏霏失四山。", "老裏情懷天地窄，莫教一日酒杯閑。"]'),
('43f569e5-a8de-4c16-b3ab-07192721e5c6','少年遊','朱繼芳','宋','宋诗','song-poetry','','[]','紫陌尋芳愛馬遲，一春能得幾晴時。',64,'全唐诗/poet.song.216000.json','["紫陌尋芳愛馬遲，一春能得幾晴時。", "海棠露重衣全透，楊柳風微帽半欹。", "大白引浮銀鑿落，小紅吹徹玉參差。", "人生行樂須年少，莫等星星滿鏡絲。"]'),
('5d11dbbd-827b-465a-89be-8a7f11a21f10','江湖偉觀','朱繼芳','宋','宋诗','song-poetry','','[]','吳山表裏水爲池，百有餘年壯帝畿。',64,'全唐诗/poet.song.216000.json','["吳山表裏水爲池，百有餘年壯帝畿。", "天目舊將雙鳳下，海門新拱六龍飛。", "胥濤白雪生秋思，太乙紅雲駐夕暉。", "江上沙鷗湖上舫，柳絲風裏兩依依。"]'),
('87df7d31-ccab-4e0e-b2a4-baec5eaa6e21','用前韻謝野水郎君招飲','朱繼芳','宋','宋诗','song-poetry','','[]','爲有臺池無限嬌，遊人歌舞尚朝朝。',64,'全唐诗/poet.song.216000.json','["爲有臺池無限嬌，遊人歌舞尚朝朝。", "清漪浴日開金面，晴哢調風衮綠腰。", "騷客五花唐殿馬，主家七葉漢庭貂。", "丁寧紅紫休開遍，約住春風待見邀。"]'),
('f60c217a-8fe9-4e81-9d4b-95615720f7c0','次韻橋亭禊事','朱繼芳','宋','宋诗','song-poetry','','[]','圯上還成集禊亭，杉松自古草仍新。',64,'全唐诗/poet.song.216000.json','["圯上還成集禊亭，杉松自古草仍新。", "彩虹卧飲流杯水，白鷺飛迎入座賓。", "俛仰已成今昔事，東西更看往來人。", "聚蚊金谷皆安在，若見吾徒合主臣。"]'),
('59a53e0c-3f25-48fb-ae3d-3ebfed11a2dc','次庸齋先生韻贈黄隆中','朱繼芳','宋','宋诗','song-poetry','','[]','醒眼隆中閲逝川，茅茨爲屋竹爲椽。',64,'全唐诗/poet.song.216000.json','["醒眼隆中閲逝川，茅茨爲屋竹爲椽。", "吟成梁父時當隠，炊熟邯鄲客正眠。", "漢土一抔無處覓，白墳三尺有人憐。", "君歸欲作千年計，只合躬耕一寸田。"]'),
('d10bd1ce-6629-47f3-a11f-215a401eff8d','聽白雲寺清師琴','朱繼芳','宋','宋诗','song-poetry','','[]','古寺沉沉晝日長，泠然清響發僧房。',64,'全唐诗/poet.song.216000.json','["古寺沉沉晝日長，泠然清響發僧房。", "昭君別去顔如玉，蘇武歸來鬢已霜。", "山水無端言爾志，炭冰何事置吾腸。", "老來却愛虛簷外，雨滴梧桐一味凉。"]'),
('bdfc4944-1ccc-4bbc-87b7-7137c41e3505','送李敬則之昇揚','朱繼芳','宋','宋诗','song-poetry','','[]','江北江南一葉舟，憑將往事問東流。',64,'全唐诗/poet.song.216000.json','["江北江南一葉舟，憑將往事問東流。", "錦帆月冷瓊花夜，綺閣風高玉樹秋。", "杜牧三生開笑口，劉郎五絕掉吟頭。", "淮山眼見詩人慣，高築詩壇汗漫遊。"]'),
('e34a6d4c-2876-4085-bb97-60d7d5745274','次韻池上暮雨','朱繼芳','宋','宋诗','song-poetry','','[]','濕遍欄干欲倚休，手中團扇漸知秋。',64,'全唐诗/poet.song.216000.json','["濕遍欄干欲倚休，手中團扇漸知秋。", "細聲合作簷間溜，大點漂成水面漚。", "小小竹窗醒倦鶴，疎疎荷屋冷棲鷗。", "漁翁簑笠隨身在，立到黄昏釣未收。"]'),
('9eae7445-46ce-4e13-986b-4fc901fd4d28','書窗夏日','朱繼芳','宋','宋诗','song-poetry','','[]','南風伊軋語窗扉，團扇無功白日遲。',64,'全唐诗/poet.song.216000.json','["南風伊軋語窗扉，團扇無功白日遲。", "長恨老來方學易，自從春去不吟詩。", "蟲絲有力縈琴索，蛀粉無聲點墨池。", "偶出門前行數步，石榴花過已多時。"]'),
('15257b5c-e19e-416a-96ee-7bf7970c8c77','贈西蜀馮道士','朱繼芳','宋','宋诗','song-poetry','','[]','峨眉山月照清溪，中有方瞳一羽衣。',64,'全唐诗/poet.song.216000.json','["峨眉山月照清溪，中有方瞳一羽衣。", "拄杖經行天下半，丹砂乞與世人希。", "千年城郭空歸鶴，萬里山河自落暉。", "安得與君遊汗漫，乘槎一問女星機。"]'),
('9b756e56-1317-4c67-bf8b-5d3e541d239c','次韻李黄州江淮偉觀','朱繼芳','宋','宋诗','song-poetry','','[]','檻前卷箔見晴峯，夏口武昌西復東。',64,'全唐诗/poet.song.216000.json','["檻前卷箔見晴峯，夏口武昌西復東。", "三國六朝襟带地，孤城四水鼓鼙中。", "女牆夜送淮山月，老樹秋生夢澤風。", "君作此堂心萬里，應憐世上少英雄。"]'),
('b0d7f971-935c-4ded-9ac2-29a36156bd94','示醫卜逢松崖','朱繼芳','宋','宋诗','song-poetry','','[]','我生八月十五夜，清淺斜河浸月華。',64,'全唐诗/poet.song.216000.json','["我生八月十五夜，清淺斜河浸月華。", "顧兔擣殘千歲藥，牽牛引動半天槎。", "自拋蓬海傳方處，曾過成都賣卜家。", "今日相逢圓昨夢，一杯松下醉流霞。"]'),
('10dbdb57-915a-484c-a30f-7132cf3079b9','陳令君增誠齋三三徑爲十二徑次韻','朱繼芳','宋','宋诗','song-poetry','','[]','四家三徑各風流，今古悠悠貉一丘。',64,'全唐诗/poet.song.216000.json','["四家三徑各風流，今古悠悠貉一丘。", "拍甕新篘浮臘膩，繞堤老柳弄春柔。", "日邊黄紙催人去，霞外青山聽鶴留。", "若問西疇簑笠事，合還陶令一孤舟。"]'),
('b1beba1d-521a-4b3f-833a-36cd92429f61','次韻野水花朝之集','朱繼芳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','睡起名園百舌嬌，一年春事說今朝。',64,'全唐诗/poet.song.216000.json','["睡起名園百舌嬌，一年春事說今朝。", "鞦韆庭院紅三徑，舴艋池塘綠半腰。", "苔色染青吟屐蠟，花風吹暖弊裘貂。", "主人自欠西湖債，管領風光是客邀。"]'),
('f19510f5-9d09-4cca-a68b-4678dd3544e9','和秋房題半湖樓二首  其一','朱繼芳','宋','宋诗','song-poetry','','[]','天目飛來第幾峯，峯前著屋貯虛空。',64,'全唐诗/poet.song.216000.json','["天目飛來第幾峯，峯前著屋貯虛空。", "濕雲低亞鈎欄角，缺月斜窺戶牖中。", "一水東西添柳岸，兩山南北欠樵風。", "住家欲作千年計，頃刻陰晴便不同。"]'),
('1bc357c9-f22b-4455-a5e9-71e2f7abd073','和秋房題半湖樓二首  其二','朱繼芳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','四明仙客此樓居，畢竟西湖壓鑑湖。',64,'全唐诗/poet.song.216000.json','["四明仙客此樓居，畢竟西湖壓鑑湖。", "曾謂家童欺賀老，不如沙鶴認林逋。", "蒲根釣水知深淺，柳外行人乍有無。", "此景天公厭多取，只分一半與吾徒。"]'),
('1d41c8c1-0116-4325-9bfb-4afa0dc4f3f1','栽松道者像','朱繼芳','宋','宋诗','song-poetry','','[]','手便筇杖冷，脚厭芒鞋緊。',24,'全唐诗/poet.song.216000.json','["手便筇杖冷，脚厭芒鞋緊。", "兩袖吹松風，東岡復西嶺。"]'),
('1fdb16e0-e646-42f0-a6e0-1cb7fb2645c4','吳歌','朱繼芳','宋','宋诗','song-poetry','','[]','鴈影江潭底，秋聲浦溆間。',24,'全唐诗/poet.song.216000.json','["鴈影江潭底，秋聲浦溆間。", "吳兒歌一曲，月子幾回彎。"]'),
('ad3616a9-7caf-444e-ba40-bbd2dc5c2ff8','草蟲便面','朱繼芳','宋','宋诗','song-poetry','','[]','蝶舞蜂歌倦，蜻蜓看未休。',24,'全唐诗/poet.song.216000.json','["蝶舞蜂歌倦，蜻蜓看未休。", "誰知織婦意，方夏已思秋。"]'),
('15a16be4-f1f7-4c7e-8a00-82baed3b588d','意行橋','朱繼芳','宋','宋诗','song-poetry','','[]','我行且奚適，興盡忽自返。',24,'全唐诗/poet.song.216000.json','["我行且奚適，興盡忽自返。", "倒影射清漪，回光在橋板。"]'),
('e86cf060-2e33-4651-a459-d9288b92c836','塵外','朱繼芳','宋','宋诗','song-poetry','','[]','塵飛不到處，山色入芒屨。',24,'全唐诗/poet.song.216000.json','["塵飛不到處，山色入芒屨。", "乘興一長吟，回頭已忘句。"]'),
('836e13ca-24bf-4256-9a97-153a58fabff0','鴻','朱繼芳','宋','宋诗','song-poetry','','[]','鴻飛九天上，人在平地望。',24,'全唐诗/poet.song.216000.json','["鴻飛九天上，人在平地望。", "塵土與青雲，其間能幾丈。"]'),
('86261739-472a-49d4-b7dd-6e197f4e97ef','聽雪','朱繼芳','宋','宋诗','song-poetry','','[]','瓦溝初瑟瑟，隠几坐虛白。',24,'全唐诗/poet.song.216000.json','["瓦溝初瑟瑟，隠几坐虛白。", "良久却無聲，門前深幾尺。"]'),
('8ec8f61f-6cf8-43fc-85e6-8a06df3c812a','東菑','朱繼芳','宋','宋诗','song-poetry','','[]','東菑足時雨，離離半青黄。',24,'全唐诗/poet.song.216000.json','["東菑足時雨，離離半青黄。", "田家不待穫，小摘炊新香。"]'),
('8c806967-c4fe-4242-be8f-be144b9cc43b','畫舫','朱繼芳','宋','宋诗','song-poetry','','[]','畫舫茭中出，青山樹上斜。',24,'全唐诗/poet.song.216000.json','["畫舫茭中出，青山樹上斜。", "浪醒孤客酒，塵蓋萬人家。"]'),
('9a1a2b38-cbcd-4659-af4f-cb60e7de70be','溪村  其一','朱繼芳','宋','宋诗','song-poetry','','[]','櫸柳正當官道，漁舟偏繫柴門。',28,'全唐诗/poet.song.216000.json','["櫸柳正當官道，漁舟偏繫柴門。", "今年春水深淺，看取層層岸痕。"]'),
('3ab36fe2-004e-4c96-9728-9098e2af2755','溪村  其二','朱繼芳','宋','宋诗','song-poetry','','[]','雨洗山光綠浄，波涵天影清空。',28,'全唐诗/poet.song.216000.json','["雨洗山光綠浄，波涵天影清空。", "草際自浮鵝鴨，柳陰分坐兒童。"]'),
('656c5e20-03d8-497f-9c00-7fc588ca8cdf','漁翁','朱繼芳','宋','宋诗','song-poetry','','[]','漁翁家在何許，慣宿蘆花不歸。',28,'全唐诗/poet.song.216000.json','["漁翁家在何許，慣宿蘆花不歸。", "昨夜江村欲雪，百錢買得蓑衣。"]'),
('b154ddea-3168-4089-bc90-d871439652a2','揚州','朱繼芳','宋','宋诗','song-poetry','','[]','金陵王氣水東流，流到東淮古岸頭。',32,'全唐诗/poet.song.216000.json','["金陵王氣水東流，流到東淮古岸頭。", "夜半一聲天上曲，錦帆天子下揚州。"]'),
('a0e6b6e1-4eac-4074-b29e-bba5a52fb374','七夕','朱繼芳','宋','宋诗','song-poetry','','[]','兒女穿針夜向分，樓頭月落尚鑪薰。',32,'全唐诗/poet.song.216000.json','["兒女穿針夜向分，樓頭月落尚鑪薰。", "憑誰爲覓機邊石，留取支牀卧白雲。"]'),
('8c9e4d74-884a-46aa-8a04-62ca13857daf','野望','朱繼芳','宋','宋诗','song-poetry','','[]','帝青八萬四千里，更著脩眉一兩尖。',32,'全唐诗/poet.song.216000.json','["帝青八萬四千里，更著脩眉一兩尖。", "古往今來愁得盡，不教我輩送愁添。"]'),
('3bc6c440-1ee7-4334-a937-eb4fcd657b37','題李秋堂盟鷗集','朱繼芳','宋','宋诗','song-poetry','','[]','相逢已恨十年遲，買酒吳山一夜詩。',32,'全唐诗/poet.song.216000.json','["相逢已恨十年遲，買酒吳山一夜詩。", "明日送春仍送客，柳花風颺鬢絲絲。"]'),
('18fccf28-9679-4c34-a2ec-1050f5c8f0a2','航海','朱繼芳','宋','宋诗','song-poetry','','[]','地角與天倪，茫茫何處期。',48,'全唐诗/poet.song.216000.json','["地角與天倪，茫茫何處期。", "星回析木次，日挂扶桑枝。", "沉石尋孤嶼，浮針辨四維。", "飄然一桴意，持此欲安之。"]'),
('b45c6b8d-e596-4e77-a8ec-1f1cca9146ed','橋西','朱繼芳','宋','宋诗','song-poetry','','[]','雲澹風微日未低，瘦藤扶到小橋西。',32,'全唐诗/poet.song.216000.json','["雲澹風微日未低，瘦藤扶到小橋西。", "林花過雨相爭發，谷鳥無人自在啼。"]'),
('1e67550c-c144-4017-b8f6-14f0385a7b66','淮客','朱繼芳','宋','宋诗','song-poetry','','[]','長淮萬里秋風客，獨上高樓望秋色。',32,'全唐诗/poet.song.216000.json','["長淮萬里秋風客，獨上高樓望秋色。", "說與南人未必聽，神州只在闌干北。"]'),
('40abf6f6-ccae-47c4-aead-d989035779f7','調宜州冷官不赴','朱繼芳','宋','宋诗','song-poetry','','[]','瘴海南邊路淺深，客愁不待嶺猿吟。',32,'全唐诗/poet.song.216000.json','["瘴海南邊路淺深，客愁不待嶺猿吟。", "無人喚得涪翁起，分我桄榔橄欖陰。"]'),
('8774bbf4-bac0-4f0e-93d4-952743510b0d','辛亥二月望祭齋宮因游甘園  其一','朱繼芳','宋','宋诗','song-poetry','','[]','山入湖光碧四圍，棋枰零落葑田稀。',32,'全唐诗/poet.song.216000.json','["山入湖光碧四圍，棋枰零落葑田稀。", "蒲芽短短鴛鴦冷，惟有漁師幾網歸。"]'),
('4cc054b1-ef4c-4f43-aabc-060baa81cfdb','辛亥二月望祭齋宮因游甘園  其二','朱繼芳','宋','宋诗','song-poetry','','[]','朝霏作雨連天濕，春氣熏人到骨香。',32,'全唐诗/poet.song.216000.json','["朝霏作雨連天濕，春氣熏人到骨香。", "四望水亭無正面，有花多處背湖光。"]'),
('0299ca27-5648-4849-8a22-4dacde206823','辛亥二月望祭齋宮因游甘園  其三','朱繼芳','宋','宋诗','song-poetry','','[]','海棠陰下小徘徊，屐齒深深一徑苔。',32,'全唐诗/poet.song.216000.json','["海棠陰下小徘徊，屐齒深深一徑苔。", "忽聽銅鉦花外近，園丁說是主人來。"]'),
('4c34de08-cdaa-4ded-b472-fd2a307108ef','辛亥二月望祭齋宮因游甘園  其四','朱繼芳','宋','宋诗','song-poetry','','[]','老眼看花興未厭，不知頭上雨廉纖。',32,'全唐诗/poet.song.216000.json','["老眼看花興未厭，不知頭上雨廉纖。", "流鶑浪語春風恨，誰拗花枝插帽簷。"]'),
('b3ab814c-5105-45cc-8e36-a869dfb926f3','辛亥二月望祭齋宮因游甘園  其五','朱繼芳','宋','宋诗','song-poetry','','[]','公事相妨一半春，今朝纔得自由身。',32,'全唐诗/poet.song.216000.json','["公事相妨一半春，今朝纔得自由身。", "眼中領畧能多少，細雨斜風便妬人。"]'),
('c6fffbdc-d6d8-4794-b8b8-805d84108e5f','晚眺','朱繼芳','宋','宋诗','song-poetry','','[]','鳥飛欲盡暮烟橫，一笛西風萬里晴。',32,'全唐诗/poet.song.216000.json','["鳥飛欲盡暮烟橫，一笛西風萬里晴。", "山外有山青不見，微雲映出却分明。"]'),
('34cc6a48-af69-47ba-89cc-7b03ff1d682d','次意一先生仙霞壁間韻','朱繼芳','宋','宋诗','song-poetry','','[]','回首仙源隔彩霞，叢祠攫肉有饑鴉。',32,'全唐诗/poet.song.216000.json','["回首仙源隔彩霞，叢祠攫肉有饑鴉。", "貞元朝士重來晚，不見桃花見菜花。"]'),
('74da27f7-9f50-413e-b718-d830390e626f','宜春臺','朱繼芳','宋','宋诗','song-poetry','','[]','定王米換長安土，北望長安日幾迴。',32,'全唐诗/poet.song.216000.json','["定王米換長安土，北望長安日幾迴。", "更有築臺歸未得，憑高却望定王臺。"]'),
('ffa8771f-2197-4289-a52d-5865733e2740','行路難贈蕭坦翁','朱繼芳','宋','宋诗','song-poetry','','[]','行路難，居不易，旋買生柴煮一字。',192,'全唐诗/poet.song.216000.json','["行路難，居不易，旋買生柴煮一字。", "三千風月不直一杯水，何用狂吟動天地。", "君不見陸天隨，忍窮讀書白眼屠沽兒。", "又不見孟東野，載少於車車是借。", "丈夫吐氣摩星斗，六印黄金真唾手。", "莫吟詩，詩能窮人君不知。", "古人坐詩窮到骨，今人方笑古人癡。", "又聞夜半舟移壑，却嘆東門黄犬華亭鶴。", "人生短長無百年，富貴未必如賤貧。", "富貴賤貧何足據，出門總是亡羊路。", "居不易，行又難，况是長安十二門。", "相逢一笑豈易得，莫惜床頭沽酒錢。"]'),
('45d714d7-c65c-4020-9469-e9fef5477d06','送李秋堂赴京口酒人','朱繼芳','宋','宋诗','song-poetry','','[]','客懷正頼春相與，苦欲留春天不許。',160,'全唐诗/poet.song.216000.json','["客懷正頼春相與，苦欲留春天不許。", "送君一舸下南徐，落花起舞流鶑語。", "鮫人浴出扶桑繭，天女染作紅雲段。", "君從何處得錦機，借與人間爲樣看。", "青杏園深暖漏長，柳綿如雪撲酒缸。", "吳姬道字未端正，當壚學唱新番腔。", "貔貅百萬張頤仰，都將鐵甕盛春釀。", "有客高談四座傾，主人合序諸侯上。", "日邊此別各南北，君頤始髭我衰白。", "何以贈之折柳條，千絲萬絲心摇摇。"]'),
('ccb75993-683b-4387-b5a5-7c7247695d00','讀黄玉溪湯婆傳','朱繼芳','宋','宋诗','song-poetry','','[]','君不見湯家阿泉驪山陰，出入宮掖承恩深。',198,'全唐诗/poet.song.216000.json','["君不見湯家阿泉驪山陰，出入宮掖承恩深。", "只流妃子脂粉氣，不暖少陵如鐵衾。", "又不見湯家阿池紫塞上，沉香霧擁將軍帳。", "天寒十指墮弓刀，底用空言如挾纊。", "何如韓時老湯婆，冬則飲湯惟腹皤。", "形模混沌婦女笑，閉塞其兌藏天和。", "老生門前十日雪，兩脚凍皴眠不得。", "斷無蠻素構心兵，頼有婆兮相暖熱。", "夫人竹氏青玲瓏，炎炎幾時奈秋風。", "婆耻居下常熱中，毋棄憔悴以御冬。", "得黄太史五字詩，厥孫傳之尤滑稽。", "霜風蕭蕭歲年晚，吾喜湯婆有完傳。"]'),
('e5628785-11b0-4b39-b998-67173750310a','挽周伯弜','朱繼芳','宋','宋诗','song-poetry','','[]','今日忽不樂，散行湖水濱。',48,'全唐诗/poet.song.216000.json','["今日忽不樂，散行湖水濱。", "有懷天下士，遽作夢中人。", "醉語驚天地，狂歌哭鬼神。", "九原如可贖，那不百其身。"]'),
('7719b708-f03d-4ce1-86c7-fbc02a51e014','贈續芸','朱繼芳','宋','宋诗','song-poetry','','[]','誰謂芸居死，餘香解返魂。',48,'全唐诗/poet.song.216000.json','["誰謂芸居死，餘香解返魂。", "六丁將不去，孤子續猶存。", "科斗三生債，蟫魚再世冤。", "向來詩作祟，揮涕對人言。"]'),
('d6344568-4fac-4b76-9050-8a014dc9c6a0','滄浪風月','朱繼芳','宋','宋诗','song-poetry','','[]','我登滄浪亭，復歌滄浪曲。',48,'全唐诗/poet.song.216000.json','["我登滄浪亭，復歌滄浪曲。", "歌竟復長歌，杳杳山水綠。", "天風吹散髮，山月照濯足。", "爲謝獨醒人，漁家酒初熟。"]'),
('ca4bd561-945b-4755-88f3-aec022835c51','有懷鷲山次僧芳庭韻','朱繼芳','宋','宋诗','song-poetry','','[]','一塔與雲齊，尋僧路不迷。',48,'全唐诗/poet.song.216000.json','["一塔與雲齊，尋僧路不迷。", "小舟沙鳥外，疎磬夕陽西。", "古樹含雲亞，春橋覆水低。", "鷲峰飛不去，夜夜子規啼。"]'),
('d19f7f90-b2be-4b3f-95cc-9323bacd9161','柳','朱繼芳','宋','宋诗','song-poetry','','[]','臨水送將歸，春風折贈時。',24,'全唐诗/poet.song.216000.json','["臨水送將歸，春風折贈時。", "而今三丈樹，元是手中枝。"]'),
('0a19cebe-cd0f-4d99-91eb-7c20dd3e8582','鷗','朱繼芳','宋','宋诗','song-poetry','','[]','採魚秋江上，鷗鳥來相隨。',24,'全唐诗/poet.song.216000.json','["採魚秋江上，鷗鳥來相隨。", "蕩槳忽驚起，雲天碧四垂。"]'),
('6582c33e-ec91-408a-bde0-d7107b3b67dd','天竺分韻得芳字','朱繼芳','宋','宋诗','song-poetry','','[]','縹渺白雲鄉，天風吹曉凉。',48,'全唐诗/poet.song.216000.json','["縹渺白雲鄉，天風吹曉凉。", "人尋水源至，路入樹陰長。", "晝靜聞晴哢，春餘拾澗芳。", "余心忽有得，欲語又還忘。"]'),
('f30a5c6f-0079-4e6d-be01-2b1f60aaf6b5','失題','朱繼芳','宋','宋诗','song-poetry','','[]','千年白蝙蝠，來往撲人衣。',48,'全唐诗/poet.song.216000.json','["千年白蝙蝠，來往撲人衣。", "洞黑鬼相語，天寒僧未歸。", "巖溫生石乳，煙起作林霏。", "城裏遥看處，唯應一翠微。"]'),
('94c71ce7-d442-4789-a4e1-2d162e98983d','松澤西亭','朱繼芳','宋','宋诗','song-poetry','','[]','高人太多事，寒夜本無魚。',48,'全唐诗/poet.song.216000.json','["高人太多事，寒夜本無魚。", "船子今何許，涇流只似初。", "白蘋秋浩蕩，黄葉晚蕭疎。", "更有斯亭在，乾坤一草廬。"]'),
('0f9ef6cd-17b6-4d13-a149-cfcdf9a30778','桐江舟夜','朱繼芳','宋','宋诗','song-poetry','','[]','蕩槳入虛碧，星河俱動摇。',48,'全唐诗/poet.song.216000.json','["蕩槳入虛碧，星河俱動摇。", "前村漁火近，別浦雁聲遥。", "對景知明月，回頭得暗潮。", "桐廬在何許，江路夜迢迢。"]'),
('c24ca372-7a49-4220-b8d4-38ead39cbcba','十暑','朱繼芳','宋','宋诗','song-poetry','','[]','十暑江湖客，塵緇白苧衫。',48,'全唐诗/poet.song.216000.json','["十暑江湖客，塵緇白苧衫。", "人沿沙島路，風捲海門帆。", "带雨厨煙重，通潮井脈鹹。", "家書言不盡，重拆又重緘。"]'),
('0eb4ff58-daad-4e03-a39e-7849c4ca9b35','西湖別業','朱繼芳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寥寥湖上趣，大似水雲僧。',48,'全唐诗/poet.song.216000.json','["寥寥湖上趣，大似水雲僧。", "故國經年夢，寒窗獨夜燈。", "鞭聲爭輦道，月色淡觚稜。", "一覺平明睡，都人却未能。"]'),
('352b8995-ec04-4baa-bda2-7a2bb2128c34','春遊','朱繼芳','宋','宋诗','song-poetry','','[]','雨過青青草，湖邊信馬蹄。',48,'全唐诗/poet.song.216000.json','["雨過青青草，湖邊信馬蹄。", "夕陽沙路遠，春水板橋低。", "柳暗漁人屋，花香燕子泥。", "摩挲酒家壁，留著醉時題。"]'),
('ac599734-0c5e-48bc-aea4-1a141d27113e','秋風','朱繼芳','宋','宋诗','song-poetry','','[]','秋風欺病客，力氣復何如。',48,'全唐诗/poet.song.216000.json','["秋風欺病客，力氣復何如。", "髮短絲無數，衣寬带有餘。", "見人慵作禮，聞鴈强裁書。", "門外生秋草，呼童不要除。"]'),
('2ceacab8-9197-4ae9-b1c6-26637c33862d','再拜閬風帥幹寶謨郎中','朱繼芳','宋','宋诗','song-poetry','','[]','家世蜀青城，摶扶幾萬程。',48,'全唐诗/poet.song.216000.json','["家世蜀青城，摶扶幾萬程。", "神遊應八表，骨鍊已三生。", "舉酒呼麟脯，吹笙答鳳鳴。", "欲將余馬紲，蜷局不堪行。"]'),
('04030724-d545-4e3b-a843-debb60948a52','刺桐','朱繼芳','宋','宋诗','song-poetry','','[]','刺桐依客舍，晴綠上窗紗。',48,'全唐诗/poet.song.216000.json','["刺桐依客舍，晴綠上窗紗。", "昨夜還飛葉，來時未作花。", "鴉寒驚月色，人老惜年華。", "今度逢摇落，歸心一倍加。"]'),
('ce8f985f-20f5-4a4e-aeab-e1147984733f','清明','朱繼芳','宋','宋诗','song-poetry','','[]','餳面留寒不肯濃，一年春事看成空。',64,'全唐诗/poet.song.216000.json','["餳面留寒不肯濃，一年春事看成空。", "人歌人哭清明日，花落花開昨夜風。", "薄薄絮泥行燕子，深深茭蕩出鳬翁。", "西泠橋上多車馬，有底狂馳百歲中。"]'),
('c121bcd5-20ad-47b0-81d1-6b34353a2700','新秋雜興','朱繼芳','宋','宋诗','song-poetry','','[]','晚煙起處是孤村，漠漠郊原白道分。',64,'全唐诗/poet.song.216000.json','["晚煙起處是孤村，漠漠郊原白道分。", "菰葉池塘疎雨過，豆花籬落夕陽曛。", "遠山空闊圍天在，鄰杵丁東带鴈聞。", "獨自尋詩風滿袖，不知身入白鷗羣。"]'),
('c9de9ee3-4bd4-4594-94b0-52daef493c4c','和政和顔令君韻','朱繼芳','宋','宋诗','song-poetry','','[]','恰百年餘得縣名，從前官長是誰清。',64,'全唐诗/poet.song.216000.json','["恰百年餘得縣名，從前官長是誰清。", "魚鮭市小通蠻遠，鷄犬村深見吏生。", "過客莫嗔厨傳冷，家人方喜俸錢輕。", "却愁明日朝天去，不得黄紬飽五更。"]'),
('1dee0e81-a06f-4368-b207-7e661fcc1e6f','壽尚書意一先生','朱繼芳','宋','宋诗','song-poetry','','[]','天上麒麟地上行，當年孔釋送徐卿。',64,'全唐诗/poet.song.216000.json','["天上麒麟地上行，當年孔釋送徐卿。", "重來司馬兒童喜，初見歐陽老婢驚。", "黄道日開經幄霽，紫垣星近履絇明。", "本朝寶筴千千歲，惟讀書人共太平。"]'),
('057a1dfe-1a82-4705-980d-6885ee795eef','閑觀','朱繼芳','宋','宋诗','song-poetry','','[]','閑觀造化餘，靜極悅自性。',24,'全唐诗/poet.song.216000.json','["閑觀造化餘，靜極悅自性。", "胡蝶忽飛來，吾心已無競。"]'),
('c3a5867b-266a-4362-bb87-24f3f2130149','幽尋','朱繼芳','宋','宋诗','song-poetry','','[]','幽尋興不淺，歸路故遲遲。',24,'全唐诗/poet.song.216000.json','["幽尋興不淺，歸路故遲遲。", "猿斷空山答，人行片月隨。"]'),
('479713f1-cf6f-47ba-999b-99e28f557a53','冷泉亭','朱繼芳','宋','宋诗','song-poetry','','[]','白猿弄清泚，秋入山骨冷。',24,'全唐诗/poet.song.216000.json','["白猿弄清泚，秋入山骨冷。", "老僧怯憑欄，忽失袈裟影。"]'),
('02fb11c6-5755-4926-b0cb-4b17a6515d28','溪橋','朱繼芳','宋','宋诗','song-poetry','','[]','雲歸洞府癡龍睡，日澹山椒倦翼還。',32,'全唐诗/poet.song.216000.json','["雲歸洞府癡龍睡，日澹山椒倦翼還。", "橋上行人橋下水，如今日夜不曾閑。"]'),
('cda0c6a3-5280-4367-a441-620a9d700e5d','見野祭者','朱繼芳','宋','宋诗','song-poetry','','[]','餳粥初香未賜煙，百金難買過湖船。',32,'全唐诗/poet.song.216000.json','["餳粥初香未賜煙，百金難買過湖船。", "南屏山下何年骨，猶向人間覓紙錢。"]'),
('491ffe24-c406-472d-ac64-f968a3801bb5','疎山矮師叔道場','朱繼芳','宋','宋诗','song-poetry','','[]','白雲深處水茫茫，四百年餘古道場。',32,'全唐诗/poet.song.216000.json','["白雲深處水茫茫，四百年餘古道場。", "我來不見矮師叔，手種樹身今許長。"]'),
('7a6d35ee-719d-46bf-a2bd-6a41a82961c7','行都春事詩','朱繼芳','宋','宋诗','song-poetry','','[]','紫陌無泥雨後天，綠陰多處正鞦韆。',32,'全唐诗/poet.song.216000.json','["紫陌無泥雨後天，綠陰多處正鞦韆。", "土風未必知農事，也聽村夫說種田。"]'),
('59656cb0-257a-4a8a-ab93-5bd2a15b3d3f','張子中牡丹圖','朱繼芳','宋','宋诗','song-poetry','','[]','寫來猶是挾春嬌，想見當年魏與姚。',32,'全唐诗/poet.song.216000.json','["寫來猶是挾春嬌，想見當年魏與姚。", "花外小車看未了，杜鵑聲裏洛陽橋。"]'),
('28654366-c496-4cdc-ad2b-d949bb38b50b','次韻胡仲方因楊伯子見寄  其一','朱繼芳','宋','宋诗','song-poetry','','[]','此去廬陵定幾程，向來筇杖未經行。',32,'全唐诗/poet.song.216000.json','["此去廬陵定幾程，向來筇杖未經行。", "懸知征棹雲邊集，大有吟情雪裏生。"]'),
('ab2c9950-9c51-4606-ba72-0e0fdda27b32','次韻胡仲方因楊伯子見寄  其二','朱繼芳','宋','宋诗','song-poetry','','[]','楚渡食萍應甚美，舜祠吹玉直能清。',32,'全唐诗/poet.song.216000.json','["楚渡食萍應甚美，舜祠吹玉直能清。", "二君即日青冥上，唯我青山带雨耕。"]'),
('618e9846-3d03-4e7b-823b-551dcc251ab1','題飛來峰','朱繼芳','宋','宋诗','song-poetry','','[]','元是西天住，飛來莫去休。',48,'全唐诗/poet.song.216000.json','["元是西天住，飛來莫去休。", "未憑仙佛國，好似帝王州。", "彼樹亦如寄，吾生應更浮。", "白猿呼不應，松露滴獼猴。"]'),
('d935064d-4669-4fc9-915d-5890ddddc272','錢塘江','朱繼芳','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','極浦無高樹，蒼茫只遠空。',48,'全唐诗/poet.song.216000.json','["極浦無高樹，蒼茫只遠空。", "潮來江水黑，日出海門紅。", "兩岸東西浙，千帆來去風。", "中原山色外，殘夢逐歸鴻。"]'),
('1b64a42f-2665-4beb-bc10-bdb4696ecdb0','宋五嫂魚羹','朱繼芳','宋','宋诗','song-poetry','','[]','柳下白頭釣叟，不知生長何年。',28,'全唐诗/poet.song.216000.json','["柳下白頭釣叟，不知生長何年。", "前度君王遊幸，賣魚收得金錢。"]'),
('0583683c-0233-48e8-9c29-844f88d571bb','靈芝寺','朱繼芳','宋','宋诗','song-poetry','','[]','黄金匝地小橋通，四面清平納遠空。',64,'全唐诗/poet.song.216000.json','["黄金匝地小橋通，四面清平納遠空。", "雲氣長扶天子座，日光浮動梵王宮。", "殘碑幾字莓苔雨，清磬一聲楊柳風。", "沙鳥不知行樂事，背人飛過夕陽東。"]'),
('ea922274-877c-441a-b269-0c3d84087710','宿靈巖','張至龍','宋','宋诗','song-poetry','','[]','樹杪鍾樓出半層，佛牀黠鼠弄殘燈。',32,'全唐诗/poet.song.216000.json','["樹杪鍾樓出半層，佛牀黠鼠弄殘燈。", "五更石上僧猶定，頭滿清霜喚不譍。"]'),
('94b74c1c-4d7d-4916-8cd7-7dec9698c288','登東山懷朱靜佳','張至龍','宋','宋诗','song-poetry','','[]','布石行山磵，雲封竹洞名。',48,'全唐诗/poet.song.216000.json','["布石行山磵，雲封竹洞名。", "照池傳古貌，借箸數同庚。", "禽鬭巢幾覆，蛛閑網半成。", "冬深猶見菊，還憶晉淵明。"]'),
('00962014-949f-4c73-b3ab-c31a07335195','塞上曲','張至龍','宋','宋诗','song-poetry','','[]','匣裏干將午夜鳴，碧油幢下夢魂驚。',32,'全唐诗/poet.song.216000.json','["匣裏干將午夜鳴，碧油幢下夢魂驚。", "沙場燐火風吹起，半在骷髏眼底明。"]'),
('b0dbd72c-7175-4f85-92be-5ee2c4101c59','紫微閣贈凌丹士','張至龍','宋','宋诗','song-poetry','','[]','風林葉葉带新寒，匕箸虀鹽客味酸。',64,'全唐诗/poet.song.216000.json','["風林葉葉带新寒，匕箸虀鹽客味酸。", "兔抱粟眠傳道石，鹿銜花上拜章壇。", "沿崖取水和冰嚼，掃壁題詩當畫看。", "盡日玄房無俗話，山鍾敲月上闌干。"]'),
('514a5ac7-9122-4308-927c-a22ff0214611','送鏡山僧游雪峰','張至龍','宋','宋诗','song-poetry','','[]','海風迎鐵錫，半是水爲程。',48,'全唐诗/poet.song.216000.json','["海風迎鐵錫，半是水爲程。", "故國往來熟，空門宿食清。", "舊房雲借住，早路月同行。", "象骨最高處，師今履似平。"]'),
('d524cba3-7387-4bda-a374-4a3dc1a0e1e7','齊雲寺','張至龍','宋','宋诗','song-poetry','','[]','雨疎分點下，略彴界橫塘。',48,'全唐诗/poet.song.216000.json','["雨疎分點下，略彴界橫塘。", "接竹通生水，搴蘿補壞牆。", "字塗窗眼黑，香染佛衣黄。", "未晚螢先出，蕭然兩畫廊。"]'),
('f4a8d679-8004-4816-afbd-bfc7ae1bd529','化龍閣','張至龍','宋','宋诗','song-poetry','','[]','鎸滿留題屋柱間，風吹醉面不知寒。',32,'全唐诗/poet.song.216000.json','["鎸滿留題屋柱間，風吹醉面不知寒。", "漁舟撐出垂楊岸，驚鷺銜魚過別灘。"]'),
('5f951a87-260b-4e39-90e1-478f2b3b68b3','吊蝶','張至龍','宋','宋诗','song-poetry','','[]','數日偎紅翅力慵，化成長夢別春風。',32,'全唐诗/poet.song.216000.json','["數日偎紅翅力慵，化成長夢別春風。", "却憐蟻爲埋香玉，舁入殘花土穴中。"]'),
('4d9d7118-6bde-47ef-b4c6-d83013e37927','寄胡竹洲','張至龍','宋','宋诗','song-poetry','','[]','野菜生根土亦香，寒林晴久漏春陽。',64,'全唐诗/poet.song.216000.json','["野菜生根土亦香，寒林晴久漏春陽。", "山臨古畫開當戶，蝸學名書篆滿牆。", "密竹旋刪嫌礙月，青柑遲摘待經霜。", "兒童閑取池頭水，剜破琉璃綠一方。"]'),
('9382e674-c7f0-495b-8f34-adb28bd31c6d','題白沙驛','張至龍','宋','宋诗','song-poetry','','[]','霧裹峰頭薄似巾，路逢水後誤行人。',64,'全唐诗/poet.song.216000.json','["霧裹峰頭薄似巾，路逢水後誤行人。", "山泉釀酒力偏重，石銚煎茶味最真。", "燕不傳家猶教子，梅纔有肉便生仁。", "枕邊學夢人方悟，未到鍾聲夢更頻。"]'),
('a8c5304c-5791-4a6f-88d6-a51d28dfb1aa','贈劉介菴','張至龍','宋','宋诗','song-poetry','','[]','一心憂道不開眉，懶扣黄扉謁故知。',64,'全唐诗/poet.song.216000.json','["一心憂道不開眉，懶扣黄扉謁故知。", "有累祇因難棄鶴，無疑何用苦求龜。", "常厨飲食夷齊輩，晚筆文章漢魏時。", "冷笑富家錢塞屋，蘭亭誰更有真碑。"]'),
('ce5ef6c6-58b5-4c5e-a8ad-39919b4d6a8e','馬升菴惠鞠苗','張至龍','宋','宋诗','song-poetry','','[]','稅得隣東地一方，旋栽黄鞠待重陽。',32,'全唐诗/poet.song.216000.json','["稅得隣東地一方，旋栽黄鞠待重陽。", "春晨摘落青苗葉，挼作秋花氣味香。"]'),
('7319c402-9389-4625-811c-5d2374507d39','東林寺','張至龍','宋','宋诗','song-poetry','','[]','滿院香風乍熟楂，猴孫抱子坐枯槎。',32,'全唐诗/poet.song.216000.json','["滿院香風乍熟楂，猴孫抱子坐枯槎。", "頭陀不慣迎賓客，自折芙蓉供釋迦。"]'),
('01a6ebd0-a42d-4e77-aa5b-2bc8f30db2d6','李梅磵雪夜留飲','張至龍','宋','宋诗','song-poetry','','[]','擁爐收案牘，市遠隔諠譁。',48,'全唐诗/poet.song.216000.json','["擁爐收案牘，市遠隔諠譁。", "妓唱新填曲，僮分旋碾茶。", "花枝承雪重，燭焰受風斜。", "僦屋爲官舍，更深酒更賒。"]'),
('a1557495-b398-430b-a57a-d9035fd2d5d4','宿易沖妙道院','張至龍','宋','宋诗','song-poetry','','[]','松髮經寒亂不梳，夜來風減屋茆疎。',32,'全唐诗/poet.song.216000.json','["松髮經寒亂不梳，夜來風減屋茆疎。", "吟邊凍指僵如鐵，袖裹枯筇畫雪書。"]'),
('61a21216-e2ea-43dd-81d2-70a1a1a8c1e4','朱柏巖約南歸','張至龍','宋','宋诗','song-poetry','','[]','忍聞秋管悲，猶未定歸期。',48,'全唐诗/poet.song.216000.json','["忍聞秋管悲，猶未定歸期。", "吟咏窮邊長，艱難老後知。", "水寒魚上少，月閏雁來遲。", "不作膏粱夢，長令一劍隨。"]'),
('e92eb9e8-9433-4030-80ed-4b484b2c99fe','橫峰感事','張至龍','宋','宋诗','song-poetry','','[]','石角多情挽布衣，候蟲送響出林微。',64,'全唐诗/poet.song.216000.json','["石角多情挽布衣，候蟲送響出林微。", "文章首面趨時好，字學偏傍徇俗非。", "綠水被風吹作白，密花因雨打教稀。", "歸鴉路熟知巢近，直望松林盡翅飛。"]'),
('1c1f97fb-35cb-4841-bf63-a66ffa49db67','答黄芳洲','張至龍','宋','宋诗','song-poetry','','[]','抱膝書樓望太清，一生心事月同明。',32,'全唐诗/poet.song.216000.json','["抱膝書樓望太清，一生心事月同明。", "因過隣寺分茶供，閑取高僧史傳評。"]'),
('a5ca6bf3-72a0-48d5-8836-d8e13126c4e9','餞翁丹山發南浦','張至龍','宋','宋诗','song-poetry','','[]','鳴鳩語燕近清明，柳絮風輕秧水平。',32,'全唐诗/poet.song.216000.json','["鳴鳩語燕近清明，柳絮風輕秧水平。", "一带春流多斷岸，盡緣倒樹當橋行。"]'),
('a5420234-e446-47de-ae66-cb2f0a1acafe','點史','張至龍','宋','宋诗','song-poetry','','[]','水草山花各自春，閑居常謹坐船身。',64,'全唐诗/poet.song.216000.json','["水草山花各自春，閑居常謹坐船身。", "忠言似藥偏醫國，好句如金不療貧。", "王霸興亡難諱史，彭殤壽夭不由人。", "感來莫計更深淺，祇見蒼頭換燭頻。"]'),
('d9f757f7-aa1e-4d73-b285-1b544545d543','採蓮曲  其一','張至龍','宋','宋诗','song-poetry','','[]','荷葉籠頭學道情，花妝那似妾妝清。',32,'全唐诗/poet.song.216000.json','["荷葉籠頭學道情，花妝那似妾妝清。", "雙雙頭白猶交頸，翻笑鴛鴦不老成。"]'),
('3a9c201e-8b93-4431-b6cd-baa3bbd80d87','採蓮曲  其二','張至龍','宋','宋诗','song-poetry','','[]','拗落圓房響釧金，背人細數子藏深。',32,'全唐诗/poet.song.216000.json','["拗落圓房響釧金，背人細數子藏深。", "不嫌到手多尖刺，祇怕傷人有苦心。"]'),
('ea103ef2-f014-4157-a40d-ad01d30e3933','子期臺','張至龍','宋','宋诗','song-poetry','','[]','拾葉題詩愧不才，袖遮微日上層臺。',32,'全唐诗/poet.song.216000.json','["拾葉題詩愧不才，袖遮微日上層臺。", "山僧分我松陰坐，隔岸花香渡水來。"]'),
('bb05b416-5a51-4529-aa7e-b42a59d4d00d','武夷山','張至龍','宋','宋诗','song-poetry','','[]','九折滄江轉葦航，花間流水自宮商。',64,'全唐诗/poet.song.216000.json','["九折滄江轉葦航，花間流水自宮商。", "巖開天綫登無路，殿鏁僊金拜有光。", "曝背龜從平石上，避人猴向險枝藏。", "斷橋盍有重紅日，狂欲乘風扣魏王。"]'),
('d04d5e53-c05c-4c61-9dcd-346692f3b42b','擬韓偓體','張至龍','宋','宋诗','song-poetry','','[]','一聲阿鵲顫鸞雙，學調新詞未得腔。',32,'全唐诗/poet.song.216000.json','["一聲阿鵲顫鸞雙，學調新詞未得腔。", "拜了夜香郎喚睡，旋收鍼綫背銀釭。"]'),
('7dc9f0fa-ea08-44ef-9f27-89b6ec93b8d0','題隠者壁','張至龍','宋','宋诗','song-poetry','','[]','寒著麻衣餒食薇，樂山清興只琴知。',64,'全唐诗/poet.song.216000.json','["寒著麻衣餒食薇，樂山清興只琴知。", "蛛經圓網當中立，蜂徙新厨出外飛。", "山脊倚天無改日，草根埋雪有青時。", "莫言鴻燕多相背，去去來來共一機。"]'),
('006d454e-89ee-4f1b-9a61-d1730ccf668f','雨中過陸家園','張至龍','宋','宋诗','song-poetry','','[]','斜搭鞦韆窗半扃，行人屐送隔牆聲。',32,'全唐诗/poet.song.216000.json','["斜搭鞦韆窗半扃，行人屐送隔牆聲。", "群花相倚啼妝面，苦不催晴怨懶鶑。"]'),
('04973d7f-7e9a-41ca-aa33-6fc5a33d0bdf','寄苕川故人','張至龍','宋','宋诗','song-poetry','','[]','千古長情祇翠岑，休談點石化黄金。',64,'全唐诗/poet.song.216000.json','["千古長情祇翠岑，休談點石化黄金。", "秋來國事方嘗膽，病後禪機忽上心。", "老眼看書嫌字細，乾喉飲酒喜杯深。", "幾回空檢斑衣篋，望斷白雲天外陰。"]'),
('d394c492-ee64-4f9b-b7e4-3c05c6edfb63','晚窗','張至龍','宋','宋诗','song-poetry','','[]','風約鍾聲落耳根，歸鴉點點不成群。',32,'全唐诗/poet.song.216000.json','["風約鍾聲落耳根，歸鴉點點不成群。", "前山野燒青煙起，散滿空中作暮雲。"]'),
('32fb31c0-303c-48a0-a637-de72332d360a','喜楊琴隠至','張至龍','宋','宋诗','song-poetry','','[]','世塗多不平，擇地度吾生。',48,'全唐诗/poet.song.216000.json','["世塗多不平，擇地度吾生。", "風靜花遲落，雲移月倒行。", "自抄閑作改，客借古琴評。", "凡事虛空裏，何勞苦著情。"]'),
('b40629f7-f959-4765-8d38-df103da819b5','寄寶林僧','張至龍','宋','宋诗','song-poetry','','[]','磨折英雄輩，無停日月梭。',48,'全唐诗/poet.song.216000.json','["磨折英雄輩，無停日月梭。", "達人愁夢少，明主直言多。", "藥試單方驗，碑評近本訛。", "吟成無愛者，寄與病僧哦。"]'),
('55a0f29d-52fb-4b25-b35d-0bf32fb73834','巴嶺','張至龍','宋','宋诗','song-poetry','','[]','處處柴門掩半邊，鶑啼綠樹隔炊煙。',32,'全唐诗/poet.song.216000.json','["處處柴門掩半邊，鶑啼綠樹隔炊煙。", "竹梯閑倚柔桑畔，定是人家蠶正眠。"]'),
('4f9d4133-26e3-4357-a1c2-502dc8492e93','楚節西塘省鞠','張至龍','宋','宋诗','song-poetry','','[]','鞠胎綠蕊未曾成，百種藂中半忘名。',32,'全唐诗/poet.song.216000.json','["鞠胎綠蕊未曾成，百種藂中半忘名。", "試檢記花牌字看，春籬醉墨欠分明。"]'),
('7bd6a493-2c45-46e7-9ff7-68a2dbdce0ae','槎','張至龍','宋','宋诗','song-poetry','','[]','槁形冷度幾晨昏，不受東風一點恩。',32,'全唐诗/poet.song.216000.json','["槁形冷度幾晨昏，不受東風一點恩。", "却有僊人求作伴，浪游星渚到天門。"]'),
('b1ce5b80-cd77-46c0-808d-942e8d1fc434','古別離','張至龍','宋','宋诗','song-poetry','','[]','扶上花驄酒半醺，望沉鞭影暗銷魂。',32,'全唐诗/poet.song.216000.json','["扶上花驄酒半醺，望沉鞭影暗銷魂。", "離情恐被行人覺，背拂菱花補淚痕。"]'),
('b293721f-5cd2-43c6-998f-7cbb05ae7313','峽口','張至龍','宋','宋诗','song-poetry','','[]','峽深猶有路，泉遠不知源。',48,'全唐诗/poet.song.216000.json','["峽深猶有路，泉遠不知源。", "禽學鄉談語，山填野燒痕。", "晚風樵笛塢，春日酒旗村。", "茆舍人耕罷，鳬雛浴水渾。"]'),
('d4f16d9d-cec3-4d9d-9252-9ea212f43ace','北津','張至龍','宋','宋诗','song-poetry','','[]','獨立長橋喜近城，半闌斜日又催行。',64,'全唐诗/poet.song.216000.json','["獨立長橋喜近城，半闌斜日又催行。", "船過別浦波痕沒，堠立當塗里界明。", "古木雲邊僧住處，落花風裏鳥啼聲。", "青山莫道渾無事，日與行人管送迎。"]'),
('7c11db2f-bf2c-4f92-9336-1773ad1345d0','江常菴出武夷','張至龍','宋','宋诗','song-poetry','','[]','厭居京洛說行持，袖裹青蛇上武夷。',64,'全唐诗/poet.song.216000.json','["厭居京洛說行持，袖裹青蛇上武夷。", "僊爲寫真供御覽，天憐病眼召神醫。", "江中白石差龍斲，洞裏蒼松带鶴移。", "無事出山衣屨濕，滿城風雨鞠花時。"]'),
('4fa2b659-97f1-411f-a4b1-7b78f649030d','晚步寄劉澂齋','張至龍','宋','宋诗','song-poetry','','[]','縱橫屐齒印蒼苔，夢筆山高翠作堆。',64,'全唐诗/poet.song.216000.json','["縱橫屐齒印蒼苔，夢筆山高翠作堆。", "日带晚光歸海去，風傳秋信下天來。", "竹開小路通螢過，松守空巢待鶴回。", "蚋甕乾坤還自樂，何須金屋玉樓臺。"]'),
('ed21c406-228a-4281-b236-12e9474effe3','簡勝上人','張至龍','宋','宋诗','song-poetry','','[]','林深嵐氣重，一犬吠寒煙。',48,'全唐诗/poet.song.216000.json','["林深嵐氣重，一犬吠寒煙。", "高思天雲外，新房柏樹邊。", "愛蒲尋石種，惜茗濾泉煎。", "昔創如來殿，老於師一年。"]'),
('11b4e0c9-c15e-4c51-9f7b-746353013ccd','演雅十章  其一','張至龍','宋','宋诗','song-poetry','','[]','麒麟感世出，鳳凰覽德至。',24,'全唐诗/poet.song.216000.json','["麒麟感世出，鳳凰覽德至。", "人苟常見之，應不指爲瑞。"]'),
('1d2c245c-3f64-455a-b2b8-b08a79561009','演雅十章  其二','張至龍','宋','宋诗','song-poetry','','[]','櫩蛛巧經網，林鳩拙營巢。',24,'全唐诗/poet.song.216000.json','["櫩蛛巧經網，林鳩拙營巢。", "孰知拙反勝，網壞巢獨牢。"]'),
('7012f5a6-ef86-4323-8824-3d9e39ced1f6','演雅十章  其三','張至龍','宋','宋诗','song-poetry','','[]','雀食野人田，燕栖公子堂。',24,'全唐诗/poet.song.216000.json','["雀食野人田，燕栖公子堂。", "野情饑亦樂，依人難久長。"]'),
('bcc4f24b-6eeb-4447-8716-9b324d60ffbf','演雅十章  其四','張至龍','宋','宋诗','song-poetry','','[]','猩猩隕機穽，鸚鵡鏁金籠。',24,'全唐诗/poet.song.216000.json','["猩猩隕機穽，鸚鵡鏁金籠。", "言笑適爲累，緘嘿斯保躬。"]'),
('78d0da9a-18ed-4d70-a233-15c439940c05','演雅十章  其五','張至龍','宋','宋诗','song-poetry','','[]','蠶飽辦絲課，蜂忙供蜜工。',24,'全唐诗/poet.song.216000.json','["蠶飽辦絲課，蜂忙供蜜工。", "役役爲人勞，衣食還自空。"]'),
('000382bc-ea11-478a-aa5d-68adc03f2a4c','演雅十章  其六','張至龍','宋','宋诗','song-poetry','','[]','鵲鳴人共憐，烏鳴人共嫉。',24,'全唐诗/poet.song.216000.json','["鵲鳴人共憐，烏鳴人共嫉。", "祇因聲妍媸，何心報凶吉。"]'),
('7bf83a0c-afa7-4405-a65d-ffb92e80247d','演雅十章  其七','張至龍','宋','宋诗','song-poetry','','[]','江鱗行比目，沙鴛睡交頸。',24,'全唐诗/poet.song.216000.json','["江鱗行比目，沙鴛睡交頸。", "不知山兔寒，清夜顧蟾影。"]'),
('c24eb182-eb7e-4b6c-9d9e-755ace6e6f97','演雅十章  其八','張至龍','宋','宋诗','song-poetry','','[]','饑鷹健搏兔，饞鷺勤捕魚。',24,'全唐诗/poet.song.216000.json','["饑鷹健搏兔，饞鷺勤捕魚。", "各爲口腹累，不聞有騶虞。"]'),
('e2bf7d08-3202-460f-9a56-f6ea06b02ce4','演雅十章  其九','張至龍','宋','宋诗','song-poetry','','[]','犬眠蒼玉地，貓卧香綺叢。',24,'全唐诗/poet.song.216000.json','["犬眠蒼玉地，貓卧香綺叢。", "倘無鼠與盜，貓犬命亦窮。"]'),
('281e0311-0ca5-4cdc-97ce-c2d07b46c7bf','演雅十章  其一○','張至龍','宋','宋诗','song-poetry','','[]','墨魚黑覆形，火螢明照身。',24,'全唐诗/poet.song.216000.json','["墨魚黑覆形，火螢明照身。", "拙於用顯晦，蹤跡徒自陳。"]'),
('1cda4ee4-5643-4960-9840-86c494bdbc5c','寓興十首  其一','張至龍','宋','宋诗','song-poetry','','[]','孤燈照長夜，膏盡燈影滅。',24,'全唐诗/poet.song.216000.json','["孤燈照長夜，膏盡燈影滅。", "劃見窗戶間，鮮鮮有明月。"]'),
('1ad615bb-b219-4800-aa03-0b56ae92cd74','寓興十首  其二','張至龍','宋','宋诗','song-poetry','','[]','日夜江水流，不海水不止。',24,'全唐诗/poet.song.216000.json','["日夜江水流，不海水不止。", "孰謂流去者，不是海中水。"]'),
('b6e095d3-68cd-4c4b-9427-152fcdabd83a','寓興十首  其三','張至龍','宋','宋诗','song-poetry','','[]','東日照瓦霜，西嚮界餘白。',24,'全唐诗/poet.song.216000.json','["東日照瓦霜，西嚮界餘白。", "莫言日不到，日光來未及。"]'),
('302b5046-064e-4263-8a01-fbabd260675e','寓興十首  其四','張至龍','宋','宋诗','song-poetry','','[]','遲月上深夜，新蟾不終夕。',24,'全唐诗/poet.song.216000.json','["遲月上深夜，新蟾不終夕。", "何如月圓時，通宵照無極。"]'),
('0fec8a6e-908d-4411-b7bd-24094650e47b','寓興十首  其五','張至龍','宋','宋诗','song-poetry','','[]','種鞠一百叢，九月開盈枝。',24,'全唐诗/poet.song.216000.json','["種鞠一百叢，九月開盈枝。", "莫言無好花，好花開較遲。"]'),
('2f822cd4-2deb-4f46-8b9a-591a3c1c2538','寓興十首  其六','張至龍','宋','宋诗','song-poetry','','[]','庭前無繁植，疎竹附梅坡。',24,'全唐诗/poet.song.216000.json','["庭前無繁植，疎竹附梅坡。", "雖然無巨蔭，明月飛來多。"]'),
('24de3c6f-ea20-4abb-97f3-026a06c5d923','寓興十首  其七','張至龍','宋','宋诗','song-poetry','','[]','草蟲設細網，小穽不可見。',24,'全唐诗/poet.song.216000.json','["草蟲設細網，小穽不可見。", "日日朝露中，群白草間現。"]'),
('c36fec8a-499c-462f-9540-94e24c969cd7','寓興十首  其八','張至龍','宋','宋诗','song-poetry','','[]','高風吹秋霜，庭前百草死。',24,'全唐诗/poet.song.216000.json','["高風吹秋霜，庭前百草死。", "誰知草有根，昨夜東風起。"]'),
('395ec3cb-bf35-45e8-963d-e27ce4295d37','寓興十首  其九','張至龍','宋','宋诗','song-poetry','','[]','夏月灌鞠根，見花在秋日。',24,'全唐诗/poet.song.216000.json','["夏月灌鞠根，見花在秋日。", "先時不施工，臨花已何及。"]'),
('ba4afe67-981b-4543-a7b3-e9830570d78e','寓興十首  其一○','張至龍','宋','宋诗','song-poetry','','[]','十年插柳枝，今與高樹齊。',24,'全唐诗/poet.song.216000.json','["十年插柳枝，今與高樹齊。", "垂條綠春風，上有流鶑啼。"]'),
('27dac59c-cc34-411f-b486-a1d19dd2aaec','梅花十詠 梅梢','張至龍','宋','宋诗','song-poetry','','[]','根清條不肥，影落明月地。',24,'全唐诗/poet.song.216000.json','["根清條不肥，影落明月地。", "凄凄欲寒時，胚腪已生意。"]'),
('b40ad220-1e9e-400b-9c5d-de1e22e0ad2f','梅花十詠 蓓蕾','張至龍','宋','宋诗','song-poetry','','[]','歷歷銜冰霜，綴作珠的皪。',24,'全唐诗/poet.song.216000.json','["歷歷銜冰霜，綴作珠的皪。", "香色俱渾然，花中之太極。"]'),
('650f16e0-08ef-4540-b778-f1edda8ed7cb','梅花十詠 欲開','張至龍','宋','宋诗','song-poetry','','[]','凝成姑射姿，幽潔世所獨。',24,'全唐诗/poet.song.216000.json','["凝成姑射姿，幽潔世所獨。", "春近迫芳心，羞澀破唇玉。"]'),
('67021438-2e9e-4a48-8dcb-3ebac36a15a1','梅花十詠 半開','張至龍','宋','宋诗','song-poetry','','[]','五出稍敷露，不受塵目愛。',24,'全唐诗/poet.song.216000.json','["五出稍敷露，不受塵目愛。", "鮮鮮著精神，獨於此時最。"]'),
('de74356d-60ed-48b9-9bcc-61f96de4f283','梅花十詠 全開','張至龍','宋','宋诗','song-poetry','','[]','昨夜東風多，花神莫之禦。',24,'全唐诗/poet.song.216000.json','["昨夜東風多，花神莫之禦。", "玉立對幽人，十分盡情吐。"]'),
('2507d71c-7e68-49f2-9969-7e7b1148b25f','梅花十詠 欲謝','張至龍','宋','宋诗','song-poetry','','[]','垂垂雪中枝，暗裏度香遠。',24,'全唐诗/poet.song.216000.json','["垂垂雪中枝，暗裏度香遠。", "忽動調羹機，黏枝花力軟。"]'),
('5ba51ab2-e592-42d5-a84c-7d1fe5a6ec37','梅花十詠 半謝','張至龍','宋','宋诗','song-poetry','','[]','旋隨瓊霙飛，繞我茆屋角。',24,'全唐诗/poet.song.216000.json','["旋隨瓊霙飛，繞我茆屋角。", "結子意漸濃，豈爲羌管落。"]'),
('08eec34b-92ab-4fb7-a37f-d47df88570ae','梅花十詠 全謝','張至龍','宋','宋诗','song-poetry','','[]','冰花不留丁，收香盡藏白。',24,'全唐诗/poet.song.216000.json','["冰花不留丁，收香盡藏白。", "一朝作陳人，遜與桃李出。"]'),
('503a441c-244c-43e6-a1dc-4710b4e7f895','梅花十詠 小實','張至龍','宋','宋诗','song-poetry','','[]','青青長朱裳，小摘脆不墮。',24,'全唐诗/poet.song.216000.json','["青青長朱裳，小摘脆不墮。", "勿欺如豆微，中懷仁已大。"]'),
('060b6bdf-7c2f-4508-ab06-0ce61820ab10','梅花十詠 大實','張至龍','宋','宋诗','song-poetry','','[]','圓碧日益肥，磊落壓枝重。',24,'全唐诗/poet.song.216000.json','["圓碧日益肥，磊落壓枝重。", "雖然苦味酸，酸中藏大用。"]'),
('47239ac3-9aba-40bd-820a-b1516082c3c2','山礬花','張至龍','宋','宋诗','song-poetry','','[]','漫山白蕊殿春華，多貯清香野老家。',32,'全唐诗/poet.song.216000.json','["漫山白蕊殿春華，多貯清香野老家。", "頻向風前招蝶使，密通家籍省梅花。"]'),
('0eb0d32e-5119-492d-8f36-d7bff2c2a2c2','立春','施樞','宋','宋诗','song-poetry','','[]','雪花風細拂春旗，一色雲邊漏暖曦。',64,'全唐诗/poet.song.216000.json','["雪花風細拂春旗，一色雲邊漏暖曦。", "群吏守文行故典，長官書祝致新祠。", "土牛底事遭身碎，綵勝隨時把鬢欺。", "爭似野人閑可睡，枕邊搔髮自吟詩。"]'),
('c04246ee-c985-4253-bcd1-ada071130ca9','感春','施樞','宋','宋诗','song-poetry','','[]','等閑覊旅欲歸難，又見蔬盤簇綵幡。',64,'全唐诗/poet.song.216000.json','["等閑覊旅欲歸難，又見蔬盤簇綵幡。", "九十日春從此始，萬千心事對誰言。", "梅邊粉墜寒香骨，草際青歸野燒痕。", "且把一杯酬好景，花風今日已翩翩。"]'),
('a2851cf9-8207-47c1-bd16-ce9f9d0a4aec','春前一日雪','施樞','宋','宋诗','song-poetry','','[]','曆頭只有今朝臘，猶雨霏霙滿太虛。',64,'全唐诗/poet.song.216000.json','["曆頭只有今朝臘，猶雨霏霙滿太虛。", "六出試妝梅欲妬，萬花飄絮柳難如。", "雲凝慘送玄冥旆，風舞歡迎青帝車。", "始信春工多富貴，便堆白玉滿前除。"]'),
('aab00966-1c31-4417-9f89-c297cbf99d1c','春多日','施樞','宋','宋诗','song-poetry','','[]','春到溪山已近旬，尋春猶自負深情。',64,'全唐诗/poet.song.216000.json','["春到溪山已近旬，尋春猶自負深情。", "愛閑長向梅邊立，趁煖時從竹下行。", "苦乏詩材無可借，更嫌酒病有餘酲。", "算來豈是因名利，纔有關心便不清。"]'),
('4048d651-8a94-4b82-afcd-ef22dc7bee0f','贈湖邊柳','施樞','宋','宋诗','song-poetry','','[]','亂撒鵝黄拂曉晴，天涯多少故人情。',32,'全唐诗/poet.song.216000.json','["亂撒鵝黄拂曉晴，天涯多少故人情。", "遊舡空逐輕陰轉，半屬春風半屬鶑。"]'),
('d98f86c7-06a2-4808-bcfc-98877d97ae16','夢遊徑山值雪擁爐賦詩','施樞','宋','宋诗','song-poetry','','[]','雪天元自冷，何况是山中。',48,'全唐诗/poet.song.216000.json','["雪天元自冷，何况是山中。", "雙徑衝寒霧，千林戰晚風。", "室中人已定，爐內火常紅。", "萬事皆如夢，誰知夢亦空。"]'),
('d3b3f823-317a-4275-a313-2815deacc08f','次蒙齋至日韻','施樞','宋','宋诗','song-poetry','','[]','試檢清臺曆，黄宮氣已回。',48,'全唐诗/poet.song.216000.json','["試檢清臺曆，黄宮氣已回。", "功名難强致，歲月任渠來。", "雨逕猶存菊，煙村可問梅。", "爲貪吟有伴，到此又徘徊。"]'),
('3a31c4f9-ef12-423e-8ed2-c3a5de7074cf','玉泉','施樞','宋','宋诗','song-poetry','','[]','水蹟無增減，從知地有靈。',48,'全唐诗/poet.song.216000.json','["水蹟無增減，從知地有靈。", "羣魚潜異窟，一芥納滄溟。", "濟隠新留詠，超師舊講經。", "聖時調玉燭，龍睡不須醒。"]'),
('195b3f3e-a15e-4e85-980f-d2eca0437d9b','老僧念佛','施樞','宋','宋诗','song-poetry','','[]','身世皆空境，知空自不悲。',48,'全唐诗/poet.song.216000.json','["身世皆空境，知空自不悲。", "何須臨暮日，逐急念阿彌。", "裴相安心際，維摩懺罪時。", "同歸無有地，明月在秋池。"]'),
('e07b35e9-86f8-4117-a8b4-2b7988059fbf','和菊潭韻題秋潭買山圖後','施樞','宋','宋诗','song-poetry','','[]','身世如萍漫浪休，機心誰遣誤沙鷗。',64,'全唐诗/poet.song.216000.json','["身世如萍漫浪休，機心誰遣誤沙鷗。", "從來風月驚人句，即是湖山買屋謀。", "訪友定尋雲外寺，携壺須上竹邊樓。", "知音自有漁樵侶，莫被人稱第一流。"]'),
('3e6748ab-345b-4df8-8d19-0eb40c69d545','對雪','施樞','宋','宋诗','song-poetry','','[]','怪得連陰不放晴，直教飛雪試輕盈。',64,'全唐诗/poet.song.216000.json','["怪得連陰不放晴，直教飛雪試輕盈。", "風回冉冉霓裳舞，雲暗紛紛鶴羽明。", "大似梅花饒一出，薄於柳絮更多情。", "披衣端爲詩催起，吟得詩成分外清。"]'),
('5554f8e7-fcba-4d60-a03a-169b86c02587','霸國祠','施樞','宋','宋诗','song-poetry','','[]','瓶笙驚晝睡，此意有誰知。',48,'全唐诗/poet.song.216000.json','["瓶笙驚晝睡，此意有誰知。", "蛙井成何事，鴻圖豈易窺。", "一身雖戮辱，萬姓免瘡痍。", "茅土今何在，惟存霸國祠。"]'),
('4e4661f7-1def-4df6-be2d-90c1890cded1','早起','施樞','宋','宋诗','song-poetry','','[]','早起看花露，西風把鬢欺。',48,'全唐诗/poet.song.216000.json','["早起看花露，西風把鬢欺。", "心清多在道，夢好亦成詩。", "過但思求己，生無事皺眉。", "功名緣底事，到手却如遲。"]'),
('9e9c7778-72ba-4d42-a5ca-1f03a34aad2b','漕闈揭曉後述懷','施樞','宋','宋诗','song-poetry','','[]','畫眉深淺與時殊，肯向堂前怨舅姑。',64,'全唐诗/poet.song.216000.json','["畫眉深淺與時殊，肯向堂前怨舅姑。", "自是吾儂多蹇薄，可堪爾汝肆揶揄。", "心知不是池中物，眼獨羞看屋上烏。", "得喪總爲身外事，不如委命樂樵蘇。"]'),
('94047c3e-4149-49ec-935a-4bbe2e14d839','聞雁','施樞','宋','宋诗','song-poetry','','[]','飛盡沙田到水鄉，年年來往爲誰忙。',32,'全唐诗/poet.song.216000.json','["飛盡沙田到水鄉，年年來往爲誰忙。", "只貪月夜蘆花宿，不是將身傍稻粱。"]'),
('6bff6e11-241e-4f03-a44c-2abc5ef6ec0e','通真觀  其一','施樞','宋','宋诗','song-poetry','','[]','不到凝安二十年，丹青一幅尚依然。',32,'全唐诗/poet.song.216000.json','["不到凝安二十年，丹青一幅尚依然。", "青牛已去仙蹤遠，却有山禽下玉田。"]'),
('8015b320-68cb-4c7d-af3e-282b45e0d908','通真觀  其二','施樞','宋','宋诗','song-poetry','','[]','桃源事已成荒幻，那更形容學避秦。',32,'全唐诗/poet.song.216000.json','["桃源事已成荒幻，那更形容學避秦。", "欲訪舊蹤無處覓，滿山花落不知春。"]'),
('b25d761b-f7fd-4b5d-9552-a4e745f5de68','泛月夜歸','施樞','宋','宋诗','song-poetry','','[]','短艇衝寒泛淺沙，滿溪明月浸蘆花。',32,'全唐诗/poet.song.216000.json','["短艇衝寒泛淺沙，滿溪明月浸蘆花。", "忽驚遠岸燈光發，籬落蕭疏一兩家。"]'),
('d1012c4c-4689-495a-b825-02db149abad2','龜溪市橋見月','施樞','宋','宋诗','song-poetry','','[]','樓臺疊翠繞清溪，淺澹雲邊月一眉。',32,'全唐诗/poet.song.216000.json','["樓臺疊翠繞清溪，淺澹雲邊月一眉。", "行到市聲相接處，傍橋燈火未多時。"]'),
('95276dd5-7875-4950-bb95-00af8b9c51b1','寄寶藏壁天瑞','施樞','宋','宋诗','song-poetry','','[]','路轉小橋東，群龍擁梵宮。',48,'全唐诗/poet.song.216000.json','["路轉小橋東，群龍擁梵宮。", "荇花明晚水，蓮葉向秋風。", "匠斧應休役，禪窗定費功。", "笑他塵俗者，客路每匆匆。"]'),
('51ea8df5-16b6-476e-b5fb-8f30aee69767','夜寒有作','施樞','宋','宋诗','song-poetry','','[]','可怪輕寒薄短衾，起來搔首傍燈吟。',64,'全唐诗/poet.song.216000.json','["可怪輕寒薄短衾，起來搔首傍燈吟。", "百年易老風前鬢，萬事難侵水樣心。", "雁叫雲天秋渺渺，蟲鳴露砌夜沉沉。", "朱絲自寫無人識，一曲寥寥太古音。"]'),
('23ba4c9b-b6f4-4fa3-8bcb-c91451457793','入京','施樞','宋','宋诗','song-poetry','','[]','何期又泛玉京船，行止於人不偶然。',64,'全唐诗/poet.song.216000.json','["何期又泛玉京船，行止於人不偶然。", "寒力勝如前兩夜，世情熟似近三年。", "只將興味留詩裏，苦乏工夫到酒邊。", "萬事看來忙不得，只須委順樂吾天。"]'),
('b91bd936-c657-4981-816b-9b008f13277f','憶孤山','施樞','宋','宋诗','song-poetry','','[]','孤山不是遠，只隔鳳城門。',48,'全唐诗/poet.song.216000.json','["孤山不是遠，只隔鳳城門。", "爭賞詩家句，誰招隠士魂。", "秋風林下塚，寒月水邊村。", "擬待梅花發，長吟酹一尊。"]'),
('48a40f3c-097b-42a0-92c6-17f0cd6dc969','小樓獨坐用菊潭壁間韻','施樞','宋','宋诗','song-poetry','','[]','簾捲疏風入小樓，夕陽銜雁欲西流。',32,'全唐诗/poet.song.216000.json','["簾捲疏風入小樓，夕陽銜雁欲西流。", "無人細說吟邊事，獨有黄花共晚秋。"]'),
('083ee7bc-087b-4eec-8566-87996edc4db1','別高家店','施樞','宋','宋诗','song-poetry','','[]','獨抱朱絃識者稀，湖山與我獨相知。',64,'全唐诗/poet.song.216000.json','["獨抱朱絃識者稀，湖山與我獨相知。", "烟迷柳岸經行少，月照梅窗做夢遲。", "酒價寒高誰與貰，衾綿夜薄自多思。", "歸舟又值商量雪，好似清溪訪戴時。"]'),
('f3b2e8d2-823c-4d56-91ff-3a680c84cd41','夢回','施樞','宋','宋诗','song-poetry','','[]','銀漏迢迢箭緩傳，夢回月在早梅邊。',32,'全唐诗/poet.song.216000.json','["銀漏迢迢箭緩傳，夢回月在早梅邊。", "小池凍合寒蘆折，應是鴛鴦夜不眠。"]'),
('f200cb1e-020d-4b55-bc07-f73461f263d0','馬上','施樞','宋','宋诗','song-poetry','','[]','只爲溪山有宿盟，兩旬兩度此經行。',64,'全唐诗/poet.song.216000.json','["只爲溪山有宿盟，兩旬兩度此經行。", "馬嘶險逕霜蹄滑，鷗舞平沙雪羽輕。", "豪氣不從塵外減，新詩偏向道間成。", "梅花似有相迎意，野水籬邊數蘂明。"]'),
('6dcf6be8-2754-4df0-b65e-ea999a0a9890','讀真西山奏疏','施樞','宋','宋诗','song-poetry','','[]','戎狄從來不可憑，誰令漢祖議和親。',64,'全唐诗/poet.song.216000.json','["戎狄從來不可憑，誰令漢祖議和親。", "連衡休易從游說，厝火當憂卧積薪。", "黯在淮南謀自寢，亮亡司馬志方伸。", "本强始見遐衝折，信是經綸直要人。"]'),
('47681e8e-d7f1-43ca-b90b-d06447f7cf0a','新月照雪','施樞','宋','宋诗','song-poetry','','[]','等是尋常月，因添雪更明。',48,'全唐诗/poet.song.216000.json','["等是尋常月，因添雪更明。", "看他同樣白，與我一般清。", "睡鶴應難認，棲烏亦屢驚。", "梅花仍有意，相伴聽寒更。"]'),
('de6cd7f2-ef3c-4a68-85b9-e4e65ab8ead5','雪晴','施樞','宋','宋诗','song-poetry','','[]','送臘終宵舞，知春破曉晴。',48,'全唐诗/poet.song.216000.json','["送臘終宵舞，知春破曉晴。", "燒痕隨草長，霽色映梅清。", "溜滴簷簪折，冰開沼鏡明。", "夜窗如對月，還又憶輕盈。"]'),
('32b9479f-8bcd-4f7f-8111-6281967cbb8b','對雪','施樞','宋','宋诗','song-poetry','','[]','誰使霓裳逞細腰，隨風盡日袂飄颻。',64,'全唐诗/poet.song.216000.json','["誰使霓裳逞細腰，隨風盡日袂飄颻。", "飛花却訝春將遍，舞片還驚凍易銷。", "看熟似同鷗過渚，興仙剛道鶴沖霄。", "吟成誰與相酬酢，頼有疏梅伴寂寥。"]'),
('89a6c2e1-a0eb-4efe-b4a1-04cca25ed91d','正月十四夜','施樞','宋','宋诗','song-poetry','','[]','覊游偶值上元時，蓮艷燒空照錦溪。',64,'全唐诗/poet.song.216000.json','["覊游偶值上元時，蓮艷燒空照錦溪。", "堂上珠簾如水浸，庭前鰲架與山齊。", "風傳鼓吹春聲閙，雨遏笙歌夜語低。", "自笑蓬窗勤苦士，何當太乙爲燃藜。"]'),
('001ec22b-426f-4e8c-baba-5b2718a0a8a9','新晴','施樞','宋','宋诗','song-poetry','','[]','寒窗寂寞度殘冬，接得春來雨又風。',64,'全唐诗/poet.song.216000.json','["寒窗寂寞度殘冬，接得春來雨又風。", "芳思悠悠空自遠，清游款款與誰同。", "林梢淡抹烟初霽，菜甲新抽土旋融。", "多謝殷勤簷鵲舞，數聲足喜夕陽中。"]'),
('b17c0f39-1b0e-4078-b3ca-4520d3c45271','分韻春字','施樞','宋','宋诗','song-poetry','','[]','柳外鶑聲錯喚人，小樓吟苦不知春。',32,'全唐诗/poet.song.216000.json','["柳外鶑聲錯喚人，小樓吟苦不知春。", "落花飛過秋千去，一片閑情客裏身。"]'),
('022bd7f7-870b-48e1-827a-77e792d956c6','綠字韻','施樞','宋','宋诗','song-poetry','','[]','曉帳香銷閑畫燭，夢回山斷屏風曲。',32,'全唐诗/poet.song.216000.json','["曉帳香銷閑畫燭，夢回山斷屏風曲。", "輕烟細雨客情多，南浦草隨新漲綠。"]'),
('aee272dc-7579-472a-a166-24f1126040b1','書事','施樞','宋','宋诗','song-poetry','','[]','閑時但覺求人易，險處方知爲己深。',32,'全唐诗/poet.song.216000.json','["閑時但覺求人易，險處方知爲己深。", "世事盡隨流水去，白雲自識古人心。"]'),
('d31b3623-f967-46d4-acdc-ec22fcc8ed7f','所見','施樞','宋','宋诗','song-poetry','','[]','齊眉沉醉綺羅叢，心事誰知付去鴻。',32,'全唐诗/poet.song.216000.json','["齊眉沉醉綺羅叢，心事誰知付去鴻。", "不惜千金留粉黛，更無一語怨東風。"]'),
('5a55236e-9309-420e-950e-f07d0c78f76a','閨思','施樞','宋','宋诗','song-poetry','','[]','簾底臨鸞惜歲華，鬢雲慵掠寶釵斜。',32,'全唐诗/poet.song.216000.json','["簾底臨鸞惜歲華，鬢雲慵掠寶釵斜。", "落梅香斷無消息，一樹春風屬杏花。"]'),
('db9cc194-22c7-4926-8604-55da761f8225','湧金門外','施樞','宋','宋诗','song-poetry','','[]','柳絲舞困起炊烟，羅綺相催欲上船。',32,'全唐诗/poet.song.216000.json','["柳絲舞困起炊烟，羅綺相催欲上船。", "貴冶亦知春有夜，煖沙還付白鷗眠。"]'),
('4a790c55-60e7-4620-97ab-e0af4a6c3198','春夜賦小字','施樞','宋','宋诗','song-poetry','','[]','岸桐花開春欲老，目斷斜陽芳信杳。',32,'全唐诗/poet.song.216000.json','["岸桐花開春欲老，目斷斜陽芳信杳。", "東風不筦客情多，杜鵑啼月青山小。"]'),
('34ca075c-2a61-4436-a642-1d201b278c77','再行湖上','施樞','宋','宋诗','song-poetry','','[]','樓臺萬疊照斜暉，紅褪園林綠漸肥。',32,'全唐诗/poet.song.216000.json','["樓臺萬疊照斜暉，紅褪園林綠漸肥。", "艷是杏桃開過了，春風吹到野薔薇。"]'),
('1ea18e3b-3b6b-437d-bdcc-3e90e594e4a6','小樓對月','施樞','宋','宋诗','song-poetry','','[]','京國誰曾念旅游，閑情芳思兩悠悠。',32,'全唐诗/poet.song.216000.json','["京國誰曾念旅游，閑情芳思兩悠悠。", "却因今夜欄干月，引得春風上小樓。"]'),
('c769cb65-0e35-4f45-92c3-be79524efc78','晚望','施樞','宋','宋诗','song-poetry','','[]','芳草迢迢客路長，柳邊吹絮燕泥香。',32,'全唐诗/poet.song.216000.json','["芳草迢迢客路長，柳邊吹絮燕泥香。", "桐花拆盡春歸去，猶倚危闌問夕陽。"]'),
('90f21723-4058-4681-a699-43d72c362785','再賦酬吳鞠潭','施樞','宋','宋诗','song-poetry','','[]','酌酒酬春醉晚紅，誰知書劍兩無功。',64,'全唐诗/poet.song.216000.json','["酌酒酬春醉晚紅，誰知書劍兩無功。", "漁竿冷浸半絲月，牛背閑消一笛風。", "仙夢不隨狂蝶亂，家書只倩素魚通。", "友聲更擬遷喬去，底似人情較異同。"]'),
('08563ac9-9773-4bf0-b587-358d51c92069','覽鏡','施樞','宋','宋诗','song-poetry','','[]','心到無營本倦游，何期身又客王州。',64,'全唐诗/poet.song.216000.json','["心到無營本倦游，何期身又客王州。", "匣藏青鏡閑情薄，衣染紅塵滿面羞。", "風月幾曾於我少，波濤半是爲人憂。", "故山幸自堪耕釣，不必生涯足是休。"]'),
('da01fa20-e8fe-4312-a6fa-873438fff59a','牡丹','施樞','宋','宋诗','song-poetry','','[]','天然貴格鎮群芳，細雨叢中試寶妝。',64,'全唐诗/poet.song.216000.json','["天然貴格鎮群芳，細雨叢中試寶妝。", "肯與亂紅爭國色，甘同柔綠挽春光。", "玉闌倚困嬌無力，金鴨沉煙不敢香。", "可惜承恩亭北賦，苦無妙語告君王。"]'),
('56a05a6d-998e-457c-92da-23a41a543f12','留別詩僧','施樞','宋','宋诗','song-poetry','','[]','家山方繾綣，客路復西東。',48,'全唐诗/poet.song.216000.json','["家山方繾綣，客路復西東。", "自念依明世，誰令策雋功。", "三盃桑落酒，一棹柳花風。", "別後詩應好，吟成寄短筒。"]'),
('243c5a56-7d75-44d7-ac78-a2906bc4f692','送春','施樞','宋','宋诗','song-poetry','','[]','相逢九十日，彼此惜芳期。',48,'全唐诗/poet.song.216000.json','["相逢九十日，彼此惜芳期。", "折柳停閑騎，嚼花吟好詩。", "經年行遠別，對景起深思。", "日落不知處，四山啼子規。"]'),
('c7b9c324-5ec4-4637-9284-97c23a25b15a','懷友人','施樞','宋','宋诗','song-poetry','','[]','錦野重來已秀葽，雨肥梅杏粉痕銷。',64,'全唐诗/poet.song.216000.json','["錦野重來已秀葽，雨肥梅杏粉痕銷。", "晚山四面子規叫，曉樹一聲婆餠焦。", "耐久交當如水淡，慣游身亦似蓬飄。", "老鶑不省春歸久，猶自教雛學徙喬。"]'),
('5bdb5dcb-347a-4d8c-ac26-2e5cb97cc459','後塢示壁天瑞','施樞','宋','宋诗','song-poetry','','[]','幾年不到巳公齋，客裏明知未定家。',32,'全唐诗/poet.song.216000.json','["幾年不到巳公齋，客裏明知未定家。", "生滅無邊方共語，滿山春雨落松花。"]'),
('62737d08-9810-485e-9a00-2fb2604bb70b','即事','施樞','宋','宋诗','song-poetry','','[]','暝色分烟上遠峯，雨聲斷處又晴風。',32,'全唐诗/poet.song.216000.json','["暝色分烟上遠峯，雨聲斷處又晴風。", "寶香羞冷閑情遠，落盡薔薇一架紅。"]'),
('636f4fbf-09ff-4e84-b08b-dfa4cc265fe4','簷玉鳴','施樞','宋','宋诗','song-poetry','','[]','嘵窗風細響簷鈴，一曲雲璈枕上聞。',32,'全唐诗/poet.song.216000.json','["嘵窗風細響簷鈴，一曲雲璈枕上聞。", "夢斷不知仙路杳，鶴銜松露入青雲。"]'),
('1920c099-6b87-43cd-a821-9bae4b065a7a','東天目  其一','施樞','宋','宋诗','song-poetry','','[]','不辭巇險訪龍潭，潭底無窮碧似藍。',64,'全唐诗/poet.song.216000.json','["不辭巇險訪龍潭，潭底無窮碧似藍。", "亂石鳴灘溪過九，飛泉瀉瀑塹分三。", "雖然道士能相引，不比樵人得盡諳。", "怊悵飛橋無路到，乘風應許御雲驂。"]'),
('05c33c73-c8e4-493c-83f7-4b85552745b4','東天目  其二','施樞','宋','宋诗','song-poetry','','[]','不謂山行得此晴，有名勝處必須經。',64,'全唐诗/poet.song.216000.json','["不謂山行得此晴，有名勝處必須經。", "玉田草滿春無極，石室人稀夜不扃。", "自料俗情應厭倦，誰知幽意在空冥。", "碧桃却似傳消息，一曲瓊歌月滿庭。"]'),
('713ce11e-2a7d-4411-9a14-211e4cf23b30','西天目','施樞','宋','宋诗','song-poetry','','[]','苕水之源出此山，地如邾魯始躋攀。',64,'全唐诗/poet.song.216000.json','["苕水之源出此山，地如邾魯始躋攀。", "三池浚澤高岡上，一勺爲霖反掌間。", "著脚不知蒼漢近，無心直共白雲閑。", "何時結屋枕泉玉，滌盡塵根學大還。"]'),
('1ba3fdbc-4ea5-4223-9375-2d26f3b51023','題朝陽洞中','施樞','宋','宋诗','song-poetry','','[]','一吸龍泉萬慮清，更尋古洞入柴荆。',32,'全唐诗/poet.song.216000.json','["一吸龍泉萬慮清，更尋古洞入柴荆。", "桃花落盡春無路，獨許騎鸞上玉京。"]'),
('09edf545-942e-47ac-b5b6-b3091e1afb4b','題至道宮雲巢軒','施樞','宋','宋诗','song-poetry','','[]','碧霄路底作生涯，雲亦何曾定有家。',32,'全唐诗/poet.song.216000.json','["碧霄路底作生涯，雲亦何曾定有家。", "月印天池心宇浄，水鳴環珮出松花。"]'),
('88732f4a-2228-442d-9709-c6e1d9384535','別天目','施樞','宋','宋诗','song-poetry','','[]','東尖森洞穴，西目浚淵庭。',48,'全唐诗/poet.song.216000.json','["東尖森洞穴，西目浚淵庭。", "三日若爲霽，群龍亦有靈。", "立依松作蓋，坐倚石爲屏。", "猶恨歸鞍急，回頭望遠青。"]'),
('f5058eb2-54b9-41d5-8d70-741d623da9e1','聞西山訃音','施樞','宋','宋诗','song-poetry','','[]','奪到斯人處，天心亦杳冥。',48,'全唐诗/poet.song.216000.json','["奪到斯人處，天心亦杳冥。", "嘉謀猶未罄，直道信無靈。", "四海方思雨，中營忽隕星。", "群賢知孰附，客泪欲飄零。"]'),
('39077dba-e5a8-41cd-a00c-e0d01f0aeff9','芍藥  其一','施樞','宋','宋诗','song-poetry','','[]','雖殊桃李競年芳，色相惟應付夢鄉。',64,'全唐诗/poet.song.216000.json','["雖殊桃李競年芳，色相惟應付夢鄉。", "綸閣曾看金縷艷，蘂宮初試玉樓妝。", "露凝深淺烟中淚，日汎溫柔雨後香。", "幸蜀歸來花正好，可憐不忍看嬪嬙。"]'),
('b9674910-cdcb-4fe1-b5b7-b203c4ab4aa6','芍藥  其二','施樞','宋','宋诗','song-poetry','','[]','天女霜刀剪亦難，露紅烟紫碧闌干。',64,'全唐诗/poet.song.216000.json','["天女霜刀剪亦難，露紅烟紫碧闌干。", "步摇衣袂飄霞珮，鈿合釵梁間寶冠。", "枝上任他無力笑，燈前還作有情看。", "采根若可蘇民病，始信無經載牡丹。"]'),
('74914a90-64d0-4987-a327-6c0784863271','玉蝴蝶花','施樞','宋','宋诗','song-poetry','','[]','芳意深深掩綠苔，粉團香翅自裴回。',32,'全唐诗/poet.song.216000.json','["芳意深深掩綠苔，粉團香翅自裴回。", "多應又怨春歸早，化作飛花滿樹開。"]'),
('d5838845-a2fa-4881-9fe2-f791083cd076','小瓊花','施樞','宋','宋诗','song-poetry','','[]','合是孤根在廣庭，世間那得此雲英。',32,'全唐诗/poet.song.216000.json','["合是孤根在廣庭，世間那得此雲英。", "霓裳一曲天香散，惆悵瑶階月自明。"]'),
('810875df-27a3-4620-9c65-5f24e39211a2','午寢','施樞','宋','宋诗','song-poetry','','[]','舊詩零亂滿藤牀，綠映簾深一縷香。',32,'全唐诗/poet.song.216000.json','["舊詩零亂滿藤牀，綠映簾深一縷香。", "午夢驚回槐國遠，浮生消得幾斜陽。"]'),
('3c5e12d9-0499-41b4-a4c3-3b49b29cc5ce','道間','施樞','宋','宋诗','song-poetry','','[]','一溪新綠漲晴沙，傍岸疏籬八九家。',32,'全唐诗/poet.song.216000.json','["一溪新綠漲晴沙，傍岸疏籬八九家。", "桑葉又抽麻正長，綠陰深處響繰車。"]'),
('671644a2-4eff-46ca-b573-d0cf93e119e6','再觀錢廟','施樞','宋','宋诗','song-poetry','','[]','荒碑五丈蘚生花，飛鼠巢梁壁綴蝸。',32,'全唐诗/poet.song.216000.json','["荒碑五丈蘚生花，飛鼠巢梁壁綴蝸。", "華胄遥遥天下滿，不知誓券落誰家。"]'),
('3da9b1d0-54fc-4248-be90-92286ddc5d5c','牆外竹','施樞','宋','宋诗','song-poetry','','[]','森森新竹亞牆屏，籜解餘斑粉泪零。',32,'全唐诗/poet.song.216000.json','["森森新竹亞牆屏，籜解餘斑粉泪零。", "幸入詩家窮相眼，可能不爲此君青。"]'),
('ada79a30-b81e-4e9c-880d-cf1c14f0730a','題鶴林丈室用俞紫薇韻','施樞','宋','宋诗','song-poetry','','[]','物我相忘付八還，偶來瓊舘扣霞關。',64,'全唐诗/poet.song.216000.json','["物我相忘付八還，偶來瓊舘扣霞關。", "玉峯自有三生約，塵世真同一夢間。", "華表風清丹頂去，緱山月冷碧笙閑。", "當知象外機無息，肯羨黄金繫九環。"]'),
('37792d95-7ebf-4c45-859b-5d15b7c84787','五到洞霄兼似沖妙','施樞','宋','宋诗','song-poetry','','[]','多謝名山不厭人，五來此地著閑身。',64,'全唐诗/poet.song.216000.json','["多謝名山不厭人，五來此地著閑身。", "泉聲带雨驅煩暑，空翠縈風絕點塵。", "金鼎火能知應候，玉壺花自占長春。", "何時許證三生約，乞借烟霞與卜鄰。"]'),
('27829f8e-87e1-4fb1-88e2-2c27a8a91889','楊蟾川鐵佛普度會  其一','施樞','宋','宋诗','song-poetry','','[]','重陰九壘幾曾開，廣布陰功亦異哉。',64,'全唐诗/poet.song.216000.json','["重陰九壘幾曾開，廣布陰功亦異哉。", "八景定中朝十極，五雲深處步三台。", "烟騰綠字鸞初下，月照黄壇鶴未來。", "去地一珠如黍米，天人競湊鬰羅臺。"]'),
('cccdc057-80b1-4cbe-8541-3340b3e3feea','楊蟾川鐵佛普度會  其二','施樞','宋','宋诗','song-poetry','','[]','煒燁神光燭素屏，苦魂蒙度語堪聽。',64,'全唐诗/poet.song.216000.json','["煒燁神光燭素屏，苦魂蒙度語堪聽。", "但知實相皆非相，自證無形入有形。", "火煉赤鑪超上景，水流華沼蕩寒庭。", "功成試問誰能似，元子真人舊典刑。"]'),
('02e05d3c-7398-4a6c-be94-b473414b8a7b','夜泊黄灣','施樞','宋','宋诗','song-poetry','','[]','移近黄灣泊短篷，野雲垂地一溪風。',32,'全唐诗/poet.song.216000.json','["移近黄灣泊短篷，野雲垂地一溪風。", "渚香吹散荷花雨，幾點流螢出葦叢。"]'),
('4efb4e73-69e5-44dc-a885-b79c5947efb1','夜凉聽雨','施樞','宋','宋诗','song-poetry','','[]','暑雨沉沉夜正深，凉欺客枕夢頻醒。',32,'全唐诗/poet.song.216000.json','["暑雨沉沉夜正深，凉欺客枕夢頻醒。", "雖然未是秋時候，滴在梧桐亦厭聽。"]'),
('393b272f-6d88-4b94-b4ca-c3425cb71b00','西河柳','施樞','宋','宋诗','song-poetry','','[]','一把輕絲拂地垂，柔梢淺淺抹燕脂。',32,'全唐诗/poet.song.216000.json','["一把輕絲拂地垂，柔梢淺淺抹燕脂。", "絮花吹盡枝方長，却恨春風未得知。"]'),
('f7334a4f-1644-4de1-8293-a656b14f6739','三過垂虹','施樞','宋','宋诗','song-poetry','','[]','秋來三度過垂虹，灝氣橫江水接空。',64,'全唐诗/poet.song.216000.json','["秋來三度過垂虹，灝氣橫江水接空。", "帆影輕浮千幅月，漁竿冷浸一絲風。", "楓初落葉前村近，荷有餘香別浦通。", "笑拍闌干天地闊，鱠鱸樽酒許誰同。"]'),
('73152ec6-f8ed-4f36-a5d3-5e3e1f56ca94','滄浪','施樞','宋','宋诗','song-poetry','','[]','長史遺蹤二百年，直教名字到今傳。',64,'全唐诗/poet.song.216000.json','["長史遺蹤二百年，直教名字到今傳。", "渚香細浥蓮須雨，野色輕團竹尾烟。", "但得幽情關水石，何須隠迹痼林泉。", "客中正有塵纓在，來此清遊亦是緣。"]'),
('c8664370-49bb-442c-9243-d974d674b461','水次秋蚊可畏','施樞','宋','宋诗','song-poetry','','[]','利觜似花鷹，針膚不暫停。',48,'全唐诗/poet.song.216000.json','["利觜似花鷹，針膚不暫停。", "有生何蠢蠢，藏毒在冥冥。", "亂舞迷昏水，喧聲接曉汀。", "風威秋晚勁，看汝易飄零。"]'),
('1f1cb684-e988-4689-b87d-40eb7f7e0447','中秋日虎丘呈庾使東畎先生','施樞','宋','宋诗','song-poetry','','[]','蹇步接輶軒，於山亦有緣。',48,'全唐诗/poet.song.216000.json','["蹇步接輶軒，於山亦有緣。", "劍鋒遺斷石，閣影倒平田。", "紫日穿林暝，黄雲共野連。", "清輝無著處，月伴使星圓。"]'),
('ab09e4c5-156a-4e04-9fd7-029713e10576','清夜','施樞','宋','宋诗','song-poetry','','[]','客身隨取止，一室冷如冰。',48,'全唐诗/poet.song.216000.json','["客身隨取止，一室冷如冰。", "景遠吟何託，情疏夢不曾。", "雨粘初蘚壁，風謝欲花燈。", "豈是無家者，甘爲有髮僧。"]'),
('fbb9bdbe-fac3-4971-a1dc-ba9fa6094171','客中雨思','施樞','宋','宋诗','song-poetry','','[]','細雨粘雲結晚愁，黄金垂地菊錢流。',32,'全唐诗/poet.song.216000.json','["細雨粘雲結晚愁，黄金垂地菊錢流。", "風來不覺窗聲戰，分却覊懷一半秋。"]'),
('337c4fe2-8e9b-45c2-b954-01fc6fe11040','聞鶴','施樞','宋','宋诗','song-poetry','','[]','誰家嘹唳九臯聲，客夢初回曉帳清。',32,'全唐诗/poet.song.216000.json','["誰家嘹唳九臯聲，客夢初回曉帳清。", "華表不知仙路遠，剛隨寒角轉殘更。"]'),
('69e77f45-5a0c-4b21-9451-98c33b687c08','秋夜即事','施樞','宋','宋诗','song-poetry','','[]','斷雨寒雲過暝窗，落桐葉葉是凄凉。',32,'全唐诗/poet.song.216000.json','["斷雨寒雲過暝窗，落桐葉葉是凄凉。", "楚山不入清宵夢，月影蛩聲滿桂薌。"]'),
('87b99808-e872-4e81-b627-b0282efc3b2d','對菊','施樞','宋','宋诗','song-poetry','','[]','欲荒三逕負歸期，魂夢何曾到短籬。',32,'全唐诗/poet.song.216000.json','["欲荒三逕負歸期，魂夢何曾到短籬。", "九辯不歌陶令老，清香還許入誰詩。"]'),
('32441b4e-6985-4867-a125-26da4dc47377','開爐次夕以不禁離抱來訪宏菴挑燈細語漏促忘歸即事有賦時黄澹翁在焉','施樞','宋','宋诗','song-poetry','','[]','客裏情懷不自如，夜深來訪子雲居。',64,'全唐诗/poet.song.216000.json','["客裏情懷不自如，夜深來訪子雲居。", "挑燈細按新翻曲，拂案同看舊架書。", "梧葉敲風蛩砌冷，菊香銷雨鶴庭虛。", "相逢且與開眉笑，莫遣吟邊酒琖疏。"]'),
('7d855924-86ec-4b0c-bfed-e54a337736ab','雪','施樞','宋','宋诗','song-poetry','','[]','只消頃刻便漫漫，人亦求窺造化難。',64,'全唐诗/poet.song.216000.json','["只消頃刻便漫漫，人亦求窺造化難。", "柳外情知非絮落，梅邊誤作有花看。", "朱門合席持杯煖，紫塞分屯坐甲寒。", "慨想英雄當此際，肯分事業與袁安。"]'),
('8f231d0b-1829-4874-b2c2-5e7e6101a7df','賡庾使和毛君玉送墨梅韻','施樞','宋','宋诗','song-poetry','','[]','東風吹上歲寒枝，筆下工夫頗涉奇。',64,'全唐诗/poet.song.216000.json','["東風吹上歲寒枝，筆下工夫頗涉奇。", "此操直應同晚節，有香亦合伴冰姿。", "淡於淺水籠蟾夜，清似疏籬壓雪時。", "春在小窗橫幅裏，調羹深意許誰知。"]'),
('7486764f-1d25-49df-ba0b-4a7f825b4fb8','蠟梅送東畎先生併寓探梅之意','施樞','宋','宋诗','song-poetry','','[]','澤國寒深未見梅，東風何日到南枝。',32,'全唐诗/poet.song.216000.json','["澤國寒深未見梅，東風何日到南枝。", "玉堂應有新消息，恐是人間未得知。"]'),
('0a740130-34d3-4db1-b4e3-e03743cc7982','劍池','施樞','宋','宋诗','song-poetry','','[]','雨壁烟崖翠蘚長，龍泓冷浸斗牛光。',32,'全唐诗/poet.song.216000.json','["雨壁烟崖翠蘚長，龍泓冷浸斗牛光。", "獨憐有水清無底，不洗花池粉膩香。"]'),
('d44e85b0-b973-4998-b529-68d923e6d3fd','生公講臺','施樞','宋','宋诗','song-poetry','','[]','千人湊座雨天花，片石雖頑識當家。',32,'全唐诗/poet.song.216000.json','["千人湊座雨天花，片石雖頑識當家。", "萬境俱空非有相，漫留塵跡與人誇。"]'),
('d9e1d7ef-0670-4b5e-969a-3bc2d113c441','寄陳藏一','施樞','宋','宋诗','song-poetry','','[]','萬人如海亦紛紜，還著江湖有限身。',64,'全唐诗/poet.song.216000.json','["萬人如海亦紛紜，還著江湖有限身。", "題葉恨深波影遠，嚼花吟苦月痕新。", "羨君朝市情俱薄，笑我山林趣未真。", "名勝搜羅能盡否，細論何日許相親。"]'),
('038654bc-9220-43ba-a95b-cbd0819f47ad','送同幕劉正父召試','施樞','宋','宋诗','song-poetry','','[]','合是冰壺寘露寒，果然筆札對金鑾。',64,'全唐诗/poet.song.216000.json','["合是冰壺寘露寒，果然筆札對金鑾。", "雖云經世談何易，謾道憂時事轉難。", "正氣必能回壞證，中流當與障狂瀾。", "熟知議論平如砥，且把清規作樣看。"]'),
('dfd8c1a7-9b82-4b81-9b1e-0855acdf1e33','紹興城隍廟','施樞','宋','宋诗','song-poetry','','["\u592a\u6e56"]','江頭曾夢見，髣髴此山川。',48,'全唐诗/poet.song.216000.json','["江頭曾夢見，髣髴此山川。", "幻說從何證，來游即是緣。", "嫗言前世事，我是太湖仙。", "神理俱冥漠，清香謾致虔。"]'),
('6dd29944-6816-421e-9538-00083c7ad5a5','借張憲韻述懷呈東畎先生','施樞','宋','宋诗','song-poetry','','[]','早起看秋意，山前深未深。',48,'全唐诗/poet.song.216000.json','["早起看秋意，山前深未深。", "水香飄遠渚，晴色上平林。", "風雨一雙鬢，江湖萬里心。", "何期來此地，時作短長吟。"]'),
('09f0cbc2-29da-4856-a0bb-2f4e4a066c45','初泊世綵','施樞','宋','宋诗','song-poetry','','[]','不問蕭條傳舍空，來欹客枕聽西風。',32,'全唐诗/poet.song.216000.json','["不問蕭條傳舍空，來欹客枕聽西風。", "一庭明月無人筦，秋在梧桐落葉中。"]'),
('5d384268-030b-4655-bcb8-acf3744623f9','早起','施樞','宋','宋诗','song-poetry','','[]','簷前鳴玉響丁東，清夢初迴鶴帳中。',32,'全唐诗/poet.song.216000.json','["簷前鳴玉響丁東，清夢初迴鶴帳中。", "早起井梧飄一葉，方知昨夜是秋風。"]'),
('8abf500f-bcef-4dbf-9c21-6033cf77fd91','風雨','施樞','宋','宋诗','song-poetry','','[]','入夏惟憂旱，秋來却浸霪。',48,'全唐诗/poet.song.216000.json','["入夏惟憂旱，秋來却浸霪。", "風聲連海響，山氣與雲深。", "望歲丹心切，憂時白髮侵。", "旅中無別事，隠几自長吟。"]'),
('6a9efd0d-5019-4ad2-93d0-ab2421fe9cf7','禹廟','施樞','宋','宋诗','song-poetry','','[]','衮服嚴常祀，平成萬世功。',48,'全唐诗/poet.song.216000.json','["衮服嚴常祀，平成萬世功。", "圭璋藏道室，弓劍莽幽宮。", "石定今猶在，梅梁事莫窮。", "幽尋須作計，多恨雨匆匆。"]'),
('4b76d094-8686-45d1-96f9-c70d58c95cff','高園  其一','施樞','宋','宋诗','song-poetry','','[]','入門雖較小，中却是壺天。',48,'全唐诗/poet.song.216000.json','["入門雖較小，中却是壺天。", "委曲松篁逕，清新錦繡篇。", "蟠胸有丘壑，隨處是林泉。", "更讀鰲峯句，風流似謫仙。"]'),
('db0d3912-25d6-4c7b-869d-373fdbbe2d1d','高園  其二','施樞','宋','宋诗','song-poetry','','[]','扁名俱不俗，難得此規模。',48,'全唐诗/poet.song.216000.json','["扁名俱不俗，難得此規模。", "一鏡荷香冷，四圍花逕蕪。", "沼寬魚自樂，竹靜鶴同孤。", "倣盡東州景，何須作畫圖。"]'),
('044797d7-39f2-4c49-987b-825d12ec9c42','夢前室','施樞','宋','宋诗','song-poetry','','[]','長夜幾年別，傷哉千古心。',48,'全唐诗/poet.song.216000.json','["長夜幾年別，傷哉千古心。", "自因緣較淺，不是老相侵。", "熊夢如先兆，鸞膠豈續琴。", "曉窗秋葉響，不覺淚盈襟。"]'),
('64a8e458-2c2c-443f-9b1d-9c10c4ca2610','西興寄呈東畎先生','施樞','宋','宋诗','song-poetry','','[]','生平未始識東州，不謂招邀得漫遊。',64,'全唐诗/poet.song.216000.json','["生平未始識東州，不謂招邀得漫遊。", "南鎮門前秦望曉，西興浦口浙江秋。", "風搏怒氣潮初落，山湧青冥雨乍收。", "豈爲登臨重回首，使星只在五雲頭。"]'),
('67ee4ba7-92c4-43b5-ab15-ba662eba2ca4','輪差祝聖所拈香  其一','施樞','宋','宋诗','song-poetry','','[]','瓣薌來謁玉晨宮，月在觚稜絳闕東。',32,'全唐诗/poet.song.216000.json','["瓣薌來謁玉晨宮，月在觚稜絳闕東。", "轉向御街西畔過，朝天萬馬正匆匆。"]'),
('17dfae01-ac48-47cc-a2e2-b3d72d5d9d65','輪差祝聖所拈香  其二','施樞','宋','宋诗','song-poetry','','[]','幾度來游幾賦詩，又因將命到靈芝。',32,'全唐诗/poet.song.216000.json','["幾度來游幾賦詩，又因將命到靈芝。", "三呼祝了君王壽，偷眼湖光立片時。"]'),
('47079e71-cbf6-4596-9d42-aeba762fc6b9','至日謁廟吳山見日初出','施樞','宋','宋诗','song-poetry','','[]','曦龍浴海上扶桑，雲表輝芒燭萬方。',64,'全唐诗/poet.song.216000.json','["曦龍浴海上扶桑，雲表輝芒燭萬方。", "史觀繽紛書瑞色，禁城奕燁鎖祥光。", "從知繡線添紅影，獨喜丹心向太陽。", "節裏官閑無一事，諦觀易道靜焚香。"]'),
('9b97a7c4-006b-4437-a9d4-7cb82cb21000','廨宇傍河彷彿家居','施樞','宋','宋诗','song-poetry','','[]','合是清溪近處居，在官却與在家如。',64,'全唐诗/poet.song.216000.json','["合是清溪近處居，在官却與在家如。", "柳風拂岸時鳴櫓，梅月橫窗夜讀書。", "休問舟閑無喚渡，須知水到自成渠。", "俸錢已足供薪粒，比著簞瓢儘有餘。"]'),
('3eda87a4-32f6-49f8-a157-cd6bc6af3490','昨夜','施樞','宋','宋诗','song-poetry','','[]','昨夜陰風刮地鳴，亂敲窗紙夢魂驚。',64,'全唐诗/poet.song.216000.json','["昨夜陰風刮地鳴，亂敲窗紙夢魂驚。", "壁寒剝落泥成片，屋老漂摇瓦作聲。", "野市霜明人蹟險，官河水冷客舟橫。", "翻思带甲眠戈者，何幸吟身傍帝城。"]'),
('bd40a0b9-d723-4615-9b20-2e151391438b','月夜憶梅花','施樞','宋','宋诗','song-poetry','','[]','夜深寒月照窗紗，忽憶林逋處士家。',32,'全唐诗/poet.song.216000.json','["夜深寒月照窗紗，忽憶林逋處士家。", "鷗鷺正眠烟樹冷，不知誰可伴梅花。"]'),
('832860c4-7d68-4c7d-ad83-f87a55452062','生朝報恩夜醮','施樞','宋','宋诗','song-poetry','','[]','絳節翩翩七寶車，謠歌飛上玉皇家。',32,'全唐诗/poet.song.216000.json','["絳節翩翩七寶車，謠歌飛上玉皇家。", "鶴壇月冷天風靜，開盡碧桃無限花。"]'),
('e65221a8-6e84-4528-803b-da93f7b80fc9','菊潭賦小窗睡香次韻','施樞','宋','宋诗','song-poetry','','[]','兀兀蒲團萬慮除，定回寒月滿康廬。',32,'全唐诗/poet.song.216000.json','["兀兀蒲團萬慮除，定回寒月滿康廬。", "幽香自有禪心會，春不相知亦任渠。"]'),
('3696bbb9-ded6-404b-8535-4bfba5d3b429','夜聞城中簫鼓','施樞','宋','宋诗','song-poetry','','[]','簫鼓喧天競看燈，都民應喜見昇平。',32,'全唐诗/poet.song.216000.json','["簫鼓喧天競看燈，都民應喜見昇平。", "芳心自不同年少，細嚼梅花坐月明。"]'),
('5cbf8ac4-5f3d-4eb2-8bec-581933e3b1f6','和東圃鄭震見寄','施樞','宋','宋诗','song-poetry','','[]','薄宦來京洛，相逢久更親。',48,'全唐诗/poet.song.216000.json','["薄宦來京洛，相逢久更親。", "丹心期爲國，白髮易催人。", "月冷烏驚夜，霜明鷄喚晨。", "呤邊頻自感，還染九衢塵。"]'),
('dea53f0b-6062-4eec-944d-6656907c1aed','題桃源圖','施樞','宋','宋诗','song-poetry','','[]','山中與世不相關，鷄犬桑麻盡日閑。',32,'全唐诗/poet.song.216000.json','["山中與世不相關，鷄犬桑麻盡日閑。", "傍水桃花春爛熳，誤傳消息到人間。"]'),
('41c329f1-a4aa-447c-87cc-5359372cb71f','和菊潭玉泉韻','施樞','宋','宋诗','song-poetry','','[]','不是靈源透碧虛，可容六六化龍魚。',32,'全唐诗/poet.song.216000.json','["不是靈源透碧虛，可容六六化龍魚。", "講經人去前湖暝，翻手爲霖自有餘。"]'),
('813e36eb-9bab-4423-b896-12edb6ff1b9d','酬瓜疇趙鑪夫投贈','施樞','宋','宋诗','song-poetry','','[]','謀生百拙世無如，贏得心清剩讀書。',64,'全唐诗/poet.song.216000.json','["謀生百拙世無如，贏得心清剩讀書。", "薄宦喜從京國路，閑身還似野人居。", "濟川事業歸商傅，獻賦聲名羨子虛。", "歲晚且留梅作伴，吟邊月冷一枝疏。"]'),
('ba84b4ec-df74-45d0-8d85-2cce37537d1d','仲孚歲晚書懷因次其韻','施樞','宋','宋诗','song-poetry','','[]','終有徵書訪綺園，心期獨向老天言。',32,'全唐诗/poet.song.216000.json','["終有徵書訪綺園，心期獨向老天言。", "物情已逐東風轉，未必全歸野燒痕。"]'),
('052db90b-25ed-46b5-a1a5-01c784c1b1cf','端平除夕','施樞','宋','宋诗','song-poetry','','[]','宦游來此亦隨緣，過了新冬又餽年。',64,'全唐诗/poet.song.216000.json','["宦游來此亦隨緣，過了新冬又餽年。", "今夕桃符猶自寫，明朝柏酒讓誰先。", "但令世道皆平地，此外身名任老天。", "春與詩家如有意，早傳清夢謝池邊。"]'),
('2f1602cb-a67d-4d8b-b79c-865ad18b044e','嘉熙元日','施樞','宋','宋诗','song-poetry','','[]','先春一日紀正元，熙號初更氣候暄。',64,'全唐诗/poet.song.216000.json','["先春一日紀正元，熙號初更氣候暄。", "萬象光隨黄道轂，千官班湊紫宸門。", "梅迎霽色來窗底，柳挽和風到水根。", "但願時平年事好，升湛有命不須論。"]'),
('bb064f5d-7a7b-4a61-9baa-82da4d8646d3','立春','施樞','宋','宋诗','song-poetry','','[]','彩勝飄春上鬢蓬，倚欄一笑問東風。',32,'全唐诗/poet.song.216000.json','["彩勝飄春上鬢蓬，倚欄一笑問東風。", "青青柳眼梅花面，纔染陽和便不同。"]'),
('7fd73ce5-8e83-4cc7-8a1b-737064e08670','雨後道間見紅梅','施樞','宋','宋诗','song-poetry','','[]','玄都境界玉堂身，輕裊湘裙步曉陰。',32,'全唐诗/poet.song.216000.json','["玄都境界玉堂身，輕裊湘裙步曉陰。", "昨夜雨肥添酒暈，紅情染得十分深。"]'),
('071f6578-7ffe-4e48-b838-fe3541e46140','盆梅','施樞','宋','宋诗','song-poetry','','[]','白玉堂前樹，誰移此地栽。',48,'全唐诗/poet.song.216000.json','["白玉堂前樹，誰移此地栽。", "看教清意足，喚得艷陽回。", "舞片疑雲墮，留香待月來。", "只應標格好，獨爲歲寒開。"]'),
('27b39df2-66f7-45e4-b8f2-b7e323ba00dd','春雪','施樞','宋','宋诗','song-poetry','','[]','臘裏霏微未許多，春來舞片却交叉。',64,'全唐诗/poet.song.216000.json','["臘裏霏微未許多，春來舞片却交叉。", "混成天地皆同色，點染園林盡著花。", "岸蹟雲凝迷去鷺，屋頭烟煖見饑鴉。", "東風畢竟能融化，不放寒澌冰柳芽。"]'),
('6ca091ac-88bd-45f1-82f0-c4bb89c4005f','再雪','施樞','宋','宋诗','song-poetry','','[]','投曉又翻飛，春風亦被欺。',48,'全唐诗/poet.song.216000.json','["投曉又翻飛，春風亦被欺。", "須知寒徹夜，勝似臘殘時。", "艷粉同梅落，輕花替柳吹。", "渾然成片玉，凍合在前池。"]'),
('8801f2b5-e87f-4c48-9160-7f53e4383407','題龍首圖','施樞','宋','宋诗','song-poetry','','[]','變化成來體勢高，坐令幽思起雲濤。',32,'全唐诗/poet.song.216000.json','["變化成來體勢高，坐令幽思起雲濤。", "春雷一鼓驚頭角，碧海風輕衮絳桃。"]'),
('c4289ab8-aaaf-4c62-820b-3670971232bc','落梅','施樞','宋','宋诗','song-poetry','','[]','粉香銷盡骨猶清，望斷瑶臺轉有情。',32,'全唐诗/poet.song.216000.json','["粉香銷盡骨猶清，望斷瑶臺轉有情。", "便是百花無此分，看看事業到和羹。"]'),
('b13af320-fa40-41d1-a160-46fe984a4a1b','桃花','施樞','宋','宋诗','song-poetry','','[]','武陵人去水橫陳，獨向玄都管領春。',32,'全唐诗/poet.song.216000.json','["武陵人去水橫陳，獨向玄都管領春。", "日暖風輕塵撲面，劉郎空老苦吟身。"]'),
('2a0e987f-2672-4c9f-812a-fedbbf6e91d7','宿接待寺','施樞','宋','宋诗','song-poetry','','[]','梵境忽巍峩，門前對市河。',48,'全唐诗/poet.song.216000.json','["梵境忽巍峩，門前對市河。", "有心弘誓願，於此接經過。", "郭近人聲雜，簷高雨氣多。", "規摹踰百載，猶說喻彌陀。"]'),
('e783609d-d7e4-4d90-8d47-8c89a2d75bff','宿龍泉寺','施樞','宋','宋诗','song-poetry','','[]','既濟功成列左玄，餘波猶作世間泉。',32,'全唐诗/poet.song.216000.json','["既濟功成列左玄，餘波猶作世間泉。", "苔荒碧甃龍宮寂，庭老梅花月在天。"]'),
('01f7c44b-d5b0-4dd1-a028-2b7685ed33bc','橫瀆岸邊梅花方開  其一','施樞','宋','宋诗','song-poetry','','[]','雪染梅花倚道傍，亭亭野水弄幽芳。',32,'全唐诗/poet.song.216000.json','["雪染梅花倚道傍，亭亭野水弄幽芳。", "東風似賞孤高意，未許飄零一片香。"]'),
('2b440faf-dbc9-480f-b0bc-52c552a85bf4','橫瀆岸邊梅花方開  其二','施樞','宋','宋诗','song-poetry','','[]','竹籬茅舍本相安，誰與移根入畫欄。',32,'全唐诗/poet.song.216000.json','["竹籬茅舍本相安，誰與移根入畫欄。", "儘道重簾妨暖日，疎枝却得護春寒。"]'),
('835185b5-fada-44bc-a90d-a23acdcf212e','橫瀆岸邊梅花方開  其三','施樞','宋','宋诗','song-poetry','','[]','風標夐與萬花殊，可有塵埃染得渠。',32,'全唐诗/poet.song.216000.json','["風標夐與萬花殊，可有塵埃染得渠。", "把住瓊枝相晤語，只疑身在玉堂居。"]'),
('2f45c782-62eb-427f-9b2c-18cc42db2f4b','雙路','施樞','宋','宋诗','song-poetry','','[]','王命驅馳不敢輕，文書要覈去來情。',64,'全唐诗/poet.song.216000.json','["王命驅馳不敢輕，文書要覈去來情。", "青山步步生幽意，碧澗悠悠趁遠程。", "春淺禽聲猶自小，泥酥馬蹟正宜晴。", "地名見說名雙路，便舍崎嶇就坦平。"]'),
('c757fead-3e96-4f6c-bb63-82d8d035c236','實際窗前睡香','施樞','宋','宋诗','song-poetry','','[]','瑞錦窠應對錦郎，誰將靈種到幽坊。',32,'全唐诗/poet.song.216000.json','["瑞錦窠應對錦郎，誰將靈種到幽坊。", "山深月冷梅花老，壓盡群英是此香。"]'),
('22d57305-cb91-4e62-a14a-78a273c8cded','石橋接待  其一','施樞','宋','宋诗','song-poetry','','[]','當年立雪直齊腰，宗旨流傳到石橋。',32,'全唐诗/poet.song.216000.json','["當年立雪直齊腰，宗旨流傳到石橋。", "風急窗寒燈影遠，疏梅無語夜薌銷。"]'),
('f61ffdbc-467d-4cda-9ae7-0966d2e7ec33','石橋接待  其二','施樞','宋','宋诗','song-poetry','','[]','手筆華嚴梵笈新，更開寶地接迷津。',32,'全唐诗/poet.song.216000.json','["手筆華嚴梵笈新，更開寶地接迷津。", "一聲金磬人初靜，月照空山草自春。"]'),
('f8313b47-963a-4198-878b-64d2dc76a200','聞寺中曉鼓','施樞','宋','宋诗','song-poetry','','[]','靈鼉一鼓振潮音，征夢迢遥枕畔聞。',32,'全唐诗/poet.song.216000.json','["靈鼉一鼓振潮音，征夢迢遥枕畔聞。", "語斷頻伽天正曉，松風吹散滿山雲。"]'),
('4448c733-a554-4e90-977a-65c74c2eee10','跨水道間','施樞','宋','宋诗','song-poetry','','[]','店舍總迢遥，山深轉寂寥。',48,'全唐诗/poet.song.216000.json','["店舍總迢遥，山深轉寂寥。", "看鷗臨遠水，下馬過危橋。", "晴雪林間少，春風野外饒。", "此行爲王事，旅食任蕭條。"]'),
('30e4131e-2266-4326-bd5c-da3538b5a733','峮山舖','施樞','宋','宋诗','song-poetry','','[]','未說路行難，山深分外寒。',48,'全唐诗/poet.song.216000.json','["未說路行難，山深分外寒。", "晚村林隠寺，春磵石鳴灘。", "薄宦曾無補，勞生敢自安。", "羽書雖較少，備禦莫教寬。"]'),
('6b8c019e-6ced-4cca-a198-632776f2ff79','杏塘','施樞','宋','宋诗','song-poetry','','[]','境接江東界，郵程是杏塘。',48,'全唐诗/poet.song.216000.json','["境接江東界，郵程是杏塘。", "雨喧茅屋小，泥滑草橋長。", "曠野人稀少，平田水渺茫。", "半生遊歷地，未若此荒凉。"]'),
('888a60e2-9a60-4e57-89bc-a7813258bed6','四安梵惠藏殿','施樞','宋','宋诗','song-poetry','','[]','劫火不能焚，空中轉法輪。',48,'全唐诗/poet.song.216000.json','["劫火不能焚，空中轉法輪。", "風霜鴟殿古，金碧貝函塵。", "物本由成數，人言不壞身。", "却憐無問者，遺蹟竟成陳。"]'),
('41cecd42-03c5-4d92-b718-3ee1b96e95ee','上司諫曹先生','施樞','宋','宋诗','song-poetry','','[]','聲名滿世重於山，果見延登左掖班。',64,'全唐诗/poet.song.216000.json','["聲名滿世重於山，果見延登左掖班。", "天子虛心求國是，先生著手濟時艱。", "要看出處諸公上，只在精神一轉間。", "前此極言雖引去，安危理亂正相關。"]'),
('dc553104-e46b-481b-9526-eeafa641089c','池萍','施樞','宋','宋诗','song-poetry','','[]','一番雨過一番多，間挾晴風漲綠波。',32,'全唐诗/poet.song.216000.json','["一番雨過一番多，間挾晴風漲綠波。", "柳絮吹殘游蹟在，謝池點點是陽和。"]'),
('137222b4-e7d6-4864-88f0-99e9e12f1952','分賦楊花','施樞','宋','宋诗','song-poetry','','[]','纖腰睡起芳情足，誰道春風浪拘束。',32,'全唐诗/poet.song.216000.json','["纖腰睡起芳情足，誰道春風浪拘束。", "日暮天涯細草多，輕飛誤入闌干曲。"]'),
('35871aa9-d63c-47e5-8e83-bbe6eb0e58ba','雨吟','施樞','宋','宋诗','song-poetry','','[]','園林綠盡合清和，猶有餘寒在薄羅。',64,'全唐诗/poet.song.216000.json','["園林綠盡合清和，猶有餘寒在薄羅。", "幾縷情風春別柳，一庭苦雨夜鳴莎。", "人於生處窮通定，事到難時感悟多。", "水上浮漚頻起滅，看來物理總由他。"]'),
('1eb3c407-4757-4eab-8e41-f9fdac5883ff','夜坐有感','施樞','宋','宋诗','song-poetry','','[]','不爲名所累，應是得安居。',48,'全唐诗/poet.song.216000.json','["不爲名所累，應是得安居。", "客夢方知幻，身謀反似疏。", "風高秋塞遠，雨急夜窗虛。", "猶望收來效，頻翻舊讀書。"]'),
('1fb7e086-9112-4139-8fed-d99ef08b99cd','送黄溱遊金陵','施樞','宋','宋诗','song-poetry','','[]','六朝多舊事，誰與問江山。',48,'全唐诗/poet.song.216000.json','["六朝多舊事，誰與問江山。", "我亦身重到，材疏語竟慳。", "燕歸秋巷靜，鷺去晚洲閑。", "健筆無輕賦，前賢轍可攀。"]'),
('b7b08942-37b7-4361-9d00-7067c37afda7','酬山月江與投贈','施樞','宋','宋诗','song-poetry','','[]','帝里風光好，隨緣適宦情。',48,'全唐诗/poet.song.216000.json','["帝里風光好，隨緣適宦情。", "却居城郭外，不雜市廛聲。", "水國霜天冷，梅庭夜月清。", "正慚無雅韻，敢說到詩名。"]'),
('5c617bb3-cbc5-41be-874b-e8182647903c','和陸明叟','施樞','宋','宋诗','song-poetry','','[]','了無閑事上眉纖，一炷清薌靜晝簾。',64,'全唐诗/poet.song.216000.json','["了無閑事上眉纖，一炷清薌靜晝簾。", "造化自從回暖律，芬華頓覺轉窮簷。", "輕風度柳春情薄，細雨催花土脈黏。", "所愧微官相束縛，何因共訪酒家帘。"]'),
('9fd42eea-802d-41f5-8db3-219433f48bbd','夜窗聽雨','施樞','宋','宋诗','song-poetry','','[]','一炷夜香清，挑燈聽雨聲。',48,'全唐诗/poet.song.216000.json','["一炷夜香清，挑燈聽雨聲。", "雖然添客夢，却可助詩情。", "澤沁蘭心重，泥酥笋角萌。", "山行頻有約，日日候晴明。"]'),
('f2e8dbc7-84ce-49f9-ba5d-f0654053ce11','破榴','施樞','宋','宋诗','song-poetry','','[]','蜂殻盈盈萬顆珠，潤於瑪瑙浸冰壺。',32,'全唐诗/poet.song.216000.json','["蜂殻盈盈萬顆珠，潤於瑪瑙浸冰壺。", "吟心先自清如水，嚼了寒霜骨更臞。"]'),
('cec902d6-efbb-425a-85d4-84b498908f48','登應天塔','施樞','宋','宋诗','song-poetry','','[]','雲級湧青冥，金鰲載寶輪。',48,'全唐诗/poet.song.216000.json','["雲級湧青冥，金鰲載寶輪。", "地高心自逸，天近足無塵。", "圖畫千峰晚，樓臺萬井春。", "三生許元度，曾此證前身。"]'),
('ce9d07ad-8129-491e-80ac-6b70326fc21e','鰻井','施樞','宋','宋诗','song-poetry','','[]','人言此井有靈源，潮落潮生透海門。',32,'全唐诗/poet.song.216000.json','["人言此井有靈源，潮落潮生透海門。", "陵谷未須窮變易，朱廧裏是濮王園。"]'),
('bc02173e-9230-4b7d-bf54-ce7f03a1d767','大能仁寺','施樞','宋','宋诗','song-poetry','','[]','規模應甲剎，殿閣擁金僊。',48,'全唐诗/poet.song.216000.json','["規模應甲剎，殿閣擁金僊。", "歲歉炊烟絕，城低野色連。", "客僧皆散去，主者獨安眠。", "成毀難逃數，山門八百年。"]'),
('1cf03e7c-920a-4474-ad46-199b5f01461a','留滯','施樞','宋','宋诗','song-poetry','','[]','何期蹤蹟又遲留，行止於人自不由。',64,'全唐诗/poet.song.216000.json','["何期蹤蹟又遲留，行止於人自不由。", "夢境固知空似蟻，生涯却笑拙如鳩。", "碧涵一鏡晴天闊，翠湧千峰宿雨收。", "從此公餘須杖屨，未應草草度春休。"]'),
('782fe024-7049-4646-883c-96863de9d465','曉寒','施樞','宋','宋诗','song-poetry','','[]','曲曲屏山憶夢中，峭寒成陣入簾櫳。',32,'全唐诗/poet.song.216000.json','["曲曲屏山憶夢中，峭寒成陣入簾櫳。", "宿香銷盡金猊冷，一樹梅花怯曉風。"]'),
('445a3e64-57a4-4d29-b787-8cae4c15a4c7','晚思','施樞','宋','宋诗','song-poetry','','[]','客思悠悠幸自安，亦因吟事可相寬。',32,'全唐诗/poet.song.216000.json','["客思悠悠幸自安，亦因吟事可相寬。", "小窗過了廉纖雨，細與東風說晚寒。"]'),
('f8740fb2-8c99-4214-96d9-8d0b98d7b22a','用明叟韻併寓山行未成之意','施樞','宋','宋诗','song-poetry','','[]','久客住蘭亭，心同晉水清。',48,'全唐诗/poet.song.216000.json','["久客住蘭亭，心同晉水清。", "忘機盟宿鷺，伐木聽雛鶑。", "物亦知人意，春寧有世情。", "幽尋空作計，一夜雨連明。"]'),
('d47594b4-cadc-4cb8-a0d9-1c165c7de1a7','苦雨','施樞','宋','宋诗','song-poetry','','[]','何期一雨成三日，約客行山竟未能。',64,'全唐诗/poet.song.216000.json','["何期一雨成三日，約客行山竟未能。", "春到分時陰不解，夜當深處氣猶凝。", "簷低捲箔看飄灑，礎潤添香散鬰蒸。", "想見故園梅落盡，和羹消息又堪憑。"]'),
('9e91003b-8457-4de7-8722-7da8fad7f3b2','雨中用雪坡韻','施樞','宋','宋诗','song-poetry','','[]','無計酬春獨有詩，倚欄終日候晴暉。',32,'全唐诗/poet.song.216000.json','["無計酬春獨有詩，倚欄終日候晴暉。", "東風漸屬新桃李，簾幕深深燕子飛。"]'),
('f934f5e6-5122-4f6e-ae13-54b61f4d7dce','雪坡以雨阻山行有詩因亦次韻','施樞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','爲欲看山助眼明，頻占鵲喜報新晴。',64,'全唐诗/poet.song.216000.json','["爲欲看山助眼明，頻占鵲喜報新晴。", "春光已過三之一，塵世難逢四者并。", "詩酒深情殊未適，肴蔬薄具亦頻更。", "終來不似西湖好，晴雨皆堪傍柳行。"]'),
('26ce35c8-2379-461d-bcbe-e5049161e4c6','月丹','施樞','宋','宋诗','song-poetry','','[]','靈種飛來鶴頂紅，誰云九轉有仙功。',32,'全唐诗/poet.song.216000.json','["靈種飛來鶴頂紅，誰云九轉有仙功。", "廣庭曾侍東風宴，留得霞杯照晚叢。"]'),
('776495e6-b326-420d-b003-d919e59b324d','禹廟','施樞','宋','宋诗','song-poetry','','[]','且要盡清歡，須知一出難。',48,'全唐诗/poet.song.216000.json','["且要盡清歡，須知一出難。", "人因晴後喜，春到水邊寬。", "柳長官橋媚，梅飄客袖寒。", "荒祠存禹跡，得得又來看。"]'),
('29511eb9-cc9a-4c62-b432-605fc9acb425','鏡湖一曲','施樞','宋','宋诗','song-poetry','','[]','天與平湖老賀郎，春波依舊染晴光。',32,'全唐诗/poet.song.216000.json','["天與平湖老賀郎，春波依舊染晴光。", "可憐千載風流意，付與租符曉夕忙。"]'),
('aee934de-d130-4ec5-82f0-cd5ce82eac7e','用雪坡春色韻','施樞','宋','宋诗','song-poetry','','[]','纔出城門興便濃，晴光野色兩俱融。',64,'全唐诗/poet.song.216000.json','["纔出城門興便濃，晴光野色兩俱融。", "柳方染得三分綠，桃已熏成一半紅。", "山湧林巒荒寺隠，湖分港汊小舟通。", "相携各自論年事，幾度春風上鬢蓬。"]'),
('fd82fd79-9d3e-45e7-97ed-d04c37ef3894','用梅溪鏡湖韻','施樞','宋','宋诗','song-poetry','','[]','畎畝鏡中分，滄波雜斷雲。',48,'全唐诗/poet.song.216000.json','["畎畝鏡中分，滄波雜斷雲。", "向來官裏賜，今屬野人耘。", "懷古天難問，貪吟日易曛。", "羽衣遺傳本，起誦想餘芬。"]'),
('28a63047-e8b4-4a15-bb91-8fe319cf04e9','天基瑞應宮','施樞','宋','宋诗','song-poetry','','[]','金碧耀瓊廬，天開繞電區。',48,'全唐诗/poet.song.216000.json','["金碧耀瓊廬，天開繞電區。", "烏流周室瑞，蛇斷漢家符。", "石井騰曦馭，瑶壇布斗樞。", "願將皇極福，敷錫遍康衢。"]'),
('febaa673-580c-47b2-89be-148ffc5d855a','送東浦張應發歸永嘉','施樞','宋','宋诗','song-poetry','','[]','客裏偶相逢，襟懷亦偶同。',48,'全唐诗/poet.song.216000.json','["客裏偶相逢，襟懷亦偶同。", "對梅吟夜月，折柳問春風。", "子勿言浮梗，余方笑轉蓬。", "歸程經雁蕩，得句附郵筒。"]'),
('e4ceaaf4-e6e2-4456-8191-d12fe9658755','碧桃','施樞','宋','宋诗','song-poetry','','[]','月浸虛庭夜未央，一枝靜對白雲鄉。',32,'全唐诗/poet.song.216000.json','["月浸虛庭夜未央，一枝靜對白雲鄉。", "三生自結玄都約，來伴疎梅到玉堂。"]'),
('ff09a68e-094b-4898-a925-910b10bcb518','一春屢有陽明之約雨輒尼之將旋幕侍外舅來游解后二羽衣一能參上道一能知大丹竟日留話喜賦二解時清明日也  其一','施樞','宋','宋诗','song-poetry','','[]','幾有行山約，山靈聖得知。',48,'全唐诗/poet.song.216000.json','["幾有行山約，山靈聖得知。", "仙家寧易到，塵世亦何爲。", "草潤非烟石，花流止水池。", "不晴還不雨，正是賣餳時。"]'),
('bb20afeb-3b62-4f5a-8da1-4294ec8d5fe1','一春屢有陽明之約雨輒尼之將旋幕侍外舅來游解后二羽衣一能參上道一能知大丹竟日留話喜賦二解時清明日也  其二','施樞','宋','宋诗','song-poetry','','[]','裂石未嘗關，毋將俗眼觀。',48,'全唐诗/poet.song.216000.json','["裂石未嘗關，毋將俗眼觀。", "虛中元有受，造藴亦何難。", "羽客能談道，雲房識候丹。", "只應仙有分，風響步虛壇。"]'),
('2d8cb5b2-e3c1-45c0-ac0d-c4213a9ecb60','道間見桃李花','施樞','宋','宋诗','song-poetry','','[]','東風到處競繁華，不問窮簷與大家。',32,'全唐诗/poet.song.216000.json','["東風到處競繁華，不問窮簷與大家。", "垂柳絲中深院宇，隔廧時有出來花。"]'),
('57355b43-4de9-4d27-84b9-899e54442805','龍瑞宮側訪仙姑不值','施樞','宋','宋诗','song-poetry','','[]','輕紅片片落桃花，劉阮空迎紫鳳車。',32,'全唐诗/poet.song.216000.json','["輕紅片片落桃花，劉阮空迎紫鳳車。", "石洞有天元不閉，何須流水覓胡麻。"]'),
('46a1220e-e113-4f5e-9791-3007ec8907ac','送妻叔歸括','施樞','宋','宋诗','song-poetry','','[]','此身元是客，還作送行詩。',48,'全唐诗/poet.song.216000.json','["此身元是客，還作送行詩。", "笑語如今度，綢繆似舊時。", "買舡春載酒，剪燭夜枰棋。", "烟雨樓前景，圖來慰所思。"]'),
('d9bdef8e-79e6-4f4e-8316-72bf5bac63a5','出西門寄呈外舅姑','施樞','宋','宋诗','song-poetry','','[]','自從依監宅，不似□時親。',48,'全唐诗/poet.song.216000.json','["自從依監宅，不似□時親。", "義重難爲別，情同久更真。", "一簫思去鳳，雙璧倚靈椿。", "只等中除報，相迎輦路塵。"]'),
('eb6d77e7-c8a5-4e3c-9b67-e8bdde631e53','唐園','施樞','宋','宋诗','song-poetry','','[]','幽居已似水中仙，更有亭臺在屋邊。',32,'全唐诗/poet.song.216000.json','["幽居已似水中仙，更有亭臺在屋邊。", "擬作小圖難畫處，一年兩駐內家舡。"]'),
('3232bfdf-6b21-41e8-8c6d-1f4d004bc5bb','覺苑寺','施樞','宋','宋诗','song-poetry','','[]','此是詞人宅，名因後世傳。',48,'全唐诗/poet.song.216000.json','["此是詞人宅，名因後世傳。", "驛中存廢井，橋下駐歸舡。", "一夢空塵蹟，千年尚福田。", "筆靈應賸馥，試爲酌清泉。"]'),
('894aaac3-5f27-4c73-8ebf-bf87ad712573','祇園寺許詢舊宅有戚公水','施樞','宋','宋诗','song-poetry','','[]','應天曾建塔，又此結精廬。',48,'全唐诗/poet.song.216000.json','["應天曾建塔，又此結精廬。", "釋氏緣何熟，詩人念總疏。", "壁荒遺畫水，僧老學醫書。", "笑我重來者，經年不定居。"]'),
('1254b56e-d886-4828-af45-4dd0d0fdb303','奉和龜翁送別','施樞','宋','宋诗','song-poetry','','[]','爲說吟邊事，曾陪讌笑頻。',48,'全唐诗/poet.song.216000.json','["爲說吟邊事，曾陪讌笑頻。", "自慚無韻者，敢對有名人。", "雨洗秦山曉，波明鏡水春。", "匆匆還別去，芳草正如茵。"]'),
('8d47af58-3c3c-4982-bd7a-1188d9bb03f0','蕭山望城中遺漏','施樞','宋','宋诗','song-poetry','','[]','見說天文變，頻占太史臺。',48,'全唐诗/poet.song.216000.json','["見說天文變，頻占太史臺。", "但云星犯月，不料火爲災。", "盡夜看烟滅，逢人問訊來。", "丹心勤戀闕，東鄉極裴回。"]'),
('a2c59d6c-be58-4a7c-b4ae-72d696460266','喚渡旋幕','施樞','宋','宋诗','song-poetry','','[]','半載蓬萊地，相携只是詩。',48,'全唐诗/poet.song.216000.json','["半載蓬萊地，相携只是詩。", "心懷丹鳳去，夢與白鷗隨。", "俯仰俱無愧，勤勞必有知。", "歸舟平似掌，天亦念孤危。"]'),
('322e6369-9ad7-444b-9324-5d46d89b919b','玉蕈','施樞','宋','宋诗','song-poetry','','[]','幸從腐木出，敢被齒牙和。',48,'全唐诗/poet.song.216000.json','["幸從腐木出，敢被齒牙和。", "真有山林味，難教世俗知。", "香痕浮玉葉，生意滿瓊枝。", "饕腹何多幸，相酬獨有詩。"]'),
('e7f25724-4ca3-4e22-a387-8ee8b99f6087','大滌洞','施樞','宋','宋诗','song-poetry','','[]','玄蓋天中萬象垂，洞門無鑰許人窺。',32,'全唐诗/poet.song.216000.json','["玄蓋天中萬象垂，洞門無鑰許人窺。", "仙蹤直與華陽接，能繼玄同有阿誰。"]'),
('5c89b1cb-8030-4df6-8b44-c6515ef4f4d5','天柱峰','施樞','宋','宋诗','song-poetry','','[]','擎天一柱鎖崖嵬，六洞烟雲亦異哉。',32,'全唐诗/poet.song.216000.json','["擎天一柱鎖崖嵬，六洞烟雲亦異哉。", "更有泉飛漱寒玉，不妨頻爲此山來。"]'),
('85714590-7125-4d24-abd6-4d65ff50024f','雲根石','施樞','宋','宋诗','song-poetry','','[]','溶溶聚散霎時間，豈有根株在世凡。',32,'全唐诗/poet.song.216000.json','["溶溶聚散霎時間，豈有根株在世凡。", "料是從龍歸洞穴，故應化作此巉巖。"]'),
('cfc06d41-fd6c-4386-ac60-3b2a86a0aa68','無骨箬','施樞','宋','宋诗','song-poetry','','[]','功成歸去作飛仙，箬下遺丹不浪傳。',32,'全唐诗/poet.song.216000.json','["功成歸去作飛仙，箬下遺丹不浪傳。", "千載豈皆無遇者，要須種植驗前緣。"]'),
('f7093ade-c788-4f90-a395-1d92c5be7398','雷崖屋','施樞','宋','宋诗','song-poetry','','[]','不徒卓屋在巖阿，前後丹成亦已多。',32,'全唐诗/poet.song.216000.json','["不徒卓屋在巖阿，前後丹成亦已多。", "三十餘年勤累行，幾時跨鶴上空歌。"]'),
('ab9e1e65-3d48-4a09-a446-47ca88364fa0','飛玉亭','施樞','宋','宋诗','song-poetry','','[]','素練飛來衮雪毬，滿懷風露不勝秋。',32,'全唐诗/poet.song.216000.json','["素練飛來衮雪毬，滿懷風露不勝秋。", "翠蛟已是天然景，今日還當避一頭。"]'),
('627c47d1-8730-4b24-926a-d6c5d3261b2e','句','施樞','宋','宋诗','song-poetry','','[]','刺分玉蛹堆盤脆，嚼破冰蠶繞齒凉。',16,'全唐诗/poet.song.216000.json','["刺分玉蛹堆盤脆，嚼破冰蠶繞齒凉。"]'),
('a3e2e1bc-bfec-4b76-a495-d99b344322bc','仙水廟','林雲','宋','宋诗','song-poetry','','[]','天風吹我上瑶臺，滿眼煙霞掃不開。',64,'全唐诗/poet.song.216000.json','["天風吹我上瑶臺，滿眼煙霞掃不開。", "藥竈無丹人已去，洞霄有樹鶴還來。", "溪聲晴带三秋雨，山色青無半點埃。", "更愛夜深清夢斷，碧紗明月映蒼苔。"]'),
('bbd9a892-76f9-4f3e-8db3-c888ad28b68e','洪山','韓伯修','宋','宋诗','song-poetry','','[]','壁立東南第一峯，問知名道葛仙翁。',64,'全唐诗/poet.song.216000.json','["壁立東南第一峯，問知名道葛仙翁。", "丹砂竈逼雲頭近，玉井泉流海眼通。", "六字籀文天篆刻，數間洞屋石帡幪。", "我來整屐層巔上，無數羣山立下風。"]'),
('5fa0de2b-ab24-462b-bd86-037f06c725b3','梅花坡','韓伯修','宋','宋诗','song-poetry','','[]','休問桃源路，尋梅蹔往還。',24,'全唐诗/poet.song.216000.json','["休問桃源路，尋梅蹔往還。", "梅花有知己，何必定湖山。"]'),
('b329ad64-f6b7-4ead-b0a2-55b6af66d9b7','江上別友人','薛師傳','宋','宋诗','song-poetry','','[]','秋江涓涓帆亂飛，秋山皎皎含斜暉。',48,'全唐诗/poet.song.216000.json','["秋江涓涓帆亂飛，秋山皎皎含斜暉。", "君趁江流去已遠，立對青山不忍歸。", "知君不惜南來信，只恐衡陽雁足稀。"]'),
('7743c6db-0152-4f9a-956d-45a936dffd7b','六橋閑步  其一','薛師傳','宋','宋诗','song-poetry','','[]','出郭青岑近，臨流白鳥飛。',48,'全唐诗/poet.song.216000.json','["出郭青岑近，臨流白鳥飛。", "笙歌春雨歇，草樹夕陽微。", "山色邀藜杖，湖風颭葛衣。", "虛亭林處士，不見鶴來歸。"]'),
('c52b7328-92e6-4e8c-986f-bd5d99ef9914','六橋閑步  其二','薛師傳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','向晚西湖路，煙霞淡水汀。',48,'全唐诗/poet.song.216000.json','["向晚西湖路，煙霞淡水汀。", "垂楊拂波綠，芳草幔隄青。", "地僻漁樵聚，山深殿閣扃。", "平生卜投老，夢寐有南屏。"]'),
('b34666db-6518-4b6d-9da4-ffba8d0d6f3a','支提禪寺','黄履翁','宋','宋诗','song-poetry','','[]','福地由來此最幽，翠微深鎖碧山頭。',64,'全唐诗/poet.song.216000.json','["福地由來此最幽，翠微深鎖碧山頭。", "參差梵閣雲常護，隠現神燈夜不收。", "面壁幾人曾入定，摩崖有客記同遊。", "從今悟道支提處，知是名高十二樓。"]'),
('342d4878-2868-4eca-9d08-feb4ecbfa634','挽胡季昭','林經德','宋','宋诗','song-poetry','','[]','扶植綱常抗直聲，白頭不憚嶺南行。',64,'全唐诗/poet.song.216000.json','["扶植綱常抗直聲，白頭不憚嶺南行。", "書云惟孝友兄弟，臣罪當誅王聖明。", "削籍投荒從寶慶，陟階錄後頼端平。", "朝家賜謚今方舉，凜凜孤忠死亦生。"]'),
('ac406ebc-249a-4b8a-9e7a-470baa22a408','馬冠山','楊諄','宋','宋诗','song-poetry','','[]','陳家宅廢桑畦暗，馬道冠亡羽觀空。',32,'全唐诗/poet.song.216000.json','["陳家宅廢桑畦暗，馬道冠亡羽觀空。", "惟有山南古程氏，雕簷一簇翠煙中。"]'),
('e0a78b2a-9a9d-4795-82f5-872ab5e31075','九日山送客次趙循州韻','趙崇皦','宋','宋诗','song-poetry','','[]','蒼松藏野寺，山以隠君靈。',48,'全唐诗/poet.song.216000.json','["蒼松藏野寺，山以隠君靈。", "俛仰千年事，孤高九日亭。", "抗塵頭漸白，弔古眼猶青。", "有客耽幽討，吟情起鶴汀。"]'),
('f0872839-bf02-4018-b1a8-301ea4c3840f','鼓山','史季溫','宋','宋诗','song-poetry','','[]','上到瑶峯第幾間，御風騎氣渺人寰。',48,'全唐诗/poet.song.216000.json','["上到瑶峯第幾間，御風騎氣渺人寰。", "天高陡覺星辰近，地迥偏饒日月閒。", "去海茫茫疑十里，望州隠隠見三山。"]'),
('255ac20e-b514-439b-9747-2f5ea5919fa6','朱槿花','陸壑','宋','宋诗','song-poetry','','[]','壁槿扶疎當縛籬，山深不用掩山扉。',32,'全唐诗/poet.song.216000.json','["壁槿扶疎當縛籬，山深不用掩山扉。", "客來踏破松梢月，鶴向主人頭上飛。"]'),
('684c5bea-d0d1-40d1-b1c0-0daec0810e52','楊柳','陸壑','宋','宋诗','song-poetry','','[]','破篋猶存舊賜香，輕將魂夢別昭陽。',64,'全唐诗/poet.song.216000.json','["破篋猶存舊賜香，輕將魂夢別昭陽。", "只知鏡裏春難駐，誰道人間夜更長。", "父母家貧容不得，君王恩重死難忘。", "東風二月垂楊柳，猶解飛花入禁牆。"]'),
('a2788bfe-2e8e-4ee2-87a2-4c138b00111a','享神辭','陸壑','宋','宋诗','song-poetry','','[]','山兮如慕，水兮如訴，問故宮兮莽何許。',56,'全唐诗/poet.song.216000.json','["山兮如慕，水兮如訴，問故宮兮莽何許。", "有翼其宇，有百其堵，中冕旒兮冠珮以序。", "邦伯維主，酒醴維醹，我民兮曰毋沴我土。"]'),
('8a9be6c0-6397-47ce-8724-d8113d1fd45e','天台道中','陸壑','宋','宋诗','song-poetry','','[]','蕭颯西風吹帽紗，征途近晚欲停車。',64,'全唐诗/poet.song.216000.json','["蕭颯西風吹帽紗，征途近晚欲停車。", "峯回路轉六七里，犬吠雞鳴三四家。", "采藥人歸聞朮氣，尋仙路遠夢桃花。", "買來山釀全如水，亦解昏昏到日斜。"]'),
('fbfb8957-83ff-4b6c-a69d-2c80ae25f0d8','唐隠士袁宣墓','陳大方','宋','宋诗','song-poetry','','[]','茅山東北燕山前，翁仲遺墟幾百年。',64,'全唐诗/poet.song.216000.json','["茅山東北燕山前，翁仲遺墟幾百年。", "時有吳人來問隠，不知唐樹已啼鵑。", "山童解指看碑路，野衲分耕祭墓田。", "厚夜肯教黄壤曉，悲風偏動夕陽天。"]'),
('85508f18-60ae-4e41-9b52-5d6121942e88','萬壽觀  其一','陳大方','宋','宋诗','song-poetry','','[]','石林和月俯清流，一點紅塵不許留。',64,'全唐诗/poet.song.216000.json','["石林和月俯清流，一點紅塵不許留。", "青鳥豈傳金母信，彩鸞應返玉皇樓。", "苔鋪翠點仙橋滑，松積香梢徑路幽。", "午夜鶴翻松頂露，道人睡覺滿天秋。"]'),
('2939b950-3766-45e7-b90b-e61b60fc54ab','萬壽觀  其二','陳大方','宋','宋诗','song-poetry','','[]','玉佩丁東下界聞，天風吹動碧霞裙。',64,'全唐诗/poet.song.216000.json','["玉佩丁東下界聞，天風吹動碧霞裙。", "劉郎跨鶴遊三島，王子吹笙到五雲。", "洞府夜光傳玉印，石壇月色禮茅君。", "若逢天上吳仙子，應問丹砂成幾分。"]'),
('5f4df9ee-ab1f-4e6d-b2bc-3d5dc2e61609','判詞','徐明叔','宋','宋诗','song-poetry','','[]','科笋如刳佛面皮，科燈如點佛膏脂。',32,'全唐诗/poet.song.216000.json','["科笋如刳佛面皮，科燈如點佛膏脂。", "重科疊科何時了，奉勸諸官發大悲。"]'),
('aea99c9b-bb80-4baf-9670-db05dd9b3a87','早春汪若水宋壽谷見過','鄭芬','宋','宋诗','song-poetry','','[]','雲起松洋路，吾廬蹴水開。',48,'全唐诗/poet.song.216000.json','["雲起松洋路，吾廬蹴水開。", "故人嫌俗縛，雙騎出城來。", "春晝散微雨，隣家多早梅。", "彈琴徵古調，何處可登臺。"]'),
('b42aafa5-0b87-46a3-b400-21ece8d92f46','寄施芸隠','崔復初','宋','宋诗','song-poetry','','[]','驚見門前柳又陰，江湖何日可山林。',64,'全唐诗/poet.song.216000.json','["驚見門前柳又陰，江湖何日可山林。", "未能成事空豪氣，恐易傷時休苦吟。", "魚信不來流水遠，鴈聲低去暮雲深。", "而今甚覺春遊懶，靜看中庸養道心。"]'),
('bf6cd8ef-4fb7-48d6-b1b0-e4454bf9f217','落石廟','崔復初','宋','宋诗','song-poetry','','[]','廟門金字額，壁畫半凋零。',48,'全唐诗/poet.song.216000.json','["廟門金字額，壁畫半凋零。", "殘日挂紅樹，晚猿吟翠屏。", "村深僧村實，歲久石英靈。", "聞受河汾業，老成猶典刑。"]'),
('8de5f117-5502-4193-ada8-cf18c33e576b','三衢道中','崔復初','宋','宋诗','song-poetry','','[]','一客在他鄉，行程一月强。',48,'全唐诗/poet.song.216000.json','["一客在他鄉，行程一月强。", "雲寒山欲暗，日短道偏長。", "楓葉嫣如醉，梅花謝亦香。", "誰家砧杵急，回首感征裳。"]'),
('f1c2f7dc-30be-40d7-817d-2e60ce9e2e26','湖邊','崔復初','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西子湖邊水正肥，鴛鴦雙浴濕紅衣。',32,'全唐诗/poet.song.216000.json','["西子湖邊水正肥，鴛鴦雙浴濕紅衣。", "蜻蜓立在荷花上，受用香風不肯飛。"]'),
('48a3349a-e0f6-4b7f-906c-61493e078d90','荆公讀書堂','崔復初','宋','宋诗','song-poetry','','[]','一樹秋風啼老烏，鍾山猿鶴近何如。',32,'全唐诗/poet.song.216000.json','["一樹秋風啼老烏，鍾山猿鶴近何如。", "六經不載青苗法，不識當時讀甚書。"]'),
('cdee4363-68ca-417e-9f46-eb1406ca20c3','景定壬戌除夜','丁石','宋','宋诗','song-poetry','','[]','羅列椒盤人未眠，紅爐圍坐笑燈前。',32,'全唐诗/poet.song.216000.json','["羅列椒盤人未眠，紅爐圍坐笑燈前。", "時光過隙那知老，纔到鷄鳴又一年。"]'),
('a7c4fb19-86a0-4558-b3ba-3ff37b15f379','金陵懷古','袁太初','宋','宋诗','song-poetry','','[]','晉委東都帝秣陵，豈無機會可爭衡。',64,'全唐诗/poet.song.216000.json','["晉委東都帝秣陵，豈無機會可爭衡。", "諸公坐視敵來往，一水反爲國重輕。", "北伐上章空有語，中流擊楫竟何成。", "登臨不是多傷感，老却胸中十萬兵。"]'),
('472cc62d-d131-4bdd-b884-3f96f219af2e','山中','邵定','宋','宋诗','song-poetry','','[]','白日看雲坐，清秋對雨眠。',24,'全唐诗/poet.song.216000.json','["白日看雲坐，清秋對雨眠。", "眉頭無一事，筆下有千年。"]'),
('e19cca6c-10df-4642-a0b2-af19ae773997','漁家','邵定','宋','宋诗','song-poetry','','[]','漁家臨水住，春盡無花開。',24,'全唐诗/poet.song.216000.json','["漁家臨水住，春盡無花開。", "年年謝流水，流得好花來。"]'),
('fdabafe3-61dc-4d0f-9d83-489bb2e547cb','贈裱褙匠','蕭立之','宋','宋诗','song-poetry','','[]','牙籤玉軸新未觸，何如頹簷燈火讀。',96,'全唐诗/poet.song.216000.json','["牙籤玉軸新未觸，何如頹簷燈火讀。", "李成驟雨郭熙山，何如一藤烟火間。", "書畫移人亦尤物，寶繪堂中長公說。", "子持此藝將歸時，霜刀正足供刈葵。", "爭名場中困機械，學古悠悠晚知悔。", "殘編料理數能來，了我明窗讀書債。"]'),
('5093e4c4-eaf7-4a28-a5af-1b6c34e9f293','黄景純社倉求詩','蕭立之','宋','宋诗','song-poetry','','[]','黄君爲善不近名，九鼎大呂荆溪評。',96,'全唐诗/poet.song.216000.json','["黄君爲善不近名，九鼎大呂荆溪評。", "賊奴金印棄如唾，未用富民侯漢廷。", "只今作倉北原北，肯與貧人供年穀。", "乖崖夢中紫府客，君家世美如喬木。", "題詩往往來達官，錦標玉軸烏絲欄。", "知君見詩應怒駡，百萬摴蒲乞鵝炙。"]'),
('0de37675-f2f2-4c24-9e36-512e2a6ad197','錦雞送陳廣文','蕭立之','宋','宋诗','song-poetry','','[]','舞鸞失鏡啼秋影，文鸞白頭翠交頸。',96,'全唐诗/poet.song.216000.json','["舞鸞失鏡啼秋影，文鸞白頭翠交頸。", "山雞誰遣雙入籠，走送書堂春睡醒。", "霜濃木脫生驚雷，翩翩飛下平岡來。", "錦囊礧磈碧釵文，□之而隠身之災。", "岩呼谷應深雲裏，歲晚斕斑落城市。", "吟邊憐汝忽自憐，我亦江南客千里。"]'),
('6da29ac2-ed5d-4ba5-9ec2-c27e2832b810','花朝同劉同年判簿登蘇山','蕭立之','宋','宋诗','song-poetry','','[]','欹眠困蕭寺，曉視天宇晴。',152,'全唐诗/poet.song.216000.json','["欹眠困蕭寺，曉視天宇晴。", "細馬金盤陀，路出東南城。", "獰飈碾花作紅埃，十里八里青松栽。", "雲埋塔影鈴鐸語，水落石洪風雨來。", "仙君一去今幾年，斷碑蒼蘚留層巔。", "鶴歸華表作人語，石卧沉香生晚烟。", "蟻穴蜂房三萬戶，山上清明山下霧。", "可憐當日跨龍人，依舊思歸入城去。", "我願山頭拾桃顆，歸種雲根春妸娜。", "從渠一實三千年，不向人間食烟火。"]'),
('fe67cb92-4e57-48ef-adb9-bcd9f8128d19','同年劉仲山和送錦雞長韻再用韻爲侍綵泛幕之行餞','蕭立之','宋','宋诗','song-poetry','','[]','世人論心畫寫影，傾蓋誰能交刎頸。',96,'全唐诗/poet.song.216000.json','["世人論心畫寫影，傾蓋誰能交刎頸。", "慈恩夢事風花飛，一見八年肝膽醒。", "錦雞山上霜皚皚，機動穽發從何來。", "騎牛澗谷未必惡，古來鐵馬無非災。", "綵衣蹁躚晴晝裏，臺上曲高傾倚市。", "回雁峯頭一笑春，來縕儻可煩鄰里。"]'),
('e6a1e186-d669-49f9-aa51-ee34f27fd202','府教和章狎至再用韻爲謝','蕭立之','宋','宋诗','song-poetry','','[]','平生故人誰綈袍，元龍湖海風裁高。',192,'全唐诗/poet.song.216000.json','["平生故人誰綈袍，元龍湖海風裁高。", "吟詩倉卒供十手，清水新淬龍文刀。", "壯如沙場馳百馬，奇如甘蠅飛如射。", "寒箋字字明華星，掩耳不及春霆驚。", "一天風月四方錢，冷淡未必輸華鮮。", "人生端有不朽事，虛名豈足驚烏鳶。", "小年擔書走京國，腕中一筆萬斛力。", "近來言語不驚人，出戶誰復思安仁。", "何當解韉飼我馿，嬌兒喜歸爭挽鬚。", "來時雪花大如席，繅車卷玉鳴桑枯。", "一年春風又如客，山中無人吟不得。", "煩君遠致北海秋，雁鶩行中洗朱墨。"]'),
('9e3c8421-a428-4016-8758-15f02b42c734','桂東行次劉提屬同年見寄山行韻','蕭立之','宋','宋诗','song-poetry','','[]','桂東有山何高哉，牽蘿挽葛登嵬崔。',208,'全唐诗/poet.song.216000.json','["桂東有山何高哉，牽蘿挽葛登嵬崔。", "桄榔屯雲白日暗，瘴霧颯颯吹黄埃。", "懸崖峭壁穴鼯狖，碎啄爭食嗚爭隈。", "平生忍饑北窗卧，瘦馬却載青衫來。", "江南解作斷腸句，更生年少今多才。", "曲江座上倚寒玉，落月下照秋千崖。", "北湖尊酒誰主客，公榮不飲從渠猜。", "雁峯臺前羣玉府，檄羽忽作先春雷。", "烏公取士有巨眼，十里祖道梨花杯。", "蒲團覊我著蕭寺，官梅雪盡萱榴開。", "凝香閣下得休告，雨坐十日無輿臺。", "新吟大軸忽到手，懸冰跨雪秋皚皚。", "請從今日□□□，慰我相思腸九回。"]'),
('87783514-827a-4d2c-8132-fa2d815b0dbe','次陳府教喜晴古句且踐蘇山之韻','蕭立之','宋','宋诗','song-poetry','','[]','梅花樹頭春雪晴，長廊僧定客夢醒。',128,'全唐诗/poet.song.216000.json','["梅花樹頭春雪晴，長廊僧定客夢醒。", "蛾眉豆熟櫻笋老，兩月風雨雲屏屏。", "暄寒倏忽變氣候，客衣單夾煩調停。", "移船避漏送白日，一根露草棲風蜓。", "蛙衣陵屯分變化，蘇山雲中幾秋夏。", "欲携吟卷相追隨，呈佛不堪仙可嚇。", "歸期得請那可料，炊米僧厨猶欠賈。", "吞腥啄臭欲可爲，快理紅藤趁今暇。"]'),
('7c612fc2-d5a6-492e-a512-47f6891a29ad','雨中過北湖戲作','蕭立之','宋','宋诗','song-poetry','','[]','玉虹飲湖湖欲乾，蒼林摇落金彈丸。',96,'全唐诗/poet.song.216000.json','["玉虹飲湖湖欲乾，蒼林摇落金彈丸。", "黄泥坂深沒白馬，野渡落日人爭船。", "山城草草魚菜市，乳鶑呼雛飛不起。", "練花曉薄客棲寒，自買湘羅裁半臂。", "誰家玉手鳴象床，藕絲夜織芙蓉裳。", "等得船成看花□，一屏秋色楚雲香。"]'),
('07f88764-0e80-41d7-93c4-c68017df418a','邵中立六香吟屋歌','蕭立之','宋','宋诗','song-poetry','','[]','百原山頭鶴不歸，遠孫流落滄江湄。',210,'全唐诗/poet.song.216000.json','["百原山頭鶴不歸，遠孫流落滄江湄。", "深衣大带冠嵬巍，勁氣崷崪崆峒低。", "平生不俯俗子首，食簞懸牆歌吾伊。", "蒔香環屋供吟弄，冷石幽雲選春夢。", "吞腥逐臭暍黄塵，笑殺世人無鼻孔。", "濂溪愛蓮陶愛菊，和靖梅花子猷竹。", "楚騷蘭桂有不同，昔所難并今所足。", "問君是中有何好，君言妙處難爲道。", "四時風味一家春，八窗玲瓏三徑曉。", "金精故山深冥冥，芝田朮圃無人耕。", "幾時脫我馬口銜，與君煎茶祇愁□。", "老天忌君取數多，皚霜塗屋冰塞河。", "竹門肩輿不得施，閉戶且賦疏影橫斜詩。"]'),
('17254342-1aa7-4fd2-97ae-c62ed62fa33d','虎皮送周竹友','蕭立之','宋','宋诗','song-poetry','','[]','南山有虎額欲白，當年馮婦搏不得。',162,'全唐诗/poet.song.216000.json','["南山有虎額欲白，當年馮婦搏不得。", "牛羊食盡麋鹿無，樵蘇不來道榛棘。", "莫徭客子心膽雄，雞翎銜矢山桑弓。", "憑林翳樹斃一發，狐鳴雀噪寒山空。", "向來霧雨不下食，也知文采真足惜。", "蕭森素壁動斕斑，猛氣雄姿見風格。", "我如杜陵不願施錦鯨，琢詩包卷送贈君。", "知君家學有太極，自是臯比席上人。", "翦裁更入革工手，高堂寢處魑魅走。", "尊前一色老萊衣，爲太夫人千載壽。"]'),
('78e93e9a-c741-4307-a658-817ac7393bd0','送陳廣文西山楮衾','蕭立之','宋','宋诗','song-poetry','','[]','溪工夜斲蒼匡藤，麻姑山前砧杵鳴。',98,'全唐诗/poet.song.216000.json','["溪工夜斲蒼匡藤，麻姑山前砧杵鳴。", "千金學得不龜手，并刀剪水裁寒冰。", "人間不數兜羅軟，齊紈蜀錦焉足算。", "一池明月白雲深，四壁東風晴與暖。", "道人家風此受用，贈君也作清凈供。", "梅花帳裏春茫茫，休遣淡妝美人來入夢。"]'),
('54eb2010-ea21-47fc-a09d-e913a98434f2','頒春曲','蕭立之','宋','宋诗','song-poetry','','[]','頒春亭上羅官斑，黛泥骨碎鞭影間。',96,'全唐诗/poet.song.216000.json','["頒春亭上羅官斑，黛泥骨碎鞭影間。", "蒼虬爭走青帝勅，閶闔軋損玻璃環。", "花神謝事即□起，東畔賜緋南賜紫。", "細腰學舞圓□歌，旗亭竹根枯野水。", "防江戰士卧不驚，風吹雨洗淮土青。", "街頭父老說新事，城裏倍放今年燈。"]'),
('bbce30bc-f6dc-486a-8678-cfb26e7c058e','郴幕得告歸桂東','蕭立之','宋','宋诗','song-poetry','','[]','濯枝雨乾溪水碧，西南天高月斜白。',96,'全唐诗/poet.song.216000.json','["濯枝雨乾溪水碧，西南天高月斜白。", "誰家醉竹生莓牆，一本風烟三十尺。", "去時簫鼓紅梅燈，青秧白水蝌蚪鳴。", "夢尋北湖弄素月，一葉醉度琉璃城。", "殘編斷硯烟雨濕，短衣小冠塵土澀。", "回頭不敢望前程，九十九峯如笋立。"]'),
('9570dbb2-20fe-4e47-b4db-09e32b45e3fb','贈龍張泉醫爲灼艾','蕭立之','宋','宋诗','song-poetry','','[]','留侯遠孫腹䏺肛，載儒家書雜岐黄。',160,'全唐诗/poet.song.216000.json','["留侯遠孫腹䏺肛，載儒家書雜岐黄。", "桂山木落秋蒼蒼，畫簾西風杵臼香。", "瘴烟癘雨吹南荒，弱兒倒卧瘦女僵。", "藥石不入市賈箱，利專巫祝司禱禳。", "磨刃霍霍向豬羊，見君似人喜踉蹡。", "圭刀遣贈出錦囊，我憐此身無牢强。", "外邪客氣弩矢張，君言扶衰艾火良。", "有得不計腕肉瘡，世間何事非膏肓。", "白晝二豎行跳梁，案脈駭走扁與倉。", "餒腹可復須檳榔，請君乞我囊中方。"]'),
('ba23afec-c0a7-4d3f-92ba-5c2a3644199c','寄題李叔誼蓮峰書院','蕭立之','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','高原陸地無蓮花，此峯刻畫天與狀。',64,'全唐诗/poet.song.216000.json','["高原陸地無蓮花，此峯刻畫天與狀。", "李君下構三千楹，讀書月明調悲壯。", "向來濂溪卜廬山，蓮花峯下溪之源。", "半山爭墩未苦賢，掘地何處無流泉。"]'),
('4a853a67-667e-4101-a19a-64f61032d7a9','還李世修槐陰書院稽古堂詩軸','蕭立之','宋','宋诗','song-poetry','','[]','稽古堂中書作種，兒孫班被文章宏。',64,'全唐诗/poet.song.216000.json','["稽古堂中書作種，兒孫班被文章宏。", "平園誠齋老詞伯，至今□□□□□。", "□□讀書飽秋月，木鑽石磐有時徹。", "不見王家種樹時，兒子二郎如玉雪。"]'),
('80d7a7de-cbac-44dc-afe8-16e33609cf62','送周竹友紅椒','蕭立之','宋','宋诗','song-poetry','','[]','交枝積翠鋩鑽鏃，薰風一根萬倉粟。',128,'全唐诗/poet.song.216000.json','["交枝積翠鋩鑽鏃，薰風一根萬倉粟。", "炎雲蒸作丹砂紅，黑瞳欲墮秋玲瓏。", "楚人論香不論味，風流僅足儕蘭蕙。", "長秋宮壁堊未墁，一粒蠙珠未爲貴。", "野人摘贈持滿筐，吐霞噴霧回晶光。", "我生食藉豈識此，藜羹糝莧填饑腸。", "練囊離□撐欲破，益味養神公所課。", "他年填用調羹手，請佐鹽梅供五和。"]'),
('c841509a-08d4-4612-802c-d2f9841e5ffd','鍾乳粉送趙簿','蕭立之','宋','宋诗','song-poetry','','[]','知君肺氣如少陵，十年鬢髮秋風生。',96,'全唐诗/poet.song.216000.json','["知君肺氣如少陵，十年鬢髮秋風生。", "九韶山前石鍾乳，坐致不得心崢嶸。", "玲瓏鵝管截玉肪，黄金鐺裏然枯桑。", "連明更僕百萬杵，朔風捲海凝朝霜。", "清詩濁酒橋亭別，此日身心等瓜葛。", "爲君一涴書院胸，要看筆尾生長虹。"]'),
('c75cb987-6e56-41f5-b924-2e9d381c5234','題陳廣文蘇山小草','蕭立之','宋','宋诗','song-poetry','','[]','學詩學仙將無同，昔聞此語求志翁。',128,'全唐诗/poet.song.216000.json','["學詩學仙將無同，昔聞此語求志翁。", "遠孫青春文字工，九仙城裏鞭游龍。", "三年朗吟洞天白，湖光一區開醉墨。", "向來雪壁涴髯秦，未許斜陽今德色。", "短韻急雨鳴瓦溝，大障沙場鼙鼓秋。", "蘇君欲語道未得，山鬼叫嘯江靈愁。", "請君急與棗木刻，空明下有蜿蜒宅。", "昇天倘要□朝詞，夜半風雷留不得。"]'),
('5d76519c-bc8c-463a-98db-469f94608986','題左尉死節本末','蕭立之','宋','宋诗','song-poetry','','[]','江頭鐵騎飛腥塵，孤城釜沸游游鱗。',144,'全唐诗/poet.song.216000.json','["江頭鐵騎飛腥塵，孤城釜沸游游鱗。", "景陵少府赤心膽，直與海嶽爭輪囷。", "食窮矢盡空弮起，生爲南臣死南鬼。", "百三十指閉門中，血翦羶刀如踐蟻。", "巴陵城下丹青明，孤兒襁褓今簪纓。", "雖然惜不援漢制，尉印有子侯于鉼。", "有生必死理之常，以義處死君之剛。", "雪窗細字燈前卷，髮豎毛寒雙淚濺。", "愧無李瀚筆如椽，傳看人間配巡遠。"]'),
('c50cb9a9-9598-4b2a-985a-1227c9c6a59b','周府判送錦鷄陳廣文古風見示次韻二十句','蕭立之','宋','宋诗','song-poetry','','[]','溧陽寒尉饑欲啼，擁爐一席鷦鷯枝。',208,'全唐诗/poet.song.216000.json','["溧陽寒尉饑欲啼，擁爐一席鷦鷯枝。", "鴟夷取醉與唾宜，持書推戶知爲誰。", "抽緘讀書哦新詩，如渴得飲夢得歸。", "妓圍婉轉嬌鶑詞，也復感此山梁悲。", "文禽只合長交頸，著語嫵媚相携持。", "當年飲啄擅山澤，十步百步相追隨。", "清波照影輒自愛，竟日墮此畢者機。", "憐渠求牡著樊籞，輒贈可使炫朝飛。", "于魔不忍仁者事，豈此玩物心冥迷。", "三邊風寒鐵爲衣，白日黯黯天無輝。", "室家憂煩怨曠起，新婚之別歸何時。", "存心愛物一命耳，公漸柄用酬隆知。", "蒼芒獨立將疇依，勿諉大家聾與癡。"]'),
('2c44f615-b875-49cb-92de-bd690a77a9e5','秋胡婦歌','蕭立之','宋','宋诗','song-poetry','','[]','君家作婦三日强，錦衾未暖鴛鴦床。',128,'全唐诗/poet.song.216000.json','["君家作婦三日强，錦衾未暖鴛鴦床。", "阿郎遽作遠遊別，三載菽水空襦裳。", "採桑忽忽春風陌，郎歸相逢不相識。", "攔囊贈妾雙黄金，妾心如冰介如石。", "阿郎歸來坐堂前，低頭相視默不言。", "郎心如此不易保，醜君一死滄波寒。", "稜稜勁節秋霜句，斷簡風流映千古。", "後來一種可憐人，却遣江津名妬婦。"]'),
('430540ff-d1d8-4db1-b549-b34068c4ad08','勉友人歸廬陵','蕭立之','宋','宋诗','song-poetry','','[]','雲深雨黑山潦渾，於菟嘷風吹野昏。',96,'全唐诗/poet.song.216000.json','["雲深雨黑山潦渾，於菟嘷風吹野昏。", "短衣蹀躞面黧黝，欲指石鼓窮湘源。", "祝融峯高九萬尺，五更三點看日出。", "何如矮屋一星燈，宇宙千年書四壁。", "啼鵑催客槐自黄，江濱蟹舍魚蝦香。", "古來貧者士之常，白鷺洲前春草長。"]'),
('b7cedf6c-533c-4dca-95be-f2fdaef322c3','春日長','蕭立之','宋','宋诗','song-poetry','','[]','春日長，長安貴游踏春陽。',188,'全唐诗/poet.song.216000.json','["春日長，長安貴游踏春陽。", "游龍八尺黄金裝，狎客沈宋交金張。", "真珠結屋貝作堂，錦裀七十二鴛鴦。", "吳姬趙女羅絲篁，熊蟠豹胎桂爲漿。", "主客一飲累百觴，幃風幕日綺繡香。", "白晝銅盤飛蠟光，行樂未足光陰忙。", "恨無長繩繫扶桑，何曾得知春日長。", "山中腐儒鬢欲霜，蝸牛廬中獅子床。", "二十七種飯瘦郎，過午一枕無何鄉。", "起來煎茶竹風凉，半絲不掛萬慮忘。", "從渠門外塵如馬，落絮遊絲相枕藉。", "斜陽窗戶一編書，日長只在茅簷下。"]'),
('24059c25-11d7-4510-a711-b26dde692866','自桂東入城餞使長移節東廣路過雲頭嶺作','蕭立之','宋','宋诗','song-poetry','','[]','雲頭山中石頭路，三年石上行三度。',160,'全唐诗/poet.song.216000.json','["雲頭山中石頭路，三年石上行三度。", "歲衣十疋飯兩盂，有底踉蹡走風雨。", "來得郁然無白鬚，鳴弲跨馬東南趨。", "夢回楚徼隔鴻雁，日落贛江思鯉魚。", "苔香草舍雲生處，青壁無梯鳥飛去。", "山根野店酒旗風，似我江南桃葉渡。", "渡頭翠浪吹長鯨，蘭舟欲渡不得停。", "蒼梧陳詞叫帝子，天高水闊心怦怦。", "邅余車兮遺余褋，倒卷緇塵入衣褶。", "山中春去不歸來，苦笋生孫蕨生葉。"]'),
('655527f9-2aa8-4d45-9ccf-1eb2047370f3','周宰賞蓮席上','蕭立之','宋','宋诗','song-poetry','','[]','急風吹月月魄墮，幻作玉蓮三百箇。',128,'全唐诗/poet.song.216000.json','["急風吹月月魄墮，幻作玉蓮三百箇。", "水花亭上曉光寒，主人捧觴客滿座。", "周郎朗朗屋百間，讀書下簾春晝閑。", "坐中仙人左元放，寒冰結佩玉刻環。", "位高金多責山重，萬里風烟摇醉夢。", "何如野水酌花陰，疾雷到天色不動。", "安得太華十丈花，乘風夜至玉仙家。", "老農有種來入土，鞭起卧龍天下雨。"]'),
('6e9f6e1d-fde7-4cb4-a2af-1e878d48c94b','次韻答周宰','蕭立之','宋','宋诗','song-poetry','','[]','半生身名今甑墮，吟腸寸斲字一箇。',128,'全唐诗/poet.song.216000.json','["半生身名今甑墮，吟腸寸斲字一箇。", "三年風雨楚山寒，落日行窩看草座。", "藕塘著亭花中間，酒邊消此半日閑。", "詩成索醉坐不起，立馬嚼損黄金環。", "薤花簟凉殘唾重，詩來破我□時夢。", "長風萬里一筆追，字如韝鷹欲飛動。", "人生高下如風花，奎蹄未必真堪家。", "村沽如水賤如土，何當携來說今雨。"]'),
('9949aca9-da64-4b67-ae14-422963e9683b','再韻答周宰','蕭立之','宋','宋诗','song-poetry','','[]','天孫失眠錦機墮，剪落溪藤不論箇。',128,'全唐诗/poet.song.216000.json','["天孫失眠錦機墮，剪落溪藤不論箇。", "神光下照茅屋東，驚倒閑庭馬韉座。", "我如寒蜩吟樹間，時來有啄不得閑。", "塗烟抹墨學梳洗，敢與媚嫵爭彎環。", "天畿雨乾顧憂重，剪爪桑林勞帝夢。", "却傳賀表通銀臺，小臣拜舞驩雷動。", "銀茄欲實豆亦花，一鮑已屬窮吟家。", "莫將蘇合比糞土，隔簾不是催花雨。"]'),
('41a5e89e-55db-4bbd-af7e-5f89538b3f6b','再韻前人請斷來章之作','蕭立之','宋','宋诗','song-poetry','','[]','我本金精仙謫墮，雪崖劖天玉萬箇。',128,'全唐诗/poet.song.216000.json','["我本金精仙謫墮，雪崖劖天玉萬箇。", "有時採藥白雲深，亦有樵夫看棋座。", "湘波射鴨愁黄間，茅堂晝陰秋几閑。", "前山有詩招不入，嗔我齧戶銅龍環。", "辱君三貺拜已重，又遣吟筒敲遠夢。", "今我閉戶風月場，如看解黿食指動。", "烏絲弄筆摇松花，棘端破鏃真當家。", "石鼎章成色如土，穴居由來未知雨。"]'),
('7a2aa2ba-b36b-4ed8-a747-9d58294e57c1','再韻答前人送梅實','蕭立之','宋','宋诗','song-poetry','','[]','狂風一月吹幘墮，眼底梅花無一箇。',128,'全唐诗/poet.song.216000.json','["狂風一月吹幘墮，眼底梅花無一箇。", "酒邊餉我黄金團，飣餖閈干忽驚座。", "來禽青李季孟間，玉池生肥柘漿閑。", "長卿肺渴正須此，不用玉魚供玉環。", "江梅纍垂壓枝重，三年空作吞江夢。", "遥知未老憶歸來，身落湘南飛不動。", "潘郎只種桃李花，他年種梅說君家。", "須知調羹蘇下土，更洗一瓶秧稻雨。"]'),
('29092eea-56e0-4d93-9eee-998ad0b4e861','次韻答廬陵張新恩','蕭立之','宋','宋诗','song-poetry','','[]','庭戶無人鬭鵲墮，蘚徑屐痕無半箇。',128,'全唐诗/poet.song.216000.json','["庭戶無人鬭鵲墮，蘚徑屐痕無半箇。", "玲瓏一騎薰風前，驚起胡床橐駝座。", "長身蒼髯江梅間，麒麟初脫十二閑。", "誰教驅策落何處，水石齟齬山連環。", "筆頭不識周鼎重，學古胸寬有雲夢。", "才大萬牛挽不前，時來八風吹不動。", "寒香含著西風花，漢宮壽斚傾天家。", "不愁旱火成焦土，黄頭奴來請行雨。"]'),
('2ee7c4e1-d16f-46b2-8362-72df67bf8a4c','送周竹友虎皮時權郡事','蕭立之','宋','宋诗','song-poetry','','[]','桂東山中何所有，於菟嘷風阿香吼。',160,'全唐诗/poet.song.216000.json','["桂東山中何所有，於菟嘷風阿香吼。", "鬼行狙伏塵不驚，石八强弓射生手。", "去年臘月雪塞村，射公家家肉滿門。", "有皮斑斑五花文，鬚爪完具無箭痕。", "向來鹿豕一口吞，四蹄如瓠八尺身。", "扣門邀我酬萬錢，猛氣尚欲凌蒼烟。", "深山大澤誰得前，摩挲忽此驚華顛。", "喜君風骨清且妍，贈君春風紫茸氈。", "蠹鑽塺潤與愛惜，風簷展上雪色壁。", "知君爲政今渡河，欲寄他時恐難得。"]'),
('e7d15cab-9c3e-4e2d-867d-62328f8a43e5','客有談淮土縱獵之樂因爲之歌','蕭立之','宋','宋诗','song-poetry','','[]','雪雲厭天尋丈低，將軍觀兵出打圍。',64,'全唐诗/poet.song.216000.json','["雪雲厭天尋丈低，將軍觀兵出打圍。", "彎弓數肋射走鹿，刀槊不減并州兒。", "盤空健鶻眥欲裂，落日洗空狐兔穴。", "將軍白馬錦貂褕，奏凱歸來清夜月。"]'),
('3bf0c3b9-ec1b-4520-bd3d-55f891a8f07d','贈談星數謝秀才','蕭立之','宋','宋诗','song-poetry','','[]','紛紛卜肆深五行，子以逢掖能知星。',98,'全唐诗/poet.song.216000.json','["紛紛卜肆深五行，子以逢掖能知星。", "兒時上學眼如燭，夜夜仰面看天庭。", "埃風𡏖雨彤雲裏，日晏腸鳴市無米。", "百錢下帷學君平，窗戶中有吾伊聲。", "亦知東坡磨硯厄，梅荒孤吟鬢霜白。", "安知神奇亦有臭腐時，不見春秋書隕石。"]'),
('b7a6fd10-fc8c-40de-83ce-178f6b12d9de','酃縣女子廟','蕭立之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','贛江昔有賢女祠，湘江今見女子廟。',67,'全唐诗/poet.song.216000.json','["贛江昔有賢女祠，湘江今見女子廟。", "蒼崖直下五千尺，落日晴沙媚葵蓼。", "蒼茫傳說不足徵，深山大澤龍蛇生。", "君不見堯家二女祠祀古，或言洞庭天帝女。"]'),
('1a51d37e-ebfe-43ec-994c-75ffbd1e3704','送人之常德','蕭立之','宋','宋诗','song-poetry','','[]','秋風原頭桐葉飛，幽篁翠冷山鬼啼。',96,'全唐诗/poet.song.216000.json','["秋風原頭桐葉飛，幽篁翠冷山鬼啼。", "海圖拆補兒女衣，輕衫笑指秦人溪。", "秦人得知晉已前，降唐臣宋誰爲言。", "忽逢桃花照溪源，請君停篙莫回船。", "編蓬便結溪上宅，採桃爲薪食桃實。", "山林黄塵三百尺，不用歸來說消息。"]'),
('aa0c9d91-e22c-4e9d-9d21-f93153c4b51a','野鶻行','蕭立之','宋','宋诗','song-poetry','','[]','空山落日見野鶻，千仞峯尖巢嵂屼。',64,'全唐诗/poet.song.216000.json','["空山落日見野鶻，千仞峯尖巢嵂屼。", "脚根不受絛鏇縈，眼底熟知狐兔窟。", "翻雲掠草驚萬人，招呼不來難可馴。", "不來未必非君福，饑啄君家雞與鶩。"]'),
('1da6be85-574d-4936-879b-fbec8e97f622','初見郴倅阮雲心','蕭立之','宋','宋诗','song-poetry','','[]','蘭枝蕙蔕交西風，北湖欲秋蓮子紅。',192,'全唐诗/poet.song.216000.json','["蘭枝蕙蔕交西風，北湖欲秋蓮子紅。", "金精山前種荒客，騎馬又逐湘雲東。", "三年湖上招秦七，醉墨題詩秋露濕。", "老蛟起舞聽吟哦，幻作青童傍船立。", "仙人吹笙調鳳凰，引手贈我青瑶章。", "黄心木斷海塵起，山鬼無路啼幽篁。", "慈恩玉槿飛晴雪，龍居鏡泉潄香月。", "佳人歸去暮雪深，白鳥飛來新雨歇。", "子城鶴語樓頭烟，平分風月今吟仙。", "石桃花映綵衣發，橘井筆倒寒蟾乾。", "半生辨君床下拜，昔日裹頭今鬢改。", "世無此樂三百年，爲君起舞秋風前。"]'),
('575905e8-2979-460a-b28b-4f6877753843','雲心遣示雨凉古句用舊韻再次奉答','蕭立之','宋','宋诗','song-poetry','','[]','黑豬渡河天不風，蒼龍銜燭不敢紅。',192,'全唐诗/poet.song.216000.json','["黑豬渡河天不風，蒼龍銜燭不敢紅。", "一缾何處馬背倒，芰堘藕蕩漫西東。", "西風佳時數重七，乾鵲橋成雲□濕。", "蘭膏香冷夢初回，花舘月寒秋又立。", "岐山千歲無鳳凰，玉帝夜行龍虎章。", "九仙拍手一佛笑，橘花多處開笄篁。", "卓劍泉深酌晴雪，叉魚亭空倚寒月。", "秦郎椽筆玉虬飛，雪壁流雲香味歇。", "三年兩鬢吹蠻烟，浪說梅福能神仙。", "金精秋寒木鶴瘦，銀灣水落芝田乾。", "乞身歸去望雲拜，蓬萊淺清風物改。", "停雲有賦應年年，相思起立梅花前。"]'),
('0f6ec135-9cb7-4b9b-9d4e-b1ed769498aa','次彭介山韻','蕭立之','宋','宋诗','song-poetry','','[]','丹崖老屋金精秋，玉虬駕我萬里遊。',192,'全唐诗/poet.song.216000.json','["丹崖老屋金精秋，玉虬駕我萬里遊。", "黄岑山下有小洞，北湖一曲三年留。", "山猿無聲鶴不舞，種玉田荒長琪樹。", "仙人驚怪不歸來，閑却劉郎金掌露。", "蛩音忽爾聞空虛，吟交憶此湖上居。", "賦詩繫賊喙三尺，愧死李志羞曹蜍。", "玉雪亭邊無點熱，飛昇臺上留仙轍。", "訊速相就君不來，射工含沙能宗孽。", "大篇雋永西風前，谷簾水共曾坑煎。", "半生吟事入勳業，力田那不逢豐年。", "十八灘頭喚歸棹，彫胡米香蘋葉老。", "簿書塵裏眼生花，徑欲推敲尋瘦島。"]'),
('5f14f347-e973-4bf9-a63a-0af08e03503e','賦周斗祥愛竹','蕭立之','宋','宋诗','song-poetry','','[]','平生愛蓮無極翁，而孫愛竹將無同。',128,'全唐诗/poet.song.216000.json','["平生愛蓮無極翁，而孫愛竹將無同。", "豈期野鶩有遺憾，善學下惠猶家風。", "問君竹亦有何好，蟠胸世好百無有。", "黔婁先生生不邪，西山遺民窮得瘦。", "向來結交王子猷，一日不見如三秋。", "叩門不共主人語，往往竟日肩輿留。", "先生河陽種花手，耿耿冰霜含宇宙。", "從渠紅紫競春陽，留眼相看歲寒後。"]'),
('47c15d6c-4da7-4f34-b612-50544ddc901b','郴旱檄北湖龍','蕭立之','宋','宋诗','song-poetry','','[]','北湖三百頃，其下神龍蟠。',280,'全唐诗/poet.song.216000.json','["北湖三百頃，其下神龍蟠。", "常時泛湖人，不敢笑語喧。", "龍居祠下龍王廟，碧瓦朱甍映清湫。", "邦人四時迎送神，牲肥醴香神醉飽。", "開慶元年秋七日，山中從前無此熱。", "早禾焦死晚禾枯，百姓相看眼如血。", "去年淫雨冬無收，私科官糴紛徵求。", "薯糧掘盡蕨根斷，一飽謂有今年秋。", "州家差官走田里，奉佛迎仙取龍水。", "南村北郭皷鼕鼕，幾日街頭無處避。", "爾龍位置尊鱗蟲，鬚髯如戟聲如鍾。", "人間風日不到處，珍珠室屋珊瑚宮。", "蝦蟹爲儔鰍鼈伍，耳如無聞目無覩。", "捍災禦患則祀之，安得神龍食茲土。", "我有旌陽在時劍，能磔爾龍爲萬段。", "徐將鮓法問張華，普施農民供一飯。", "刑鵝投虎終無補，爾龍有知胡不雨。", "如問只守過湖船，塊坐教人送錢楮。"]'),
('605d7b86-7ef5-44fd-9660-2b55c9651f64','題山城劉先生花史後','蕭立之','宋','宋诗','song-poetry','','[]','山城先生窮到死，老作人間花太史。',64,'全唐诗/poet.song.216000.json','["山城先生窮到死，老作人間花太史。", "縑箱未許上蘭臺，堪著洛陽園囿裏。", "雖然儒先有公是，菊花隠逸蓮君子。", "只今同傳李與韓，豈亦負公千斛米。"]'),
('4a629a70-55e3-4b58-9ce1-d798e5b56d06','贈醫士','蕭立之','宋','宋诗','song-poetry','','[]','桂山藥石不入市，土風割牲諂非鬼。',64,'全唐诗/poet.song.216000.json','["桂山藥石不入市，土風割牲諂非鬼。", "巫師懷肉飫妻孥，醫師衡門冷如水。", "子今挑囊入深雲，如以章甫投文身。", "吾詩易得藥難售，子規語人傳藉手。"]'),
('9d2dc2e3-5f3f-49b5-b75f-a00168e12c85','春寒家','蕭立之','宋','宋诗','song-poetry','','[]','一月春寒縮牛馬，束桂薪芻不當價。',99,'全唐诗/poet.song.216000.json','["一月春寒縮牛馬，束桂薪芻不當價。", "去年霜早穀蕃熟，雨爛秧青無日曬。", "深山處處人夷齊，鋤荒飯蕨填朝饑。", "干戈滿地此樂土，不謂乃有凶荒時。", "今年有田誰力種，恃牛爲命牛亦凍。", "君不見鄰翁八十不得死，昨夜哭牛如哭子。"]'),
('34b7f560-453f-4e74-b372-5ea4ed58f396','贈周材叔能畫號蒼崖','蕭立之','宋','宋诗','song-poetry','','[]','昔見蒼崖畫，今讀蒼崖詩。',158,'全唐诗/poet.song.216000.json','["昔見蒼崖畫，今讀蒼崖詩。", "問今十日水石間，幻作五字七字何能奇。", "君言詩畫本一律，等以造化供娛嬉。", "閉門磐礴天耆定，往往清氣流詩脾。", "急將畫意入詩律，兔起鶻落無由追。", "有聲無聲强分別，妙處正不差毫釐。", "人言精藝不兩能，似亦可洗千年疑。", "梅花江頭窮竹枝，遥指八境窮烟霏。", "勿云詩工畫師耻，老瓊笑人焉用彼。", "江南和糴米如珠，急圖流民獻天子。"]'),
('feba5985-5ed7-453b-8c53-0a114421a199','賦李士明古香','蕭立之','宋','宋诗','song-poetry','','[]','君家種桂知幾年，輪囷老幹秋風前。',64,'全唐诗/poet.song.216000.json','["君家種桂知幾年，輪囷老幹秋風前。", "小山荒凉汨江冷，此樹亦有幽人便。", "君家讀書今幾世，持取科名如左契。", "他年留話與人間，王家種槐李家桂。"]'),
('a896ba9b-0c4c-44a1-9231-6afd0abab67d','八駿圖','蕭立之','宋','宋诗','song-poetry','','[]','穆王八駿真八龍，萬里歷塊追長風。',131,'全唐诗/poet.song.216000.json','["穆王八駿真八龍，萬里歷塊追長風。", "齊州羶惡塵土境，夜宴阿母瑶池宮。", "人間亦有千年絹，包裹神奇夜光現。", "畫師那計馬腹羞，當時下筆親曾見。", "詩人多事管閑愁，却笑重來不到頭。", "一聲黄竹斷歸夢，枉使徐土成荒丘。", "尤物移人吁可怕，此圖至今負高價。", "君不見華陽有馬閑且都，無人畫作武成圖。"]'),
('619b6dcd-87df-4327-b073-cec0716a1988','送人','蕭立之','宋','宋诗','song-poetry','','[]','扊扅吚啞語風竹，抱琴年少如紅玉。',96,'全唐诗/poet.song.216000.json','["扊扅吚啞語風竹，抱琴年少如紅玉。", "湘山馬背弓刀塵，三年歸來門戶俗。", "愛君不肯憎家鷄，期君樹立終嵬巍。", "媚淵潤水發至寶，萬里轉軸辭門畿。", "故山西風動禾黍，檠燈坐凉日卓午。", "而翁問我今行藏，一榻牛衣映秋雨。"]'),
('81c9fac5-7093-4477-848f-9ec93961ebbe','鄧梅臞雪籬圖','蕭立之','宋','宋诗','song-poetry','','[]','夜凉北風三尺雪，懸崖凍崩樹凍折。',96,'全唐诗/poet.song.216000.json','["夜凉北風三尺雪，懸崖凍崩樹凍折。", "此時梅花獨清絕，箕山高風首陽節。", "何人花下騎蹇馿，風雪墮面冰吟鬚。", "唐巾飄蕭紵袍窄，識者指以爲梅臞。", "屋山稜稜出林罅，雙鶴忍寒追不下。", "欲尋門巷訪梅仙，人言此是苔磯畫。"]'),
('76db96ac-7ad0-49a7-96a3-26f89a134289','閤皂山杉節歌爲士真姪作','蕭立之','宋','宋诗','song-poetry','','[]','右玄仙翁開洞府，手掇靈杉種烟雨。',160,'全唐诗/poet.song.216000.json','["右玄仙翁開洞府，手掇靈杉種烟雨。", "一根磈礧獨千年，其榮不生枯不死。", "前年木價愁達官，一枝墮地琤琅玕。", "斧斤肯爲盤錯赦，夭矯尚欲丹霄干。", "初疑雷公下林壑，夜取乖龍截頭角。", "又言石家鐵如意，擊損珊瑚半凋落。", "神剜鬼斷何可求，摩挲往往驚吟眸。", "犧尊詎是材所願，爾囿於數將奚尤。", "神仙靈物生風雹，寧與塵凡供翫謔。", "請君持用懸丹崖，留補金精飛去鶴。"]'),
('56c919d3-1a55-43f9-b640-606103393d35','有感戲隠括曹景宗語','蕭立之','宋','宋诗','song-poetry','','[]','少年快馬如游龍，鼻尖出火耳生風。',64,'全唐诗/poet.song.216000.json','["少年快馬如游龍，鼻尖出火耳生風。", "柘弓放箭餓鴟叫，數肋射麞平澤中。", "渴饑食肉飲血乳，甜如天厨薦甘露。", "誰能揚州稱貴人，閉置車中作新婦。"]'),
('c3993164-ac5a-43cf-800a-6715b0f70cf4','賦陳新伯秋潭','蕭立之','宋','宋诗','song-poetry','','[]','人間四時秋最清，九秋之水寒潭明。',128,'全唐诗/poet.song.216000.json','["人間四時秋最清，九秋之水寒潭明。", "先生奇骨二難并，十指忽忽風濤生。", "麻姑山前書滿屋，讀書夜長跋見燭。", "汪汪陂度牛醫兒，未抵寒潭一泓玉。", "我家崖前十丈冰，敲冰夜作玻瓈聲。", "愛君有此秋一潭，璧月下照琉璃城。", "從來負舟須積水，置杯坳堂安足擬。", "期君渺渺泛天津，萬斛龍驤纔一葦。"]'),
('97f9d849-cfbd-4320-ac95-9f28f1510ae1','題丁松岡詩集','蕭立之','宋','宋诗','song-poetry','','[]','松岡胸中亦磊磈，勁氣少與崆峒平。',64,'全唐诗/poet.song.216000.json','["松岡胸中亦磊磈，勁氣少與崆峒平。", "白頭一脫力百斛，中有徂徠風雨聲。", "芸兄兒時戲同隊，宰木陰風吹晝晦。", "翁身與詩壽而昌，細讀燈前爲九拜。"]'),
('9bd007a1-0a7c-4ea3-98a4-a2636b96f2a7','題侯氏雲軒','蕭立之','宋','宋诗','song-poetry','','[]','太空有雲不可覊，君家有軒雲所棲。',64,'全唐诗/poet.song.216000.json','["太空有雲不可覊，君家有軒雲所棲。", "黄埃壓帽聽朝鷄，坐軒人閑琴一枝。", "眼前白衣與蒼狗，萬事悠悠且杯酒。", "是間不涴俗子塵，客有敲門急摇手。"]'),
('e3936f1f-40ba-4c98-af87-b83f09e983a7','題黎平父月潭','蕭立之','宋','宋诗','song-poetry','','[]','金精山人蒼月軿，夜半影落秋潭明。',64,'全唐诗/poet.song.216000.json','["金精山人蒼月軿，夜半影落秋潭明。", "詩人飲潭并吞月，醉墨寫出風濤聲。", "驪珠忽墮春風紙，炯如寒梅照清泚。", "幾時脫我簿書塵，細嚼君詩酌潭水。"]'),
('cd1c3114-c888-4dec-bbc7-7d96425a2271','贈相士劉跛子','蕭立之','宋','宋诗','song-poetry','','[]','廬陵跛子代有聲，相法如鏡開玄冥。',96,'全唐诗/poet.song.216000.json','["廬陵跛子代有聲，相法如鏡開玄冥。", "喙長三尺不稱身，翻江倒海驚座人。", "崆山盡頭秋色晚，椎髻梭花隠門限。", "𨃟跚袍布揖使前，塞屋堵牆驚差見。", "桑葉杉枯懷楚歸，十年讀書良未非。", "逢君嘖嘖三箇好，豈亦見吾衡氣機。"]'),
('64024dd7-d86d-4ca9-b5bf-46a895b35e7e','謝包宏齋著述科目之薦','蕭立之','宋','宋诗','song-poetry','','[]','有美人兮天一方，欲往從之道阻長。',192,'全唐诗/poet.song.216000.json','["有美人兮天一方，欲往從之道阻長。", "翩其乘風來帝旁，巍然一桂扶明堂。", "冰盤玉果君賜酒，進講歸來坐清晝。", "却從閩嶠望蓬萊，海氣渾黄天影瘦。", "春風一箋入明光，牛鐸可使調宮商。", "低頭再拜避三舍，世謂唐晉無文章。", "先生閲人亦多矣，定不尋常種桃李。", "法鼓一震波旬驚，爨下之桐作焦尾。", "爾來世道婙喧啾，百練化作繞指柔。", "茫茫萬古落我後，傳世豈必皆王侯。", "紅泉碧澗石齒齒，菖蒲著梅弄徑蕊。", "我思脫我馬口銜，歸去從公給薪水。"]'),
('f65ae19e-b183-4a77-ae9e-30ed5854bddc','送沈時父隨沈使君歸西湖','蕭立之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','卧龍山下仙人家，瓊璫玉佩明春華。',224,'全唐诗/poet.song.216000.json','["卧龍山下仙人家，瓊璫玉佩明春華。", "平生所聞蒼玉洞，投老有意窮烟霞。", "妄希刀圭亦仙去，仙人掉頭不我顧。", "天荒地老崖谷寒，九虎關深隔雲雨。", "向來結客江湖裏，走馬馱金花下醉。", "酒邊題字墨猶香，已墮黄壚兩行淚。", "眼前吟友今幾人，東陽公子下筆親。", "胸中風味見大雅，往往有似吾元賓。", "半年同往仙人國，書來相知不相識。", "豈不欲往畏簡書，紫騮銜口鳥鷙翼。", "西湖藕香鱸鱠肥，錦囊一路載詩歸。", "天津橋上望閩嶠，落日惟有南鳶飛。", "漫郎空復蕪城住，風雨荒寒舊瓜圃。", "蕭蕭短髮簿書塵，慎勿湖邊語鷗鷺。"]'),
('58796299-b83e-4d92-ac04-6f6305aa15c2','贈煉丹士','蕭立之','宋','宋诗','song-poetry','','[]','女媧鍊石丹之源，補天破碎天亦完。',64,'全唐诗/poet.song.216000.json','["女媧鍊石丹之源，補天破碎天亦完。", "後來此方世不傳，仙家之丹說九還。", "君今採藥須名山，却老起死襴囊丸。", "世間塵勞空自煩，往逐鷄犬尋劉安。"]'),
('978ad568-8dc2-440d-92d3-135f7c90344e','賀歐西湖登第兼呈宏齋','蕭立之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去年君上西湖船，白紵如雪春風前。',192,'全唐诗/poet.song.216000.json','["去年君上西湖船，白紵如雪春風前。", "今年君上天街馬，柳汁澆袍生色畫。", "人生窮達那得知，宰相正用時來爲。", "愛君負大積者厚，萬里轉軸辭門畿。", "蹇予食籍閩州飯，書桉塵深鬢絲短。", "西風一夜入山城，南雁無情秋夢遠。", "宏齋老師魯靈光，乞身不許猶周行。", "老臣政爾仗經濟，世道亦復關行藏。", "零陵千官閑言語，重見箋詩出烏府。", "瀼西白石渡頭船，且喚漫郎聽夜雨。", "一官局束爲人鞿，宇宙風物皆危機。", "短章醉墨江南路，却愛當年未第時。"]'),
('17d10f65-c0bd-4ffb-a2f3-b2b32139037a','壽何府判易齋','蕭立之','宋','宋诗','song-poetry','','[]','我欲壽公酒，酒薄不敢斟。',184,'全唐诗/poet.song.216000.json','["我欲壽公酒，酒薄不敢斟。", "我欲壽公詩，詩調不成音。", "酌公試酌鄞江水，頌公請頌鄞人心。", "江水之清有涇渭，人心之同無古今。", "紛紛巧捷褰裳趨，公獨坦履垂紳裾。", "研桑心計論錙銖，公獨一飯不顧餘。", "王謝子弟山澤癯，葵莧之腹貯詩書。", "燕居如齊好嗜無，澹然文君對相如。", "試從邦人數前後，監州頗見有此否。", "日邊催整早朝車，堂上且傾初度酒。", "欲晴未晴霜淡濃，欲香未香梅信風。", "眼前時事好閉口，只折梅花來壽公。"]'),
('6bc18284-f5b2-41ce-b22d-c0125928f6fa','送厚齋陳持正歸括蒼效山谷體有贈','蕭立之','宋','宋诗','song-poetry','','[]','贈君白紵白且鮮，絡綉機杼秋風前。',184,'全唐诗/poet.song.216000.json','["贈君白紵白且鮮，絡綉機杼秋風前。", "爲君裁作山人衣，披雲拂石弄潺湲。", "贈君紙帳清且華，機綃水底溪工家。", "夜深擁被蝴蝶床，滿身明月卧蘆花。", "聊厚不爲薄，中有故人心。", "平生湖海交，詎得商淺深。", "飛鳶亭下闌干雨，蒼玉洞前斜日樹。", "詩來一鏃箭鋒直，直置本初何足數。", "恨我不與柴桑期，多君且賦羌村詩。", "細君迎笑兒女舞，床頭酒香鷄鶩肥。", "一城行色人催動，回首龍山烟翠重。", "敲推不定起尋君，前度莓苔千里夢。"]'),
('f5ae9b51-30f0-46a0-a17d-1e14ae8db8f1','砥柱亭同寮分韻得雨字','蕭立之','宋','宋诗','song-poetry','','[]','西風吹老寒香圃，瘦碧林塘秋幾許。',144,'全唐诗/poet.song.216000.json','["西風吹老寒香圃，瘦碧林塘秋幾許。", "官閑飲思生渴吻，載酒聯翩無客主。", "亭深城遠地自寒，鴈鶩不來蘚苔古。", "秋枰爭道較一勝，長纓颯颯翠裾舞。", "百年有幾開口笑，底用研桑枉心膂。", "吟情正屬杯中物，暮色已催城上鼓。", "嗟予負愧斗粟戀，出位乖逢鑊焦苦。", "向來胸中亦磊磈，書傳消磨着塵土。", "徑須大白得我醉，歸卧黄紬聽夜雨。"]'),
('4a8ba712-5254-4d46-abcd-cc91975db610','銅瓶歌爲趙廣文生日','蕭立之','宋','宋诗','song-poetry','','[]','平生愛此雙瓶古，千里携持走塵土。',162,'全唐诗/poet.song.216000.json','["平生愛此雙瓶古，千里携持走塵土。", "滑如女膚色馬肝，間著花枝相媚嫵。", "鄞江博士諸王孫，無氈坐客今三年。", "群仙招手喚歸去，紫薇怨殺春風前。", "華堂此日春風酒，顧我覊窮無一有。", "發囊得此雙銅瓶，啄詩包裹爲君壽。", "瓶之體兮正而不阿，瓶之質兮朴而無華。", "虛中不足稱儲粟，汲冷澗水供煎茶。", "此君清苦於君似，擬人以倫正如此。", "相看一笑姑置之，金石結交從此始。"]'),
('9ddc80f1-4695-4f1e-8164-021d4361eb54','邀同寮飲鍾學正第一枝','蕭立之','宋','宋诗','song-poetry','','[]','前溪後溪兩玉虹，半村半郭地百弓。',128,'全唐诗/poet.song.216000.json','["前溪後溪兩玉虹，半村半郭地百弓。", "上有車蓋青童童，下有一畝幽人宮。", "築亭方方羅十客，八面玲瓏受風日。", "楣間誰扁第一枝，雪裏寒梅破孤寂。", "我如愛竹王子猷，不問主人携共遊。", "衙聲已送白鳥遠，醉倒更爲斜陽留。", "馬嘶人散橋南道，燈火匆匆城閉早。", "一川風雨酒醒時，明月簿書塵壓帽。"]'),
('0c1cf956-4c9a-4318-b002-50993b8fa92f','馬順文裒金買登仕爲漕試計戲題其取青券','蕭立之','宋','宋诗','song-poetry','','[]','馬君杭人墮汀角，杭試不收汀不著。',128,'全唐诗/poet.song.216000.json','["馬君杭人墮汀角，杭試不收汀不著。", "少年落筆易進取，萬里孤雲天一握。", "捐金爵試亦假途，寒士探囊桃藥無。", "平生故人于節度，買山尚肯周窮符。", "編藤裹錦如行卷，持以取青真左券。", "惜哉掘墓逢伯夷，捧土塞河吾自靦。", "君才十倍空冀北，長鯨變化滄海窄。", "人生幸得各有地，古來不見虬鬚客。"]'),
('5c1824b1-5dae-440f-812b-f5d46eb10fb6','紅糟送陳廣文','蕭立之','宋','宋诗','song-poetry','','[]','小槽無聲簷溜歇，銀缸滿貯猩紅血。',96,'全唐诗/poet.song.216000.json','["小槽無聲簷溜歇，銀缸滿貯猩紅血。", "撐囊礧磈腹果然，壓以千鈞枯欲裂。", "麯生有味取試嘗，粉身不惜糜成漿。", "春風往往醉入骨，賜以葅醢猶能香。", "贈君活火烹錡釜，芼以青葱渫薑縷。", "食之以匙不以筯，白玉盤中漲紅霧。"]'),
('df9de5c1-8070-41e6-b6b7-aea7edc8efd2','再韻答前人','蕭立之','宋','宋诗','song-poetry','','[]','我窮嗜客如黄歇，藜藿家風曾歃血。',96,'全唐诗/poet.song.216000.json','["我窮嗜客如黄歇，藜藿家風曾歃血。", "公田稻秫五十畝，倒盡空樽雙眥裂。", "床頭有甕不忍嘗，麯塵爛爛篘無漿。", "知君亦笑肉食鄙，輟贈一鼎春風香。", "有燋尚足供轑釜，顛倒柔青縈菜縷。", "看看雙頰上紅潮，絕勝檳榔驅瘴霧。"]'),
('28d69035-da6d-41e3-b7d8-b7f55b787f53','月下觀梅獨酌','蕭立之','宋','宋诗','song-poetry','','[]','北風掠地天欲晴，街東街西人不行。',96,'全唐诗/poet.song.216000.json','["北風掠地天欲晴，街東街西人不行。", "山城早閉燈火靜，霜月自照鴟鴉鳴。", "一簷梅意春欲動，星斗闌干天宇空。", "一生愛梅復欲月，獨酌月明花作供。", "南樓鼓寒聲重遲，醉眼看花越更奇。", "牽衣兒女催翁歸，翁醉正賦寒梅詩。"]'),
('b6b2264d-c56b-4ebf-acdb-23398c2cae85','郡圃欄梅分韻得手字同寮邀飲','蕭立之','宋','宋诗','song-poetry','','[]','江南不見梅花久，一夜寒香吹戶牖。',160,'全唐诗/poet.song.216000.json','["江南不見梅花久，一夜寒香吹戶牖。", "明朝十客山下亭，萬里春風一杯酒。", "霜痕卷水天不動，月逼雲收凈如帚。", "花枝圍燭白紅吐，艷歌聒醉棲烏走。", "坐窗不遨今幾日，簿書厭人目生垢。", "茲晨不待折簡招，行車纍纍魚貫柳。", "廣文玉碎磨不磷，令尹風生談滿口。", "幕中佳士檄颯颯，著我其間慚老醜。", "龍門風流千載事，歐梅賓客文禧守。", "便須畫作欄梅圖，却恨丹青無好手。"]'),
('5562219a-81b0-4429-80c3-b686fe7a7329','賦曾氏江亭','蕭立之','宋','宋诗','song-poetry','','[]','江國愜幽尚，復此塵外亭。',48,'全唐诗/poet.song.216000.json','["江國愜幽尚，復此塵外亭。", "朱闌出烟雨，掩苒交回汀。", "野鶩自爭食，霜鷗飛冥冥。", "如何漁翁醉，大浪摇不醒。"]'),
('fa4119d3-c83c-4ae4-a607-de6c7a19aea9','賦曾氏醉月亭','蕭立之','宋','宋诗','song-poetry','','[]','開元盛時月，曾照謫仙醉。',48,'全唐诗/poet.song.216000.json','["開元盛時月，曾照謫仙醉。", "有月尚可飲，仙人渺千祀。", "不恨仙人死，恨此明月非。", "徘徊復徘徊，目斷青山磯。"]'),
('c8bfa706-8079-45e6-b601-db174861aaef','蒼玉洞分韻得淺字','蕭立之','宋','宋诗','song-poetry','','[]','霜林無留紅，石氣寒翦翦。',48,'全唐诗/poet.song.216000.json','["霜林無留紅，石氣寒翦翦。", "春風何時來，玉樹破花繭。", "聊持一樽酒，陟此雲外巘。", "流香入詩脾，汲影潄清淺。"]'),
('9e33b6b9-41a3-4754-ad70-002a9da972b2','燒榾柮','蕭立之','宋','宋诗','song-poetry','','[]','何人斧空谷，斷根委柯莖。',84,'全唐诗/poet.song.216000.json','["何人斧空谷，斷根委柯莖。", "或如蛟虬蟠，或如虎豹獰。", "首尾鬚鬣具，一一皆可名。", "老夫傍地爐，溫與挾纊并。", "彼美紅爐獸，光彩生簷楹。", "出處諒所同，竅鑿非天成。", "我今不作我，卿亦自用卿。"]'),
('85ce6912-afa5-4bdb-9365-c91ebc6d715f','歲晚','蕭立之','宋','宋诗','song-poetry','','[]','歲晚仍爲客，朝晴故作陰。',48,'全唐诗/poet.song.216000.json','["歲晚仍爲客，朝晴故作陰。", "雨花添浪白，雲樹隠江深。", "留滯寧吾土，艱危獨此心。", "一瓢終藉汝，投老遂追尋。"]'),
('4090375a-3b7a-4b8b-9127-3f42eddbb40a','觀趙月林春雨詩卷有感次韻','蕭立之','宋','宋诗','song-poetry','','[]','天上須名託，人間好句休。',48,'全唐诗/poet.song.216000.json','["天上須名託，人間好句休。", "忽看疑子在，翻閲得予愁。", "斜日吟身獨，酸風冷淚流。", "不忘夭亦壽，月淡百城秋。"]'),
('41a62ad6-ce19-435c-9e7e-29d009727473','江上有懷','蕭立之','宋','宋诗','song-poetry','','[]','凍雨年催盡，覊愁夢作歸。',48,'全唐诗/poet.song.216000.json','["凍雨年催盡，覊愁夢作歸。", "風塵雙鬢短，宇宙寸心微。", "長此憂危集，終然計慮非。", "甲裳生已免，未得怨無衣。"]'),
('14b2a875-c459-49bc-8101-4697eded95fc','近有','蕭立之','宋','宋诗','song-poetry','','[]','近有西來報，愁心渺夕陽。',48,'全唐诗/poet.song.216000.json','["近有西來報，愁心渺夕陽。", "南荒仍要害，大理隔存亡。", "應變諸公屢，防秋四序忙。", "古來形勝地，豹虎謾披猖。"]'),
('5b3526ab-2ee9-4dcf-93b3-043a3f300b44','浙江亭','蕭立之','宋','宋诗','song-poetry','','[]','塵世無窮事，寒潮往復來。',48,'全唐诗/poet.song.216000.json','["塵世無窮事，寒潮往復來。", "江流限吳越，海道接蓬萊。", "多難期如客，緣情故得哀。", "誰令天柱昃，浩浩不能回。"]'),
('cda5e733-3d1f-4ee0-a718-5d5475f83e1e','歸至三衢懷芸莊兄留京','蕭立之','宋','宋诗','song-poetry','','[]','午熱猶疑夏，宵寒不似秋。',48,'全唐诗/poet.song.216000.json','["午熱猶疑夏，宵寒不似秋。", "獨歸仍念遠，久客得無愁。", "白酒村村市，黄花處處樓。", "不緣風雨色，吾欲理扁舟。"]'),
('209fcbc4-bd29-41df-8820-81c0fe6cf641','陳西崦挽詞二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','去國年猶在，深城早卜居。',48,'全唐诗/poet.song.216000.json','["去國年猶在，深城早卜居。", "寧尋少游語，不作子公書。", "晚日靈光殿，春風下澤車。", "空同有生意，千載愧曹蜍。"]'),
('7ad01b24-680a-42c2-9410-cc470810ffb3','陳西崦挽詞二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','不盡胸中藴，康時與致君。',48,'全唐诗/poet.song.216000.json','["不盡胸中藴，康時與致君。", "未應才執戟，忽去作修文。", "清節梅花屋，閑身馬鬣墳。", "銘旌瞻不及，雙淚落南雲。"]'),
('bcfa8c81-467a-4413-a88a-0f9ce3fc5924','北林羅樞使挽詞','蕭立之','宋','宋诗','song-poetry','','[]','扶日勳庸大，公胡遽止斯。',48,'全唐诗/poet.song.216000.json','["扶日勳庸大，公胡遽止斯。", "人間何可棄，天下尚堪爲。", "太史春秋筆，蒼珉德政碑。", "不遺毫髮恨，塵宇自生悲。"]'),
('afc2235a-2952-45da-b7a9-779767cba768','病起','蕭立之','宋','宋诗','song-poetry','','[]','柳暗春歸近，窗明夕照回。',48,'全唐诗/poet.song.216000.json','["柳暗春歸近，窗明夕照回。", "悠悠度長日，稍稍遠飛埃。", "山霧晴仍濕，園花落更開。", "經旬欲斷酒，門巷只蒼苔。"]'),
('15f429ab-ab46-4b77-9a04-62019eb9d278','舶幹陳祥卿挽詞二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','練練才如許，蒼蒼不可求。',48,'全唐诗/poet.song.216000.json','["練練才如許，蒼蒼不可求。", "憂時一編墨，賫志九京秋。", "薦語諸公重，危機百慮周。", "風塵仍歲歲，恨與大江流。"]'),
('7b1a80fb-368a-4151-be1e-18d4aca1c212','舶幹陳祥卿挽詞二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','與我生同月，君鞭著便先。',48,'全唐诗/poet.song.216000.json','["與我生同月，君鞭著便先。", "艱難期用大，植立想無前。", "功在通閨近，身隨薦墨顛。", "悚然怨此世，非止故人憐。"]'),
('630909b3-2782-4c9c-a463-f48137f3f521','出郭','蕭立之','宋','宋诗','song-poetry','','[]','野徑村平樹，人家石斷流。',48,'全唐诗/poet.song.216000.json','["野徑村平樹，人家石斷流。", "南雲偏有瘴，楚水欲無秋。", "素履行忠信，浮生任去留。", "尊前古今意，吾道信悠悠。"]'),
('36a764f6-9ffa-45d1-a1bf-af24f224ec39','丙辰歲起','蕭立之','宋','宋诗','song-poetry','','[]','雪意蘇寒瘴，雲陰失夕陽。',48,'全唐诗/poet.song.216000.json','["雪意蘇寒瘴，雲陰失夕陽。", "微官遠兄弟，愁鬢入風霜。", "故國梅花夢，新年竹葉觴。", "不眠應守歲，燈影隔鄰牆。"]'),
('f1616c93-d4e0-485a-bce6-75449c2ec7b4','太平寺元羅寇故基','蕭立之','宋','宋诗','song-poetry','','[]','歲月吾生晚，兵戈此地曾。',48,'全唐诗/poet.song.216000.json','["歲月吾生晚，兵戈此地曾。", "山川如有數，險阻爾何能。", "烟雨桑麻利，簞瓢粥飯僧。", "憑閑供一嘯，深谷或爲陵。"]'),
('27939520-9d3a-458d-b012-f2c8d6e8c416','過吉水','蕭立之','宋','宋诗','song-poetry','','[]','路暗元非夕，山明忽作陰。',48,'全唐诗/poet.song.216000.json','["路暗元非夕，山明忽作陰。", "年荒官糴重，野迥客愁深。", "遠水分漁窟，饑烏集社林。", "終更眠未穩，感慨起長吟。"]'),
('cb9a9f44-b59b-4714-b8c0-36886e658830','茶陵道中','蕭立之','宋','宋诗','song-poetry','','[]','山深迷落日，一徑窅無涯。',48,'全唐诗/poet.song.216000.json','["山深迷落日，一徑窅無涯。", "老屋茅生菌，饑年竹有花。", "西來無道路，南去亦塵沙。", "獨立蒼茫外，吾生何處家。"]'),
('32d65a72-3eb9-47e3-b3b3-dabedf32d9f7','次阮雲心泛湖','蕭立之','宋','宋诗','song-poetry','','[]','湖上三更酒，西風一葉身。',48,'全唐诗/poet.song.216000.json','["湖上三更酒，西風一葉身。", "水明花近眼，燭暗月窺人。", "識面頻驚晚，論交未覺新。", "清詩如雪露，一洗簿書塵。"]'),
('441cafb2-7e41-4356-a166-5fda012ca432','再韻答前人二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','畸客殘僧寺，匡床獨夜身。',48,'全唐诗/poet.song.216000.json','["畸客殘僧寺，匡床獨夜身。", "乾坤爲正統，獦獠爾何人。", "夢破驚秋短，愁多入鬢新。", "望霓空感慨，赤日雨如塵。"]'),
('840896fc-b93b-4a68-a040-ba639841ae04','再韻答前人二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','遠道人懷古，長愁屬有身。',48,'全唐诗/poet.song.216000.json','["遠道人懷古，長愁屬有身。", "青燈猶念客，白髮不饒人。", "牢落家何在，顛危事轉新。", "種桃堪借地，吾欲離風塵。"]'),
('9da2234e-e059-40e5-bb31-08b2e9bc3015','又答前人二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','落日騷蘭國，滄洲水鶴身。',48,'全唐诗/poet.song.216000.json','["落日騷蘭國，滄洲水鶴身。", "淮南招隠賦，同谷念歸人。", "籬落秋聲入，西南局勢新。", "可憐潘岳輩，只待拜車塵。"]'),
('decfaa8a-5287-40f2-9aec-d2b054fa2217','又答前人二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','水氣收荷影，闌干出榭身。',48,'全唐诗/poet.song.216000.json','["水氣收荷影，闌干出榭身。", "可憐秋月下，不著夜吟人。", "花冷侵衣薄，茶甘汲井新。", "滿懷黄葉夢，正墮九街塵。"]'),
('aa27419e-5243-4cfd-95d2-6043e433bbba','己未作','蕭立之','宋','宋诗','song-poetry','','[]','鄉夢三年闊，秋風一月深。',48,'全唐诗/poet.song.216000.json','["鄉夢三年闊，秋風一月深。", "雲寒衣納納，沙遠樹涔涔。", "茲事寧無古，斯人更有今。", "夕陽江上路，飛鳥尚爭林。"]'),
('70afd332-d579-44ea-b021-1056ea05de66','趙玉牒夫人挽章','蕭立之','宋','宋诗','song-poetry','','[]','天胄中良貴，刑家入閫儀。',48,'全唐诗/poet.song.216000.json','["天胄中良貴，刑家入閫儀。", "青山驚托體，白髮負齊眉。", "命世堅珉筆，懷仁雜佩詩。", "茂林封不朽，落月度漣漪。"]'),
('be593b03-6f4d-402b-abda-54bccef2e340','落日','蕭立之','宋','宋诗','song-poetry','','[]','落日橋明水，烟斜垣繞村。',48,'全唐诗/poet.song.216000.json','["落日橋明水，烟斜垣繞村。", "筧泉魚養子，樊棘竹生孫。", "蝌蚪古文字，鷓鴣人語言。", "仙翁蕨薇共，聊復且清樽。"]'),
('e54d3f1b-a1c9-44e4-9959-fbae7692674c','和洪倅陳元德韻同庚','蕭立之','宋','宋诗','song-poetry','','[]','仕隔同年面，詩尋晚歲盟。',48,'全唐诗/poet.song.216000.json','["仕隔同年面，詩尋晚歲盟。", "猶堪永今夕，未覺負餘生。", "湖近官居好，梅寒客意清。", "何須愁夜雨，百草爲春榮。"]'),
('3b185316-07b4-4556-a2d2-6f6d6d65777a','還陳倅蓋山集','蕭立之','宋','宋诗','song-poetry','','[]','讀盡三更雨，凄其萬古心。',48,'全唐诗/poet.song.216000.json','["讀盡三更雨，凄其萬古心。", "義霑風賦見，工到柳韋深。", "湖海誰同味，乾坤屬苦吟。", "東家顰亦醜，吾力自難任。"]'),
('78850b39-8f08-4ef2-b9ae-167e4a7941d3','次黄後谷送吳實堂中韻','蕭立之','宋','宋诗','song-poetry','','[]','投老須微祿，謀生後計然。',48,'全唐诗/poet.song.216000.json','["投老須微祿，謀生後計然。", "燕寒無空壘，犢倦有閑田。", "白髮猶行役，青山莫使年。", "秧疇遽知許，心折馬蹄前。"]'),
('cec93733-7c6c-4415-9674-475ac6eb3596','樹老','蕭立之','宋','宋诗','song-poetry','','[]','樹老仍初葉，山寒正晚花。',48,'全唐诗/poet.song.216000.json','["樹老仍初葉，山寒正晚花。", "孤舟雙港水，新燕舊人家。", "何處依劉表，誰歟異孟嘉。", "西山供拄頰，隨意數歸鴉。"]'),
('d288579b-7291-4316-a3a0-d8bb18fa6ef9','湖海','蕭立之','宋','宋诗','song-poetry','','[]','湖海千年夢，家山亥日虛。',48,'全唐诗/poet.song.216000.json','["湖海千年夢，家山亥日虛。", "舊巢新燕入，今雨故人疏。", "貧賤猶須祿，行藏不失書。", "卿如用卿法，吾亦愛吾廬。"]'),
('69f0b9dd-f765-45c2-b930-97e4b3ba953b','題危叔陽蘭雪詩卷下','蕭立之','宋','宋诗','song-poetry','','[]','閩號詩應似，蘭清雪與研。',48,'全唐诗/poet.song.216000.json','["閩號詩應似，蘭清雪與研。", "時妝羞倚布，古調入無絃。", "谷派如冰冷，驪翁此道傳。", "客窗寒燭短，吟到曉鍾前。"]'),
('51192cbc-4671-46f1-8e17-0281dafaaeba','又次見寄韻','蕭立之','宋','宋诗','song-poetry','','[]','道路空愁我，湖山喜得君。',48,'全唐诗/poet.song.216000.json','["道路空愁我，湖山喜得君。", "客閑詩有思，春重樹無痕。", "遮日憐頭白，治書怯雨昏。", "可人期未得，馬頸□□□。"]'),
('ad1de61a-2ff5-4010-8ca5-8d02800c02bd','次韻謝吳宜齋','蕭立之','宋','宋诗','song-poetry','','[]','風誼今湖海，交遊獨子推。',48,'全唐诗/poet.song.216000.json','["風誼今湖海，交遊獨子推。", "軟塵勝道戰，清氣壓囊詩。", "谷派誰能續，靈風漸許卑。", "劘堅吾豈敢，猶欲起疲師。"]'),
('e79c093a-0529-4397-ad7d-851eece93c6b','次韻曾楚山見寄','蕭立之','宋','宋诗','song-poetry','','[]','我爾梅花國，書來歲月深。',48,'全唐诗/poet.song.216000.json','["我爾梅花國，書來歲月深。", "熟知生世理，老盡別時心。", "雁信邊聲落，霜空海氣沉。", "鬢毛相對白，可惜不同吟。"]'),
('ac32fea5-8a41-4b28-96a8-5e066f53c9f9','挽龍梅癯','蕭立之','宋','宋诗','song-poetry','','[]','湖海青燈舊，山林白髮長。',48,'全唐诗/poet.song.216000.json','["湖海青燈舊，山林白髮長。", "進書猶秘府，封斧怱崇岡。", "文墨流千古，功名付二郎。", "長年不忘念，哀些謾悲凉。"]'),
('52f41a3d-9803-4581-af7c-7f8c2d030783','次李鶴雲見寄','蕭立之','宋','宋诗','song-poetry','','[]','老病吟詩廢，愁煩送日過。',48,'全唐诗/poet.song.216000.json','["老病吟詩廢，愁煩送日過。", "時危江陸變，路斷虎狼多。", "昔夢來今雨，長懷入短歌。", "行藏吾自了，匣鏡不須磨。"]'),
('65aa9e68-d6d9-4cd4-b882-aca8558f3b07','送惠教諭之興國任','蕭立之','宋','宋诗','song-poetry','','[]','縣官崇化育，君復一氈青。',48,'全唐诗/poet.song.216000.json','["縣官崇化育，君復一氈青。", "吾道春回谷，諸生刃發硎。", "岷山開浩蕩，劍水見儀刑。", "要使民鄒魯，飛騰邁迅翎。"]'),
('9253b3c5-a488-4c59-ba53-3faed7eb03b8','食盤兔','蕭立之','宋','宋诗','song-poetry','','[]','獵戶初登網，庖丁亦奏刀。',48,'全唐诗/poet.song.216000.json','["獵戶初登網，庖丁亦奏刀。", "毛皮盡剝落，風味足烹熬。", "喜有開樽適，誰知逐野勞。", "微吟供一笑，爾狡謾稱豪。"]'),
('46cd832c-f915-407e-8a04-9a29c4ca79e1','越一月復以憲檄按死事于撫之溪暑中望疏山不得往歸宿永興寺拜象山先生墓而後行兼旬得詩如前之數可發一笑爲後山行云 七夕','蕭立之','宋','宋诗','song-poetry','','[]','偃仰當日謾能工，刻楮何如造化功。',32,'全唐诗/poet.song.216000.json','["偃仰當日謾能工，刻楮何如造化功。", "乞巧從渠兒女道，自書拙賦上屏風。"]'),
('a1ba0340-816e-4577-b7f7-b4973622fa76','越一月復以憲檄按死事于撫之溪暑中望疏山不得往歸宿永興寺拜象山先生墓而後行兼旬得詩如前之數可發一笑爲後山行云 武陽渡','蕭立之','宋','宋诗','song-poetry','','[]','落日平江晚最奇，白龍鱗換紫玻璃。',32,'全唐诗/poet.song.216000.json','["落日平江晚最奇，白龍鱗換紫玻璃。", "老兵絕叫客爭渡，催得船來失却詩。"]'),
('e54fd451-5307-406e-9ea8-7b1ba71dafb2','越一月復以憲檄按死事于撫之溪暑中望疏山不得往歸宿永興寺拜象山先生墓而後行兼旬得詩如前之數可發一笑爲後山行云 西林寺 其一','蕭立之','宋','宋诗','song-poetry','','[]','尋僧閑事爲官忙，人指雲生是上方。',32,'全唐诗/poet.song.216000.json','["尋僧閑事爲官忙，人指雲生是上方。", "少避歸牛尋曲徑，野田黄雀閙斜陽。"]'),
('3a577068-6288-4c00-ad97-798bfcbb30d2','越一月復以憲檄按死事于撫之溪暑中望疏山不得往歸宿永興寺拜象山先生墓而後行兼旬得詩如前之數可發一笑爲後山行云 西林寺 其二','蕭立之','宋','宋诗','song-poetry','','[]','日日北風江倒流，木綿著花人索裘。',32,'全唐诗/poet.song.216000.json','["日日北風江倒流，木綿著花人索裘。", "西津渡口半船月，秋在芙蓉十里洲。"]'),
('4168f99f-66f0-4154-ba50-d09318c60b8c','越一月復以憲檄按死事于撫之溪暑中望疏山不得往歸宿永興寺拜象山先生墓而後行兼旬得詩如前之數可發一笑爲後山行云 疏山道中','蕭立之','宋','宋诗','song-poetry','','[]','昨夕凉颸半點無，也無林影避行車。',32,'全唐诗/poet.song.216000.json','["昨夕凉颸半點無，也無林影避行車。", "秋雲一崦疏山曉，欲往從之畏簡書。"]'),
('8995e904-d36a-44e0-81e8-d527e8a4798f','越一月復以憲檄按死事于撫之溪暑中望疏山不得往歸宿永興寺拜象山先生墓而後行兼旬得詩如前之數可發一笑爲後山行云 方廣寺','蕭立之','宋','宋诗','song-poetry','','[]','客子入門鍾梵喧，菩提樹老不知年。',32,'全唐诗/poet.song.216000.json','["客子入門鍾梵喧，菩提樹老不知年。", "竹窗有月無人管，一夜秋風落筧泉。"]'),
('7e724e21-8e43-418c-b675-6905624f07b9','九月以檄至九江雜賦','蕭立之','宋','宋诗','song-poetry','','[]','轉枕移書就晚風，晴窗雲掩樹重重。',32,'全唐诗/poet.song.216000.json','["轉枕移書就晚風，晴窗雲掩樹重重。", "如何客裏無詩得，日聽鳴蟬夜聽蛩。"]'),
('4411ac32-e740-4954-9ab2-363d33f7b121','東西林二首  其一','蕭立之','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山山裏石頭路，我自舍車便杖藜。',32,'全唐诗/poet.song.217000.json','["廬山山裏石頭路，我自舍車便杖藜。", "西林雲物古時塔，東林秋聲堂下溪。"]'),
('e8cb2ea8-c35b-4aac-b8f6-9c7d6889d3af','東西林二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','遠公與客亦從容，未至當年似懶慵。',32,'全唐诗/poet.song.217000.json','["遠公與客亦從容，未至當年似懶慵。", "送過虎溪元不惡，不妨門外聽松風。"]'),
('cf52b362-34de-4048-8265-5e427ac18b71','圓通寺','蕭立之','宋','宋诗','song-poetry','','[]','江南開山松十圍，石耳德色坡翁詩。',32,'全唐诗/poet.song.217000.json','["江南開山松十圍，石耳德色坡翁詩。", "胡孫夜半叫絕壁，宿客夢回風雨時。"]'),
('04d30974-a8ef-4e34-a524-1ec64d4357d1','靖節先生祠','蕭立之','宋','宋诗','song-poetry','','[]','柴桑祠前松菊秋，清風天地與同流。',32,'全唐诗/poet.song.217000.json','["柴桑祠前松菊秋，清風天地與同流。", "它山之石可攻玉，攛掇先生是督郵。"]'),
('f77dc2e9-4a02-4357-bcf7-20e9c1b42ba4','太平宮賦聽雨','蕭立之','宋','宋诗','song-poetry','','[]','仙人喜作狡獪事，幻此溪聲成雨聲。',32,'全唐诗/poet.song.217000.json','["仙人喜作狡獪事，幻此溪聲成雨聲。", "我聽以心非以耳，是溪是雨本分明。"]'),
('5f2b5bdb-e815-4f98-9662-297b22f286d3','琵琶亭二首  其一','蕭立之','宋','宋诗','song-poetry','','[]','天涯偶爾傷流落，聊復吟情寄水雲。',32,'全唐诗/poet.song.217000.json','["天涯偶爾傷流落，聊復吟情寄水雲。", "說夢癡兒千載後，郵亭有曲不堪聞。"]'),
('26c4ac59-fd63-48b7-92ab-46b0e02abf3e','琵琶亭二首  其二','蕭立之','宋','宋诗','song-poetry','','[]','魯男子事無人記，此地琵琶更結亭。',32,'全唐诗/poet.song.217000.json','["魯男子事無人記，此地琵琶更結亭。", "獨倚闌干成一笑，晚風低雁著寒汀。"]'),
('72f1334e-9362-4ad0-9eb4-74529519b304','食蟹九首  其一','蕭立之','宋','宋诗','song-poetry','','[]','嗔目相如長是怒，它腸衛綰本來無。',32,'全唐诗/poet.song.217000.json','["嗔目相如長是怒，它腸衛綰本來無。", "江湖結客知多少，識面微生只蔡謨。"]'),
('c76de66a-3188-4b94-b88b-347cf53f9db5','食蟹九首  其二','蕭立之','宋','宋诗','song-poetry','','[]','橫行頗有壯士氣，黄中似是君子人。',32,'全唐诗/poet.song.217000.json','["橫行頗有壯士氣，黄中似是君子人。", "當年水底緣誰怒，此日樽前有許珍。"]'),
('2ff7a5ab-2e41-4117-a1a1-1dfb7d9b48a7','食蟹九首  其三','蕭立之','宋','宋诗','song-poetry','','[]','人間族系遍湖海，豈亦避秦之子孫。',32,'全唐诗/poet.song.217000.json','["人間族系遍湖海，豈亦避秦之子孫。", "似是外黄坑向盡，內黄一種至今存。"]'),
('3d15df4a-4fbc-497b-949c-b876b5e9f6e5','食蟹九首  其四','蕭立之','宋','宋诗','song-poetry','','[]','諸公俎豆亦風流，肥腯何曾爲彘謀。',32,'全唐诗/poet.song.217000.json','["諸公俎豆亦風流，肥腯何曾爲彘謀。", "欲免鑊湯君自擇，速營將老有糟丘。"]'),
('90861fa3-4d7c-4dca-9635-6dab0aa98631','食蟹九首  其五','蕭立之','宋','宋诗','song-poetry','','[]','紛紛炙熱總成擒，束縛歸來若不禁。',32,'全唐诗/poet.song.217000.json','["紛紛炙熱總成擒，束縛歸來若不禁。", "出涸陰鄉奚所恨，煌煌堂上禍機深。"]'),
('06a3b49f-46fc-4a49-9a11-cd52dabce421','食蟹九首  其六','蕭立之','宋','宋诗','song-poetry','','[]','新酒黄花秋滿城，看渠觳{瞉殳=束}可憐生。',37,'全唐诗/poet.song.217000.json','["新酒黄花秋滿城，看渠觳{瞉殳=束}可憐生。", "前身豈亦爲書悞，死則從人五鼎烹。"]'),
('680e70c9-ed6d-4f50-98ff-d2d979b3b696','食蟹九首  其七','蕭立之','宋','宋诗','song-poetry','','[]','霜前入市勿增價，鬭揀團臍作席珍。',32,'全唐诗/poet.song.217000.json','["霜前入市勿增價，鬭揀團臍作席珍。", "知味□□□□□，□□□□□□□。"]'),
('cda53f3c-3a6d-4099-a565-fd526aa99b24','失題','蕭立之','宋','宋诗','song-poetry','','[]','人事幾何千載長，南州一夢亦荒凉。',32,'全唐诗/poet.song.217000.json','["人事幾何千載長，南州一夢亦荒凉。", "浮雲忽散秋空曉，雙井如今水亦香。"]');
